window.__dh_data["pa"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "ਧੰਮਪਦ",
  "chaps": "ਅਧਿਆਏ",
  "fontsize": "ਫੌਂਟ ਦਾ ਆਕਾਰ",
  "chap1": "ਯਮਕ",
  "1": "ਮਨ ਸਾਰਿਆਂ ਕਰਮਾਂ ਦਾ ਕਰਨਹਾਰਾ, ਦੁੱਖ ਸੁੱਖ ਵੀ ਮਨ ਦਾ ਦਾਨ ਹੁੰਦਾ । ਜੋ ਵੀ ਉਠਦੀ ਭਾਵਨਾ ਦਿਲਾਂ ਵਿੱਚੋਂ, ਮਨ ਉਸ ਦਾ ਅਸਲ ਪ੍ਰਧਾਨ ਹੁੰਦਾ । ਬੋਲੇ ਕੋਈ ਮੰਦਾ, ਕਰੇ ਕਰਮ ਮਾੜਾ, ਦੁਖ ਉਸ ਨੂੰ ਇਉਂ ਘਰਕਾਈ ਜਾਵੇ । ਪਹੀਆ ਰੱਥ ਦਾ ਜੁੱਤੇ ਹੋਏ ਬਲਦ ਤਾਈਂ, ਘੁੰਮ ਘੁੰਮ ਜਿਉਂ ਅਗਾਂਹ ਨਸਾਈ ਜਾਵੇ ।",
  "2": "ਮਨ ਆਪਣੇ ਆਪ ਪ੍ਰੇਰਨਾ ਹੈ, ਮਨ ਧਰਮ ਦਾ ਇਕ ਗਿਆਨ ਵੀ ਹੈ । ਸੋਚ ਮਨ ਦੀ ਬੜੀ ਸਮਰੱਥ ਹੁੰਦੀ, ਮਨ ਕਰਮ ਦਾ ਇਕ ਪ੍ਰਧਾਨ ਵੀ ਹੈ । ਨਿਰਮਲ ਚਿੱਤ ਹੋ ਕਰੇ ਜੇ ਕਰਮ ਕੋਈ, ਸਵੱਛ ਬੋਲਣਾ ਜੀ, ਜਾਂ ਹਾਂ, ਕਰਦਾ । ਸੁੱਖ ਆਪ ਪਰਛਾਵੇਂ ਦਾ ਰੂਪ ਧਰ ਕੇ, ਉਹਦੇ ਸੀਸ ਤੇ ਮਿਹਰ ਦੀ ਛਾਂ ਕਰਦਾ ।",
  "3": "ਜੋ ਵੀ ਸਦਾ ਸ਼ਿਕਾਇਤਾਂ ਰਹੇ ਕਰਦਾ, 'ਮੈਨੂੰ ਓਸ ਨੇ ਮਾਰਿਆ ਕੁੱਟਿਆ ਹੈ । ਗਾਲਾਂ ਕੱਢੀਆਂ ਪੁੱਜ ਖਵਾਰ ਕੀਤਾ, ਦਿੱਤੀ ਹਾਰ ਤੇ ਰੱਜ ਕੇ ਲੁੱਟਿਆ ਹੈ'। ਇਹ ਗੰਢ ਜੋ ਬੰਨ੍ਹ ਲਏ ਮਨ ਅੰਦਰ, ਉਹ ਨਾ ਅੰਦਰਲੀ ਜੋਤ ਜਗਾ ਸਕਦਾ । ਵੈਰ ਭਾਵਨਾ ਓਸ ਦੀ ਮੁੱਕਦੀ ਨਹੀਂ, ਚੈਨ ਓਸ ਦਾ ਚਿੱਤ ਨਹੀਂ ਪਾ ਸਕਦਾ ।",
  "4": "ਜੋ ਕਦੇ ਨਹੀਂ ਇਹ ਸ਼ਿਕਾਇਤ ਕਰਦਾ, 'ਮੈਨੂੰ ਓਸ ਨੇ ਮਾਰਿਆ ਕੁੱਟਿਆ ਹੈ । ਗਾਲਾਂ ਕੱਢੀਆਂ ਪੁੱਜ ਖਵਾਰ ਕੀਤਾ, ਦਿੱਤੀ ਹਾਰ ਤੇ ਰੱਜ ਕੇ ਲੁੱਟਿਆ ਹੈ'। ਇਹ ਢਹਿੰਦੀਆਂ ਕਲਾਂ ਵੱਲ ਧੂਹਣ ਵਾਲਾ, ਨਹੀਂ ਜਿਸ ਨੂੰ ਖ਼ਿਆਲ ਪਸੰਦ ਹੁੰਦਾ । ਵੈਰ ਭਾਵਨਾ ਓਸ ਦੀ ਦੂਰ ਹੋਵੇ, ਉਹਦਾ ਚਿੱਤ ਆਨੰਦ ਆਨੰਦ ਹੁੰਦਾ ।",
  "5": "ਵੈਰ ਪਾਲਿਆਂ ਵੈਰ ਨਾ ਦੂਰ ਹੁੰਦੇ, ਅੱਗ ਨਾਲ ਨਾ ਅੱਗ ਬੁਝਾਈ ਜਾਂਦੀ । ਆਏ ਦੋਸਤੀ, ਦੁਸ਼ਮਣੀ ਚਲੀ ਜਾਏ, ਹੋ ਦਿਲਾਂ ਦੀ ਝੱਟ ਸਫ਼ਾਈ ਜਾਂਦੀ । ਚਾਹ, ਪ੍ਰੇਮ ਪਿਆਰ ਦੇ ਬੂਟਿਆਂ ਨੂੰ, ਕੋਈ ਈਰਖਾ ਨਾਲ ਨਹੀਂ ਪਾਲ ਸਕਦਾ । ਸੱਚੇ ਧਰਮ ਦਾ ਨਿਯਮ ਅਟਲ ਇਹ ਹੈ, ਨਹੀਂ ਕਾਲ ਵੀ ਏਸ ਨੂੰ ਟਾਲ ਸਕਦਾ ।",
  "6": "ਕਈ ਹੋਰ ਨੇ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਨਹੀਂ ਜਾਣਦੇ, ਕੁਛ ਵਿਚਾਰਦੇ ਨਹੀਂ । ਸਹਿਣ ਸ਼ੀਲਤਾ ਆਉਣ ਨਾ ਦੇਣ ਨੇੜੇ, ਉਹ ਕਿਸੇ ਦੀ ਗੱਲ ਸਹਾਰਦੇ ਨਹੀਂ । ਜਿਹੜੇ ਰਮਜ਼ ਪਛਾਣ ਕੇ ਇਹ ਗੁਝੀ, ਨੀਵੇਂ ਮਨ ਕਰਕੇ ਬੁਰਦਬਾਰ ਹੋ ਗਏ । ਸਾਥ ਛਡਿਆ ਝਗੜਿਆਂ ਝਾਂਜਿਆਂ ਨੇ, ਬੇੜੇ ਉਹਨਾਂ ਦੇ ਭਵਜਲੋਂ ਪਾਰ ਹੋ ਗਏ ।",
  "7": "ਨਿੱਤ ਭਾਲਦਾ ਜੋ ਐਸ਼-ਇਸ਼ਰਤਾਂ ਨੂੰ, ਤਮ੍ਹਾਂ ਹਿਰਸ ਹਵਾ ਨੂੰ ਮਾਰਦਾ ਨਹੀਂ । ਪਾੜੇ ਰੋਟੀਆਂ ਬੇਹਿਸਾਬ ਵੇਹਲੜ੍ਹ, ਸ਼ੋਹਦਾ, ਆਲਸੀ ਤੇ ਕੰਮ ਕਾਰ ਦਾ ਨਹੀਂ । ਬੁਰੀਆਂ ਵਾਦੀਆਂ ਓਸ ਤੇ ਹੋਣ ਭਾਰੂ, ਉਹਨੂੰ ਇਉਂ ਸ਼ੈਤਾਨ ਲਤਾੜਦਾ ਏ । ਜਿਵੇਂ ਝਖੜ ਹਨੇਰੀ ਦਾ ਕੋਈ ਬੁੱਲਾ, ਮਾੜੇ ਰੁੱਖਾਂ ਨੂੰ ਜੜੋਂ ਉਖਾੜਦਾ ਏ ।",
  "8": "ਜਿਹੜੇ ਆਪਣੇ ਨਫ਼ਸ ਤੇ ਪਾਉਣ ਕਾਬੂ, ਐਸ਼ ਮਹਫ਼ਿਲਾਂ ਤੋਂ ਸਦਾ ਦੂਰ ਰਹਿੰਦੇ । ਥੋੜਾ ਖਾਣ ਤੇ ਰਹਿਣ ਚੇਤੰਨ ਹਰਦਮ, ਸੋਹਜ-ਜ਼ਿੰਦਗੀ ਨਾਲ ਭਰਪੂਰ ਰਹਿੰਦੇ । ਮੱਥਾ ਮਾਰ ਪਹਾੜੀ ਚੱਟਾਨ ਦੇ ਨਾਲ, ਜਿਵੇਂ ਜ਼ੋਰ ਤੂਫ਼ਾਨ ਦਾ ਲੰਘ ਜਾਏ । ਉਸੇ ਤਰ੍ਹਾਂ ਮਜਾਲ ਸ਼ੈਤਾਨ ਦੀ ਕੀ ? ਐਸੇ ਆਦਮੀ ਨੇੜਿਉਂ ਲੰਘ ਜਾਏ ।",
  "9": "ਪਹਿਲਾਂ ਲਾਹ ਕੇ ਮੈਲ ਜੋ ਹੋਏ ਲੱਗੀ, ਮਨ ਕੁੰਗੂ ਦੇ ਵਾਂਗ ਨਿਤਾਰਿਆ ਨਹੀਂ । ਨਹੀਂ ਆਪਣੇ ਆਪ ਨੂੰ ਵੱਸ ਕੀਤਾ, ਦਿਲੋਂ ਕਿਬਰ ਹੰਕਾਰ ਨੂੰ ਮਾਰਿਆ ਨਹੀਂ । ਜੇਕਰ ਪੱਲਾ ਸਚਾਈ ਦਾ ਨਹੀਂ ਫੜਿਆ, ਏਸ ਗੱਲ ਵਿੱਚ ਸਮਝਣਾ ਸ਼ੱਕ ਕੋਈ ਨਾ । ਪਾ ਲਏ ਤਾਂ ਲਏ ਉਹ ਲੱਖ ਵਾਰੀ, ਭਗਵੇ ਕੱਪੜੇ ਓਸ ਦਾ ਹੱਕ ਕੋਈ ਨਾ ।",
  "10": "ਪਹਿਲਾਂ ਲਾਹ ਕੇ ਮੈਲ ਜੋ ਹੋਏ ਲੱਗੀ, ਮਨ ਕੁੰਗੂ ਦੇ ਵਾਂਗ ਨਿਤਾਰ ਲੈਂਦਾ। ਕਾਬੂ ਪਾ ਕੇ ਆਪਣੇ ਆਪ ਉਤੇ, ਦਿਲੋਂ ਕਿਬਰ ਹੰਕਾਰ ਨੂੰ ਮਾਰ ਲੈਂਦਾ । ਜਿਹੜਾ ਪਕੜ ਸਚਾਈ ਦਾ ਤੁਰੇ ਪੱਲਾ, ਓਹਦੀ ਨੀਅਤ ਤੇ ਕਦੇ ਨਹੀਂ ਸ਼ੱਕ ਹੁੰਦਾ । ਪਾ ਲਏ ਤਾਂ ਪਾਏ ਉਹ ਜੀ ਸਦਕੇ, ਭਗਵੇ ਕੱਪੜੇ ਓਸ ਦਾ ਹੱਕ ਹੁੰਦਾ ।",
  "11": "ਸਾਰ ਹੀਣ ਨੂੰ ਸਮਝਦੇ ਸਾਰ ਕਈ, ਕਈ ਸਾਰ ਨੂੰ ਪਏ ਅਸਾਰ ਵੇਖਣ । ਫਿਰਨ ਭਟਕਦੇ ਉਹ ਭੰਬਲ ਭੂਸਿਆਂ ਵਿੱਚ, ਨਾ ਉਹ ਤੇਲ ਨਾ ਤੇਲ ਦੀ ਧਾਰ ਵੇਖਣ । ਪੈਂਦੀ ਨਹੀਂ ਇਸਰਾਰ ਦੀ ਸਾਰ ਕੋਈ, ਮਿਲਦੀ ਸ਼ਾਂਤੀ ਨਾ ਪਰੇਸ਼ਾਨ ਰਹਿੰਦੇ । ਮਾਇਆ ਜਾਲ ਜੰਜਾਲ ਵਿੱਚ ਹੋਏ ਫਾਥੇ, ਸੋਚਾਂ ਫੋਕੀਆਂ ਵਿੱਚ ਗ਼ਲਤਾਨ ਰਹਿੰਦੇ ।",
  "12": "ਸਾਰ ਸਮਝਿਆ ਜਿਨ੍ਹਾਂ ਨੇ ਸਾਰ ਤਾਈਂ, ਸਾਰ ਹੀਣ ਨੂੰ ਵੀ ਨਾਲੇ ਜਾਣ ਲਿਆ । ਸਾਰੀ ਸਾਰ, ਅਸਾਰ ਦੀ ਪਈ ਸੋਝੀ, ਅਸਲੀ ਸਾਰ ਦਾ ਰੂਪ ਪਛਾਣ ਲਿਆ । ਰਮਜ਼ਾਂ ਗੁੱਝੀਆਂ ਉਹਨਾਂ ਨੇ ਤਾੜ ਲਈਆਂ, ਸੁੱਚੀ ਨੀਤ ਤੇ ਸੱਚੀ ਵਿਚਾਰ ਦੇ ਨਾਲ । ਸਾਰ ਜਦੋਂ ਵੀ ਤੱਤ ਦੀ ਕਿਸੇ ਪਾਈ, ਪਾਈ ਸਦਾ ਹੀ ਸੱਚ-ਅਚਾਰ ਦੇ ਨਾਲ ।",
  "13": "ਜਿਵੇਂ ਘਰ ਦੀ ਛੱਤ ਜੇ ਹੋਏ ਢੱਠੀ, ਮੀਂਹ ਜ਼ੋਰ ਦਾ ਉਪਰੋਂ ਆ ਜਾਏ । ਪਾਣੀ ਲੰਘ ਕੇ ਗਲੀਆਂ, ਮਘੋਰਿਆਂ ਚੋਂ, ਢਾਹ ਓਸ ਮਕਾਨ ਨੂੰ ਲਾ ਜਾਏ । ਓਸ ਮਨ ਦੀ ਇਉਂ ਹੀ ਦਸ਼ਾ ਹੁੰਦੀ, ਜਿਹੜਾ ਸਾਧਨਾ ਬਿਨਾਂ ਕਮਜ਼ੋਰ ਹੁੰਦਾ । ਤ੍ਰਿਸ਼ਨਾ ਉਹਦੇ ਵਿੱਚ ਇਉਂ ਪ੍ਰਵੇਸ਼ ਕਰਦੀ, ਜਿਵੇਂ ਸੰਨ੍ਹ ਥੀਂ ਲੰਘਿਆ ਚੋਰ ਹੁੰਦਾ ।",
  "14": "ਚੰਗੀ ਕਿਸੇ ਮਕਾਨ ਦੀ ਛੱਤ ਹੋਵੇ, ਮੀਂਹ ਜ਼ੋਰ ਦਾ ਵੀ ਭਾਵੇਂ ਆ ਜਾਏ । ਫੇਰ ਪਾਣੀ ਦੀ ਭਲਾ ਮਜਾਲ ਕੀ ਹੈ ? ਕਿਧਰੇ ਢਾਹ ਮਕਾਨ ਨੂੰ ਲਾ ਜਾਏ । ਓਸ ਮਨ ਦੀ ਇਉਂ ਹੀ ਦਸ਼ਾ ਹੁੰਦੀ, ਜੋ ਸੰਜਮ ਦੇ ਨਾਲ ਸ਼ਹਿਜ਼ੋਰ ਹੁੰਦਾ । ਤ੍ਰਿਸ਼ਨਾ ਉਹਦੇ ਵਿੱਚ ਨਹੀਂ ਪ੍ਰਵੇਸ਼ ਕਰਦੀ, ਬਿਨਾਂ ਸੰਨ੍ਹ ਬੇ-ਵੱਸ ਜਿਉਂ ਚੋਰ ਹੁੰਦਾ ।",
  "15": "ਰਹੇ ਝੂਰਦਾ ਆਪਣੀ ਜ਼ਿੰਦਗੀ ਵਿਚ, ਮੌਤ ਪਿਛੋਂ ਵੀ ਲੁੜਛਦਾ ਝੂਰਦਾ ਏ । ਸੱਚੀ ਗੱਲ ਇਹ ਨਹੀਂ ਝੁਠਲਾਈ ਜਾਂਦੀ, ਪਾਪੀ ਦੋਹਾਂ ਜਹਾਨਾਂ ਵਿੱਚ ਝੂਰਦਾ ਏ । ਕਰੇ ਗ਼ਮਾਂ ਦੀ ਪੀੜ ਨਿਢਾਲ ਉਸ ਨੂੰ, ਖਾਂਦਾ ਓਸ ਨੂੰ ਰੋਗ ਸੰਤਾਪ ਹੁੰਦਾ । ਮੰਦੇ ਕੰਮ ਹੀ ਓਸਦੇ ਆਉਣ ਅੱਗੇ, ਉਹਨੂੰ ਮਾਰਦਾ ਆਪਣਾ ਪਾਪ ਹੁੰਦਾ ।",
  "16": "ਸੁੱਖ ਭੋਗਦਾ ਏ ਸੋਹਣੇ ਜ਼ਿੰਦਗੀ ਵਿੱਚ, ਮਰਨ ਪਿੱਛੋਂ ਵੀ ਓਸ ਨੂੰ ਸੁੱਖ ਮਿਲਦਾ । ਧਰਮੀ ਦੋਹਾਂ ਜਹਾਨਾਂ ਵਿੱਚ ਸੁਰਖਰੂ ਹੈ, ਉਹਨੂੰ ਕਿਧਰੇ ਵੀ ਜ਼ਰਾ ਨਾ ਦੁੱਖ ਮਿਲਦਾ । ਸਦਾ ਸਦਾ ਆਨੰਦ ਪਰਸੰਨ ਰਹਿੰਦਾ, ਕਦੇ ਨਹੀਂ ਦੁਹਾਈ ! ਦੁਹਾਈ ! ਕਰਦਾ । ਪੱਲੇ ਪੁੰਨ ਵਿਚਾਰ ਪੁਨੀਤ ਜਿਸ ਦੇ, ਕਰਦਾ, ਹੱਕ ਦੀ ਨੇਕ ਕਮਾਈ ਕਰਦਾ ।",
  "17": "ਕਸ਼ਟ ਝੱਲਦਾ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਮਰਨ ਪਿੱਛੋਂ ਵੀ ਰੋਗ ਸੰਤਾਪ ਰਹਿੰਦਾ । ਕੀਤੇ ਪਾਪ ਅਰਾਮ ਨਹੀਂ ਲੈਣ ਦੇਂਦੇ, ਚੜ੍ਹਿਆ ਦੋਹਾਂ ਜਹਾਨਾਂ ਵਿੱਚ ਤਾਪ ਰਹਿੰਦਾ । ਇਹ ਸੋਚ ਕੇ 'ਮੈਂ ਗੁਨਾਹ ਕੀਤਾ', ਗੁਨਾਹਗਾਰ ਕੰਬੇ ! ਹੋਰ ਦੁਖੀ ਹੁੰਦਾ । ਕਾਰਨ ਪਾਪ ਦੇ ਭਾਗ ਨਿਖੁਟ ਜਾਂਦੇ, ਸੁਫ਼ਨੇ ਵਿੱਚ ਵੀ ਪਾਪੀ ਨਹੀਂ ਸੁਖੀ ਹੁੰਦਾ ।",
  "18": "ਜੀਵਨ ਉਹਦਾ ਪਰਸੰਨ ਭਰਪੂਰ ਹੁੰਦਾ, ਉਸ ਤੋਂ ਮੌਤ ਵੀ ਖ਼ੁਸ਼ੀ ਨਹੀਂ ਖੋਹ ਸਕਦੀ । ਪੱਲੇ ਕਿਉਂਕਿ ਨੇਕੀਆਂ ਬੱਧੀਆਂ ਨੇ, ਕੋਈ ਚੰਦਰੀ ਪੀੜ ਨਹੀਂ ਛੋਹ ਸਕਦੀ । ਉਸ ਤੋਂ ਦੂਰ ਦਿਲਗੀਰੀਆਂ ਰਹਿੰਦੀਆਂ ਨੇ, ਕਥਨੀ ਕਰਨੀ ਜੁ ਓਸ ਦੀ ਨੇਕ ਹੁੰਦੀ । ਰਹਿੰਦੇ ਚਮਕਦੇ ਸਦਾ ਨਸੀਬ ਓਹਦੇ, ਉਸ ਨੂੰ ਸੱਚ ਆਨੰਦ ਦੀ ਟੇਕ ਹੁੰਦੀ ।",
  "19": "ਵੇਦ ਮੰਤਰਾਂ ਦੇ ਲੱਖ ਪਾਠ ਕਰੀਏ, ਪੜ੍ਹੀਏ ਹੋਰ ਵੀ ਸੱਚੀਆਂ ਬਾਣੀਆਂ ਨੂੰ । ਅਮਲਾਂ ਬਾਝ ਨਾ ਜ਼ਿੰਦਗੀ ਸੌਰਦੀ ਏ, ਕਾਹਨੂੰ ਰਿੜਕੀਏ ਫੋਕਿਆਂ ਪਾਣੀਆਂ ਨੂੰ । ਬਿਨਾ ਕਰਨੀਓਂ ਆਲਸੀ ਪੁਰਸ਼ ਕਈ, ਐਵੇਂ ਭੂਮੀ ਸਨਿਆਸ ਦੀ ਮਿਣੀ ਜਾਂਦੇ । ਓਹ ਓਸ ਗਵਾਲੇ ਦੇ ਵਾਂਗ ਸਮਝੋ, ਜਿਹੜੇ ਵੱਗ ਬਗਾਨੇ ਦਾ ਗਿਣੀ ਜਾਂਦੇ ।",
  "20": "ਥੋੜ੍ਹਾ ਪਾਠ ਸ਼ਲੋਕਾਂ ਦਾ ਕਰੇ ਭਾਵੇਂ, ਜੇਕਰ ਉਹ ਪਰ ਧਰਮ ਦੀ ਕਾਰ ਕਰਦਾ । ਮਨੋਂ ਤਨੋਂ ਵਿਸਾਰ ਕੇ ਮੋਹ ਮਾਇਆ, ਧਰਮ ਨੇਮ ਅਨੁਸਾਰ ਵਿਹਾਰ ਕਰਦਾ । ਤ੍ਰਿਸ਼ਨਾ, ਕਾਮਨਾ, ਲੋਭ ਤਿਆਗ ਦਿੰਦਾ, ਦੋਹੀਂ ਥਾਈਂ ਨਾ ਜਿਸ ਤੋਂ ਸਵਾਲ ਹੁੰਦਾ । ਉਹ ਪਦ ਨਿਰਬਾਨ ਨੂੰ ਪੁੱਜ ਕੇ ਤੇ, ਸਾਰੇ ਆਦਰਾਂ ਦਾ ਸਾਂਝੀਵਾਲ ਹੁੰਦਾ ।",
  "chap2": "ਅੱਪਮਾਦ",
  "21": "ਸੋਚ, ਸਾਧਨਾ ਸਦਾ ਸੁਚੇਤ ਜੀਹਦੀ, ਉਹ ਪਦ ਨਿਰਬਾਣ ਨੂੰ ਪਾਉਂਦਾ ਏ । ਕਰੇ ਨੇਸਤੀ ਜੋ ਬੇ-ਮੁੱਖ ਹੋ ਕੇ, ਉਹ ਮੌਤ ਨੂੰ ਆਪ ਬੁਲਾਉਂਦਾ ਏ । ਧਿਆਨ-ਮਗਨ ਵੀ ਰਹੇ ਚੇਤੰਨ ਜਿਹੜਾ, ਉਹ ਮਾਰਿਆਂ ਵੀ ਕਦੇ ਨਹੀਂ ਮਰਦਾ । ਉਹ ਜੀਉਂਦਾ ਵੀ ਹੁੰਦਾ ਮੋਇਆਂ ਵਰਗਾ, ਜੋ ਜਾਗਦਾ ਨਹੀਂ, ਸੋਝੀ ਨਹੀਂ ਕਰਦਾ ।",
  "22": "ਪੰਡਤ ਜਾਗਦੇ ਵੇਖ ਮਰਜੀਉੜਿਆਂ ਨੂੰ, ਬੜੇ ਚਿੱਤ ਦੇ ਵਿੱਚ ਪਰਸੰਨ ਰਹਿੰਦੇ । ਉਹਨਾਂ ਵਾਂਗ ਹੀ ਫ਼ਰਜ਼ ਪਛਾਣ ਲੈਂਦੇ, ਖਬਰਦਾਰ ਹੁਸ਼ਿਆਰ, ਚੇਤੰਨ ਰਹਿੰਦੇ । ਸੋਝੀ ਵਾਲੇ ਅਣਗਹਿਲੀਆਂ ਨਹੀਂ ਕਰਦੇ, ਉਹ ਭੁੱਲ ਵੀ ਨਹੀਂ ਬੇ-ਮੁੱਖ ਹੁੰਦੇ । ਕਿਉਂਕਿ ਸਮਝ ਲਈ ਉਨ੍ਹਾਂ ਨੇ ਗੱਲ ਪੂਰੀ, ਵਿਚ ਸਾਵਧਾਨੀ ਲੱਖਾਂ ਸੁੱਖ ਹੁੰਦੇ ।",
  "23": "ਸਦਾ ਧਿਆਨ ਦੇ ਵਿੱਚ ਗ਼ਲਤਾਨ ਰਹਿੰਦੇ, ਸਿਰੜ ਨਾਲ ਜੋ ਸਾਧਨਾ ਕਰਨ ਵਾਲੇ । ਅਗ੍ਹਾਂ ਤੁਰੇ ਜਾਂਦੇ, ਇੱਕੋ ਮਸਤ ਚਾਲੇ, ਨਿਸਚੇ ਨਾਲ ਅਰਾਧਨਾ ਕਰਨ ਵਾਲੇ । ਓੜਕ ਇਹਨਾਂ ਦੀ ਘਾਲ ਹੈ ਥਾਏਂ ਪੈਂਦੀ, ਚਿੱਤ-ਸ਼ਾਂਤ ਆਨੰਦ ਭਰਪੂਰ ਹੁੰਦੇ । ਸਹਿਜ ਨਾਲ ਉਹ ਪਦ ਨਿਰਬਾਨ ਪਾਉਂਦੇ, ਮਾਇਆ, ਮੋਹ ਤੇ ਆਲਸੋਂ ਦੂਰ ਹੁੰਦੇ ।",
  "24": "ਜਿਹੜਾ ਆਪਣੇ ਪੈਰਾਂ ਤੇ ਖੜਾ ਹੋਵੇ, ਕਦੇ ਕਿਸੇ ਦਾ ਆਸਰਾ ਤੱਕਦਾ ਨਹੀਂ । ਸੁੱਚੇ ਕੰਮ ਤੇ ਨੇਕ ਕਮਾਈ ਕਰਦਾ, ਤੁਰਦਾ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਥੱਕਦਾ ਨਹੀਂ । ਨਹੀਂ ਮੋੜਿਆ ਫ਼ਰਜ਼ ਤੋਂ ਮੁੱਖ ਜੀਹਨੇ, ਕੀਤਾ ਆਪਣੇ ਆਪ ਨੂੰ ਵੱਸ ਹੁੰਦਾ । ਓਹਦੀ ਕੀਰਤੀ ਮਹਿਕਦੀ ਹਰ ਪਾਸੇ, ਸਾਰੇ ਜੱਗ ਜਹਾਨ ਤੇ ਜੱਸ ਹੁੰਦਾ ।",
  "25": "ਕਰ ਕੇ ਸੀਲ-ਸੰਜਮ, ਨਾਲ ਚੌਕਸੀ ਦੇ, ਪੈਰੀਂ ਆਪਣੇ ਆਪ ਖਲੋ ਜਾਏ । ਕਾਬੂ ਪਾ ਕੇ ਆਪਣੇ ਨਫ਼ਸ ਉੱਤੇ, ਜ਼ਬਤ ਨੇਮ ਅੰਦਰ ਜਦੋਂ ਹੋ ਜਾਏ । ਓਦੋਂ, ਇਹ ਸਿਆਣੇ ਲਈ ਲਾਜ਼ਮੀ ਹੈ, ਇਉਂ ਮਨ ਦਾ ਦੀਪ ਉਸਾਰ ਧਰ ਲਏ । ਹੜ੍ਹ, ਤ੍ਰਿਸ਼ਨਾਂ ਦਾ ਜਿਨੂੰ ਨਾ ਡੋਬ ਸਕੇ, ਭਾਵੇਂ ਛੱਲਾਂ ਤੇ ਛੱਲਾਂ ਦਾ ਵਾਰ ਕਰ ਲਏ ।",
  "26": "ਹੁੰਦਾ ਥਹੁ ਨਹੀਂ ਮਾਸਾ ਵੀ ਓਹਬੜਾਂ ਨੂੰ, ਹਟਵੇਂ ਅਕਲ ਤੋਂ ਉਹ ਖਲੋ ਜਾਂਦੇ । ਕਰਤਬ ਆਪਣਾ ਝਟ ਵਿਸਾਰ ਦਿੰਦੇ, ਮੁਖ ਮੋੜ ਅਵੇਸਲੇ ਹੋ ਜਾਂਦੇ । ਸਮਝਦਾਰ ਪਰ ਸਦਾ ਹੁਸ਼ਿਆਰ ਰਹਿੰਦਾ, ਕਿਉਂਕਿ ਉਹ ਸੁਚੇਤ ਕਮਾਲ ਦਾ ਏ । ਦੌਲਤ ਹੁੰਦੀ ਜਿਉਂ ਲੱਖਾਂ ਖਜ਼ਾਨਿਆਂ ਦੀ, ਇਉਂ ਆਪਣਾ ਫ਼ਰਜ਼ ਸੰਭਾਲਦਾ ਏ ।",
  "27": "ਨੇੜੇ ਨੇਸਤੀ ਜਾਓ ਨਾ ਭੁੱਲ ਕੇ ਵੀ, ਫਸਣਾ ਕਦੇ ਨਾ ਵਿਸ਼ੇ ਵਿਕਾਰ ਅੰਦਰ । ਕਾਮ, ਭੋਗ, ਵਿਲਾਸ ਤੋਂ ਪਰ੍ਹੇ ਹੋ ਕੇ, ਰਹੋ ਪਾਕ ਪੁਨੀਤ ਵਿਚਾਰ ਅੰਦਰ । ਸਾਵਧਾਨ, ਸੁਚੇਤ, ਹੁਸ਼ਿਆਰ, ਹਰਦਮ, ਪੁਰਸ਼ ਜੋ ਵੀ ਧਿਆਨ-ਗ਼ਲਤਾਨ ਹੁੰਦਾ । ਉਹਦੇ ਦੁੱਖ ਅੰਦੇਸੜੇ ਦੂਰ ਹੁੰਦੇ, ਮਹਾਂ ਸੁਖੀ ਉਹ ਨੇਕ ਇਨਸਾਨ ਹੁੰਦਾ ।",
  "28": "ਉੱਦਮ ਨਾਲ ਜੋ ਜਾਗ ਹੁਸ਼ਿਆਰ ਹੋ ਕੇ, ਆਕਲ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ ਜਦੋਂ ਦੂਰ ਹੁੰਦੈ । ਪੁੱਜੇ ਉਹ ਦਾਨਾਈ ਦੀ ਸਿਖਰ ਉਤੇ, ਉਹਦਾ ਚਿੱਤ ਆਨੰਦ ਭਰਪੂਰ ਹੁੰਦੈ । ਫਿਕਰਾਂ ਮਾਰਿਆਂ, ਗ਼ਮਾਂ ਦੇ ਪੀੜਿਆਂ ਨੂੰ, ਫਿਰ ਉਹ ਉੱਪਰੋਂ ਇਉਂ ਨਿਹਾਰਦਾ ਏ । ਫਿਰਦੇ ਜਿਵੇਂ ਮੈਦਾਨਾਂ ਵਿੱਚ ਮੂਰਖਾਂ ਤੇ, ਰਿਸ਼ੀ ਪਰਬਤੋਂ ਝਾਤੀਆਂ ਮਾਰਦਾ ਏ ।",
  "29": "ਆਕਲ ਬੈਠ ਕੇ ਕੋਲ ਜੋ ਗ਼ਾਫ਼ਿਲਾਂ ਦੇ, ਦਾਮਨ ਗ਼ਾਫ਼ਲੀ ਨਾਲ ਨਾ ਦਾਗਦਾ ਏ । ਗੂਹੜੀ ਨੀਂਦਰ ਅਗਿਆਨ ਦੀ ਸੁੱਤਿਆਂ ਵਿਚ, ਸਮਝ ਲਓ ਕਿ ਉੱਦਮੀ ਜਾਗਦਾ ਏ । ਦੌੜ ਵਿਚ ਗਿਆਨ ਧਿਆਨ ਦੀ ਓਹ, ਸੋਮਨ ਰਹੇ ਤੇ ਮੰਜ਼ਲਾਂ ਮਾਰ ਜਾਏ । ਮੱਠੇ ਘੋੜੇ ਨੂੰ ਛੱਡ ਕੇ ਜਿਵੇਂ ਪਿੱਛੇ, ਅੱਗੇ ਨਿਕਲਦਾ ਤੇਜ਼-ਰਫ਼ਤਾਰ ਜਾਏ ।",
  "chap3": "ਚਿੱਤ",
  "30": "ਇੰਦਰ ਦੇਵਤਾ ਵੀ ਆਲਸ ਮੁਕਤ ਹੋ ਕੇ, ਸਭਨਾਂ ਦੇਵਾਂ ਦੇ ਸਿਰਾਂ ਤੇ ਤਾਜ ਹੋਇਆ । ਇਸੇ ਲਈ ਹੀ ਸੁਰਗ ਸੁਰਲੋਕ ਅੰਦਰ, ਸੋਭਾ ਓਸਦੀ, ਓਸਦਾ ਰਾਜ ਹੋਇਆ । ਹੋਵੇ ਸਿਫ਼ਤ ਸਲਾਹ ਚੈਤੰਨਤਾ ਦੀ, ਸਦਾ, ਸਦਾ ਹੋਵੇ ਬਾਰਮ ਬਾਰ ਹੋਵੇ । ਸਭਨਾਂ ਪਾਸਿਓਂ ਆਲਸ ਤੇ ਗਾਫ਼ਲੀ ਤੇ, ਹਰ ਸਮੇਂ ਧਿੱਕਾਰ, ਧਿੱਕਾਰ ਹੋਵੇ ।",
  "31": "ਜਿਸਨੂੰ ਜਾਗਣ ਦੇ ਨਾਲ ਪਿਆਰ ਹੋਵੇ, ਆਲਸ, ਗਾਫ਼ਿਲੀ ਨੂੰ ਖ਼ਤਰਨਾਕ ਸਮਝੇ । ਸਿੱਧੇ ਰਾਹ ਨੂੰ ਜਾਗਦਾ, ਉਹ ਭਿਖਸ਼ੂ, ਬਿਲਾ ਸ਼ੱਕ ਜਾਣੋ, ਠੀਕ ਠਾਕ ਸਮਝੇ । ਇੱਕ ਅੱਗ ਸਮਾਨ ਹੈ ਓਹ ਭਿਖਸ਼ੂ, ਜਿਹੜੀ ਸੰਸਿਆਂ ਨੂੰ ਦਾਹ ਕਰੀ ਜਾਏ । ਸਭਨਾਂ ਨਿੱਕਿਆਂ ਮੋਟਿਆਂ ਬੰਧਨਾਂ ਨੂੰ, ਸਾੜ ਸਾੜ ਸੁਆਹ ਜੋ ਕਰੀ ਜਾਏ ।",
  "32": "ਜਿਸਨੂੰ ਜਾਗਣ ਦੇ ਨਾਲ ਪਿਆਰ ਹੋਵੇ, ਆਲਸ, ਗਾਫ਼ਿਲੀ ਨੂੰ ਖ਼ਤਰਨਾਕ ਸਮਝੇ । ਸਿੱਧੇ ਰਾਹ ਨੂੰ ਜਾਗਦਾ, ਉਹ ਭਿਖਸ਼ੂ, ਬਿਲਾ ਸ਼ੱਕ ਜਾਣੋ, ਠੀਕ ਠਾਕ ਸਮਝੇ । ਓਹ ਸਦਾ ਸੁਚੇਤ ਅਡੋਲ ਰਹਿੰਦਾ, ਰਾਹੋਂ ਕਿਧਰੇ ਕੁਰਾਹ ਨਹੀਂ ਹੋ ਸਕਦਾ । ਪੁੱਜਾ ਹੋਇਆ ਨਿਰਵਾਨ ਦੇ ਓਹ ਨੇੜੇ, ਪਤਨ ਓਸਦਾ ਕਦੇ ਨਹੀਂ ਹੋ ਸਕਦਾ ।",
  "33": "ਚੰਚਲ ਮਨ ਸੁਖਾਲਾ ਨਹੀਂ ਵੱਸ ਕਰਨਾ, ਪੈਰ ਪੈਰ ਇਹ ਬਦਲਦਾ ਡੋਲਦਾ ਏ । ਏਸ ਪੰਛੀ ਦੀ ਡੋਰ ਨੂੰ ਕੌਣ ਥੰਮੇ ? ਉੱਡਣ ਲਈ ਜਦੋਂ ਪਰਾਂ ਨੂੰ ਤੋਲਦਾ ਏ । ਅਕਲਮੰਦ ਹੀ ਏਸ ਤੇ ਪਾਉਣ ਕਾਬੂ, ਗੱਲ ਸਾਫ਼ ਓਹ ਖਰੀ ਦੋ-ਟੁੱਕ ਕਰਦੇ । ਤੀਰਸਾਜ਼ ਵਾਂਗਰ ਕੱਢ ਵੱਟ ਮਨ ਦੇ, ਐਨ ਤੀਰ ਜੇਹਾ ਸਿੱਧਾ ਤੁੱਕ ਕਰਦੇ ।",
  "34": "ਜੀਉਂਦੀ ਪਕੜ ਸਰੋਵਰੋਂ ਕੋਈ ਮੱਛੀ, ਫੰਧਕ ਸੁੱਕੀ ਜ਼ਮੀਨ ਤੇ ਸੁੱਟ ਜਾਏ । ਉਹ ਤੜਫਦੀ ਤੜਫਦੀ ਲੁੱਛਦੀ ਹੈ, ਜਿਵੇਂ ਓਸ ਦੀ ਚੋਗ ਨਿਖੁੱਟ ਜਾਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਚਿੱਤ ਜੋ ਹੈ ਚੰਚਲ, ਬੜਾ ਤੜਫਦਾ ਤੇ ਡੋਬੂ ਖਾਈ ਜਾਵੇ । 'ਮਾਇਆ ਮੋਹ ਦੇ ਜਾਲ ਚੋਂ ਨਿਕਲ ਜਾਵਾਂ', ਜਿਵੇਂ ਕਿਵੇਂ ਤਦਬੀਰ ਬਣਾਈ ਜਾਵੇ ।",
  "35": "ਚਿੱਤ, ਚਪਲ, ਚਲਾਕ, ਅਮੋੜ, ਚੰਚਲ, ਨਹੀਂ ਚਿੱਤ ਨੂੰ ਸਬਰ ਕਰਾਰ ਆਉਂਦਾ । ਰਹੇ ਭਟਕਦਾ ਹਲਕੇ ਸੁਭਾਅ ਕਾਰਨ, ਤਾਂਹੀਓਂ, ਏਸ ਤੇ ਨਹੀਂ ਇਤਬਾਰ ਆਉਂਦਾ । ਏਸੇ ਲਈ ਹੀ ਚਿੱਤ ਨੂੰ ਵੱਸ ਕਰਨਾ, ਨੇਕ ਕੰਮ ਜਾਂ ਇਕ ਸਵਾਬ ਹੁੰਦਾ । ਚਿੱਤ ਸੋਧਿਆ ਖ਼ੁਸ਼ੀਆਂ ਜੋ ਵੰਡਦਾ ਏ, ਨਹੀਂ ਉਹਨਾਂ ਦਾ ਅੰਤ ਹਿਸਾਬ ਹੁੰਦਾ ।",
  "36": "ਸੌਖਾ ਨਹੀਂ ਹੈ ਮਨ ਨੂੰ ਸਮਝ ਸਕਣਾ, ਮਨ ਚਤਰ ਵੀ ਹੈ ਚਲਾਕ ਵੀ ਹੈ । ਮਰਜ਼ੀ ਆਪਣੀ ਨਾਲ ਇਹ ਲੁੜਕਦਾ ਰਹੇ, ਆਪ-ਹੁਦਰੀਆਂ ਵਿੱਚ ਇਹ ਤਾਕ ਵੀ ਹੈ । ਬੁਧੀਮਾਨ ਜੇ ਮਨ ਦੀ ਕਰੇ ਰਾਖੀ, ਓਹਦੀ ਸ਼ਾਨ ਹੁੰਦੀ, ਓਹਦਾ ਮਾਣ ਹੁੰਦਾ । ਮਨ ਨੱਥਿਆ ਅਤੇ ਸੰਭਾਲਿਆ ਫਿਰ, ਸਮਝ ਲਓ ਕਿ ਸੁੱਖਾਂ ਦੀ ਖਾਣ ਹੁੰਦਾ ।",
  "37": "ਦੂਰ ਦੂਰ ਹੈ ਭਟਕਦਾ ਮਨ ਫਿਰਦਾ, ਨਹੀਂ ਡੁੱਬਦਾ ਏਸ ਦਾ ਛੋ ਕਿਧਰੇ । ਨਿਰਾਕਾਰ, ਇਕੱਲਾ ਹੀ ਰਹੇ ਭੌਂਦਾ, ਨਹੀਂ ਸਕਦਾ ਮਨ ਖਲੋ ਕਿਧਰੇ । ਹਿਰਦੇ ਅੰਦਰ ਵੀ ਕਦੇ ਇਹ ਰਹੇ ਲੁਕਿਆ, ਵੱਸ ਜੋ ਵੀ ਮਨ ਨੂੰ ਕਰ ਜਾਏ । ਛੁੱਟ ਜਾਏ ਓਹ ਮਾਇਆ ਦੇ ਬੰਧਨਾਂ ਤੋਂ, ਸਾਗਰ ਦੁੱਖਾਂ ਦੇ ਸਾਰੇ ਉਹ ਤਰ ਜਾਏ ।",
  "38": "ਕਿਸੇ ਆਦਮੀ ਦਾ ਚਿੱਤ ਥਿਰ ਨਹੀਂ ਜੇ, ਸੱਚੇ ਧਰਮ ਨੂੰ ਵੀ ਜਿਹੜਾ ਜਾਣਦਾ ਨਹੀਂ । ਉਹ ਆਪਣੀ ਧੁੰਦਲੀ ਸੋਚ ਕਾਰਨ, ਕਿਸੇ ਗੱਲ ਨੂੰ ਠੀਕ ਪਛਾਣਦਾ ਨਹੀਂ । ਜਿਸ ਦੀ ਮੱਤ ਟਿਕਾਣਿਓਂ ਹਿੱਲ ਜਾਏ, ਪੁਰਸ਼ ਸਦਾ ਹੀ ਜੋ ਪਰੇਸ਼ਾਨ ਰਹਿੰਦਾ । ਗੱਲ ਫੇਰ ਇਹ ਪੱਥਰ ਤੇ ਲੀਕ ਜਾਣੋ, ਕੱਚ ਘਰੜ ਹੈ ਉਹਦਾ ਗਿਆਨ ਰਹਿੰਦਾ ।",
  "39": "ਓਸ ਆਦਮੀ ਨੂੰ ਉਪਜੇ ਭੈ ਕੋਈ ਨਾ, ਜਿਸ ਦਾ ਚਿੱਤ ਟਿਕਾਣਿਓਂ ਨਾ ਭਟਕੇ । ਜੀਹਦੇ ਧੁੰਦਲੇ ਨਹੀਂ ਵਿਚਾਰ ਹੁੰਦੇ, ਦੁਬਿਧਾ ਓਸ ਨੂੰ ਕਦੇ ਨਾ ਦਏ ਝਟਕੇ । ਸਾਵਧਾਨ, ਸੁਚੇਤ, ਜੋ ਜਾਗਦਾ ਹੈ, ਜਿਸ ਦੇ ਚਿੱਤ ਅੰਦਰ ਕੋਈ ਕਰਕ ਹੈ ਨਾ । ਪੁੰਨ, ਪਾਪ ਤੋਂ ਬੈਠਾ ਨਵੇਕਲਾ ਜੋ, ਹਰਖ ਸੋਗ ਅੰਦਰ ਜੀਹਨੂੰ ਫਰਕ ਹੈ ਨਾ ।",
  "40": "ਭੱਜਣ ਹਾਰ ਸਰੀਰ ਨੂੰ ਘੜਾ ਸਮਝੇ, ਪੱਕਾ ਗੜ੍ਹ ਜਿਉਂ ਆਪਣਾ ਚਿੱਤ ਕਰ ਲਏ । ਕਰੇ ਯੁੱਧ ਗਿਆਨ ਦਾ ਪਕੜ ਖੰਡਾ, ਮਾਇਆ, ਮੋਹ ਤੇ ਨਿਸਚੇ ਦੀ ਜਿੱਤ ਕਰ ਲਏ । ਜਿੱਤ ਜਿੱਤ ਕੇ ਹੋਏ ਅਵੇਸਲਾ ਨਾ, ਭਾਰ ਫ਼ਰਜ਼ ਦਾ ਸਮਝੇਗਾ ਮੋਢਿਆਂ ਤੇ । ਜਿੱਤੀ ਹੋਈ ਓਹ ਮੱਲ ਦੀ ਕਰੇ ਰਾਖੀ, ਧਰਕੇ ਹੱਥ ਨਾ ਬਹੇਗਾ ਗੋਡਿਆਂ ਤੇ ।",
  "41": "ਹਾਏ ! ਏਸ ਸਰੀਰ ਨੇ ਵਿਣਸ ਜਾਣਾ, ਛੇਤੀ ਜ਼ਿੰਦਗੀ ਏਸ ਤੋਂ ਦੂਰ ਹੋਣੀ । ਇਹਦੇ ਫੇਰ ਨਹੀਂ ਢੁੱਕਣਾ ਕਿਸੇ ਨੇੜੇ, ਇਹਦੀ ਚੇਤਨਾ ਸਭ ਕਾਫੂਰ ਹੋਣੀ । ਫੇਰ ਏਸ ਕੀ ਕਿਸੇ ਦੇ ਕੰਮ ਆਉਣਾ, ਬਣਨਾ ਕੋਈ ਨਾ ਏਸ ਦਾ ਯਾਰ ਬੇਲੀ । ਪਿਆ ਰਹੇਗਾ ਇਸ ਤਰ੍ਹਾਂ ਖ਼ਾਕ ਉਤੇ, ਹੁੰਦੀ ਕਾਠ ਦੀ ਜਿਸ ਤਰ੍ਹਾਂ ਪਈ ਗੇਲੀ ।",
  "42": "ਜਿਹੜੀ ਕਰਨ ਕਦੂਰਤਾਂ ਕਰਨ ਵਾਲੇ, ਭੈੜੀ, ਨਾਲ ਕਦੂਰਤਾਂ ਵਾਲਿਆਂ ਦੇ । ਬੁਰਾ ਕਰਨ ਜੋ ਵੈਰ ਕਮਾਉਣ ਵਾਲੇ, ਨਾਲ ਵੈਰੀਆਂ ਈਰਖਾ ਵਾਲਿਆਂ ਦੇ । ਉਹਨਾਂ ਨਾਲੋਂ ਵੀ ਕਰੇ ਨੁਕਸਾਨ ਬਹੁਤਾ, ਨਹੀਂ ਮੇਚ ਬੰਨਾ ਜੀਹਦਾ ਦੱਸ ਹੁੰਦਾ । ਮਾਇਆ ਮੋਹ ਦੇ ਮਾਰਗ ਤੇ ਤੁਰਨ ਵਾਲਾ, ਚਿੱਤ ਜੋ ਸ਼ੈਤਾਨ ਦੇ ਵੱਸ ਹੁੰਦਾ ।",
  "43": "ਸ਼ੱਕ ਏਸ ਵਿੱਚ ਰੱਤੀ ਰਵਾਲ ਕੋਈ ਨਾ, ਮਾਂ, ਪਿਓ ਨੇ ਸਦਾ ਉਪਕਾਰ ਕਰਦੇ । ਕਈ ਵਾਰ ਪਿਆਰ ਤੇ ਦਸਤਗੀਰੀ, ਸਾਕ ਅੰਗ ਸਾਰੇ, ਰਿਸ਼ਤੇਦਾਰ ਕਰਦੇ । ਪਰ ਜੇ ਮਨ ਪਰਬੋਧਿਆ ਹੋਏ ਕਿਧਰੇ, ਸੰਗੀ ਕੋਈ ਨਾ ਓਸਦੇ ਨਾਲ ਦਾ ਏ । ਤੋਰੇ ਆਦਮੀ ਨੂੰ ਸਿੱਧੇ ਰਾਹ ਉੱਤੇ, ਅੰਗ, ਸੰਗ ਮੁਹੱਬਤਾਂ ਪਾਲਦਾ ਏ ।",
  "chap4": "ਪੁੱਫ",
  "44": "ਮਹਾਂਬਲੀ ਤੇ ਸੂਰਮਾ ਕੌਣ ਐਸਾ, ਮਾਤ ਲੋਕ ਦੇ ਸਣੇ ਯਮਲੋਕ ਜਿੱਤੇ । ਦਿਗ ਵਿਜੇ ਸੁਰ ਲੋਕ ਦੀ ਕਰੇ ਕਿਹੜਾ, ਕੌਣ ? ਮਾਈ ਦਾ ਲਾਲ ਪਰਲੋਕ ਜਿੱਤੇ । ਜਿਵੇਂ ਹੱਥਾਂ ਦਾ ਕੋਈ ਸੁਚਿਆਰ ਮਾਲੀ, ਨਾਲ ਰੀਝਾਂ ਦੇ ਫੁੱਲਾਂ ਨੂੰ ਪਾਲਦਾ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਧਰਮ ਦੇ ਮਾਰਗਾਂ ਨੂੰ, ਭਲਾ ਵੇਖੀਏ ਕੌਣ ਸੰਭਾਲਦਾ ਏ ।",
  "45": "ਸੱਚਾ ਸ਼ਿਸ਼ ਜਾਂ ਚੇਲਾ ਵੀ ਸੂਰਮਾ ਹੈ, ਜਿਹੜਾ ਲੋਕ ਦੇ ਸਣੇ ਯਮਲੋਕ ਜਿੱਤੇ । ਦਿਗ ਵਿਜੇ ਸੁਰਲੋਕ ਤੇ ਪਾਏ ਜਿਹੜਾ, ਏਹੀ ਮਾਈ ਦਾ ਲਾਲ ਪਰਲੋਕ ਜਿੱਤੇ । ਜਿਵੇਂ ਹੱਥਾਂ ਦਾ ਕੋਈ ਸੁਚਿਆਰ ਮਾਲੀ, ਨਾਲ ਰੀਝਾਂ ਦੇ ਫੁੱਲਾਂ ਨੂੰ ਪਾਲਦਾ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਧਰਮ ਦੇ ਮਾਰਗਾਂ ਨੂੰ, ਚੇਲਾ ਭਾਲਦਾ ਅਤੇ ਸੰਭਾਲਦਾ ਏ ।",
  "46": "ਜਾਣ ਲਏ ਜੋ ਆਪਣੇ ਜਿਸਮ ਬਾਰੇ, ਨਿਰਾ ਬੁਲਬੁਲਾ ਇਹ ਤਾਂ ਆਬ ਦਾ ਏ । ਮਿਰਗਛਲੀ ਜਾਂ ਨਜ਼ਰ ਦਾ ਹੈ ਧੋਖਾ, ਝਾਕਾ ਇਕ ਸੁਹਾਵਣੇ ਖ਼ਾਬ ਦਾ ਏ । ਪੁਸ਼ਪਬਾਣ ਉਹ ਮਾਇਆ ਦੇ ਭੰਨ੍ਹ ਸੁੱਟੇ, ਨਹੀਂ ਓਸ ਤੇ ਮੋਹ ਦਾ ਵਾਰ ਹੁੰਦਾ । ਉਹਨੂੰ ਫੇਰ ਯਮਰਾਜ ਨੇ ਮਾਰਨਾ ਕੀ, ਉਹ ਯਮਾਂ ਦੀ ਪਕੜ ਤੋਂ ਪਾਰ ਹੁੰਦਾ ।",
  "47": "ਘਰੀਂ ਚੱਲਿਆ ਕਿਸੇ ਦਾ ਮਨ ਜੇਕਰ, ਓਹਦੀ ਸੁਰਤ ਅੰਦਰ ਇੰਤਸ਼ਾਰ ਹੋਵੇ । ਰਹੇ ਵਿਸ਼ੇ ਵਿਕਾਰਾਂ ਦੇ ਵਿਚ ਫਾਥਾ, ਜੀਹਨੂੰ ਹੋਰ ਨਾ ਕੋਈ ਵਿਹਾਰ ਹੋਵੇ । ਪੁਸ਼ਪ ਕਾਮ ਦੇ ਇਉਂ ਜੋ ਚੁਨਣ ਵਾਲੇ, ਮੌਤ ਉਹਨਾਂ ਦੀ ਧੌਣ ਮਰੋੜ ਜਾਏ । ਡੂੰਘੀ ਨੀਂਦ ਅੰਦਰ ਸੁੱਤੇ ਪਿੰਡ ਤਾਈਂ, ਪਾਣੀ ਜਿਸ ਤਰ੍ਹਾਂ ਹੜ੍ਹਾਂ ਦਾ ਰੋਹੜ ਜਾਏ ।",
  "48": "ਓਸ ਆਦਮੀ ਨੂੰ ਮੌਤ ਕਰੇ ਨਿੱਸਲ, ਕਾਮ ਭੋਗ ਵਿਚ ਜੋ ਗ਼ਲਤਾਨ ਰਹਿੰਦਾ । ਸਦਾ ਖਿਲਰੇ ਰਹਿਣ ਖ਼ਿਆਲ ਜੀਹਦੇ, ਜਿਸ ਦਾ ਮਨ ਚੰਚਲ ਪਰੇਸ਼ਾਨ ਰਹਿੰਦਾ । ਕਾਮ ਫੁੱਲ ਖ਼ੁਸ਼ਬੋਈਆਂ ਮਾਣਦਾ ਰਹੇ, ਬਿਨਾਂ ਐਸ਼ ਨਾ ਜਿਸ ਨੂੰ ਵਿਹਾਰ ਹੁੰਦਾ । ਖ਼ੁਸ਼ੀਆਂ ਸਾਰੀਆਂ ਵਿਚ ਬਦਮਸਤ ਹੋ ਕੇ, ਜਿਸ ਨੂੰ ਜ਼ਰਾ ਨਾ ਸਬਰ ਕਰਾਰ ਹੁੰਦਾ ।",
  "49": "ਮੱਖੀ ਮਾਖਿਓਂ ਫੁੱਲ ਚੋਂ ਚੁਕ ਉਡਦੀ, ਕਾਰਜ ਆਪਣਾ ਇਸ ਤਰ੍ਹਾਂ ਰਾਸ ਕਰਦੀ । ਨਾ ਹੀ ਫੁੱਲ ਦੀ ਮਹਿਕ ਨੂੰ ਮਾਰਦੀ ਹੈ, ਨਾ ਹੀ ਰੰਗ ਦਾ ਸਤਿਆਨਾਸ ਕਰਦੀ । ਭਿਖਸ਼ੂ ਸੋਚ ਕੇ ਬੰਨ੍ਹ ਲਏ ਗੱਲ ਪੱਲੇ, ਕਰੇ ਮਨ ਦੇ ਨਾਲ ਇਕਰਾਰ ਏਦਾਂ । ਕਰਦੀ ਸ਼ਹਿਦ ਮੱਖੀ ਜਿਵੇਂ ਫੁੱਲ ਦੇ ਨਾਲ, ਵੜੇ ਪਿੰਡ ਤਾਂ ਕਰੇ ਵਿਹਾਰ ਏਦਾਂ ।",
  "50": "ਕਾਹਨੂੰ ਕਿਸੇ ਦੇ ਟੋਲਦੇ ਐਬ ਫਿਰਨਾ, ਚੰਗਾ ਨਹੀਂ ਹੈ ਭਾਲਣਾ ਖਾਮੀਆਂ ਦਾ । ਕੋਈ ਕੀ ਕਰਦਾ, ਕੀ ਨਹੀਂ ਕਰਦਾ ? ਰਹਿਣਾ ਪੁੱਛਦੇ, ਮੂਲ ਬਦਨਾਮੀਆਂ ਦਾ । ਲੈਣੇ ਨਿੰਨਵੇਂ ਇਸ ਤਰ੍ਹਾਂ ਗੱਲ ਕੋਝੀ, 'ਦੱਸੀਂ ਯਾਰ ਫਲਾਣੇ ਦੀ ਕਾਰ ਕੀ ਹੈ ?' ਹਰ ਕਿਸੇ ਨੂੰ ਜਾਨਣਾ ਇਹ ਚਾਹੀਏ, 'ਮੇਰਾ ਆਪਣਾ ਅਮਲ ਕਿਰਦਾਰ ਕੀ ਹੈ ?'",
  "51": "ਖਿੜਿਆ ਫੁੱਲ ਸੁੰਦਰ ਭਾਵੇਂ ਹੋਏ ਕਿੰਨਾ, ਮਨ ਮੋਹਣਾ ਅਤੇ ਖ਼ੁਸ਼ਰੰਗ ਹੋਵੇ । ਜੇਕਰ ਓਸ ਤੋਂ ਨਹੀਂ ਖ਼ੁਸ਼ਬੋ ਆਉਂਦੀ, ਓਹਦਾ ਰੰਗ ਵੀ ਫੇਰ ਬੇਰੰਗ ਹੋਵੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਜਾਣੀਏ ਓਹ ਨਿਹਫਲ, ਵਾਂਗ ਮਾਖਿਓਂ ਦੇ ਮਿੱਠਾ ਬੋਲਦਾ ਜੋ । ਪਰ ਨਾ ਰੱਖ ਕੇ ਤੱਕੜੀ ਜ਼ਿੰਦਗੀ ਦੀ, ਕੌਲ, ਫੇਲ੍ਹ ਤਾਈਂ ਸਾਵਾਂ ਤੋਲਦਾ ਜੋ ।",
  "52": "ਜਿਵੇਂ ਫੁੱਲ ਸੋਹਣਾ, ਖਿੜਿਆ ਮਨ ਮੋਹਣਾ, ਮਹਿਕ ਆਪਣੀ ਖ਼ੂਬ ਖਿਲਾਰਦਾ ਹੈ । ਕਦਮ ਤੁਰਦਿਆਂ ਰਾਹੀਆਂ ਦੇ ਰੁਕ ਜਾਂਦੇ, ਹਰ ਕੋਈ ਓਸ ਦਾ ਰੂਪ ਨਿਹਾਰਦਾ ਹੈ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਫਲ ਕਮਾਈ ਓਹਦੀ, ਮਿੱਠੀ ਮਾਖਿਓਂ ਜੀਹਦੀ ਤਕਰੀਰ ਹੁੰਦੀ । ਨਾਲੇ ਹੁੰਦਾ ਹੈ ਕਰਨੀ ਦਾ ਸੂਰਮਾ ਜੋ, ਓਹਦੇ ਬੋਲਾਂ ਦੇ ਵਿਚ ਤਾਸੀਰ ਹੁੰਦੀ ।",
  "53": "ਢੇਰ ਫੁੱਲਾਂ ਦੇ ਮਹਿਕਦੇ ਮਲਕੜੇ ਈ, ਪਾਣੀ ਜਿਵੇਂ ਛਿੜਕਾ ਕੇ ਧੋ ਲਈ ਦੇ । ਫੇਰ ਹੱਥਾਂ ਵਿਚ ਪਕੜ ਕੇ ਸੂਈ ਧਾਗਾ, ਝੱਟ ਸੈਂਕੜੇ ਹਾਰ ਪਰੋ ਲਈ ਦੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਆਣ ਕੇ ਵਿਚ ਦੁਨੀਆਂ, ਜਿਥੋਂ ਤੱਕ ਵੀ ਹੋਏ ਭਲਾਈ ਕਰੀਏ । ਜਿਹੜੀ ਲੋਕ ਪਰਲੋਕ ਵਿਚ ਕੰਮ ਆਏ, ਖ਼ੁਸ਼ਬੋ ਵੰਡਦੀ ਨੇਕ ਕਮਾਈ ਕਰੀਏ ।",
  "54": "ਬਾਸ ਫੁੱਲਾਂ ਤੇ ਚੰਦਨ ਚੰਬੇਲੀਆਂ ਦੀ, ਸਦਾ ਮਨਾਂ ਨੂੰ ਭਾਵੇਂ ਲੁਭਾ ਸਕਦੀ । ਮਹਿਕ ਇਹਨਾਂ ਪਰ ਸਭਨਾਂ ਸੁਗੰਧੀਆਂ ਦੀ, ਕਦੀ ਹਵਾ ਦੇ ਉਲਟ ਨਹੀਂ ਜਾ ਸਕਦੀ । ਨੇਕ ਦਿਲ ਇਨਸਾਨ ਦੀ ਮਹਿਕ ਐਪਰ, ਖਿੰਡਣ ਵਾਸਤੇ ਹਵਾ ਨੂੰ ਲੋੜਦੀ ਨਹੀਂ । ਸਭਨੀ ਪਾਸੀਂ ਸੁਗੰਧੀਆਂ ਵੰਡਦੀ ਹੈ, ਮੁਖ ਕਦੇ ਵੀ ਕਿਸੇ ਤੋਂ ਮੋੜਦੀ ਨਹੀਂ ।",
  "55": "ਕੌਲ ਫੁੱਲ ਜਾਂ ਹੋਣ ਚੰਬੇਲੀ ਦੇ ਫੁੱਲ, ਫੁੱਲ ਹੋਰ ਵੀ ਹੋਣ ਜੋ ਟਹਿਕਦੇ ਨੇ, ਧੂਫਾਂ ਸਣੇ ਪਦਾਰਥ ਖ਼ੁਸ਼ਬੋਈ ਵਾਲੇ, ਜੋ ਵੀ ਮਨ ਹਰਸ਼ਾਉਂਦੇ ਮਹਿਕਦੇ ਨੇ । ਭਾਵੇਂ ਮਹਿਕਾਂ ਇਹ ਸਾਰੀਆਂ ਮਿੱਠੀਆਂ ਨੇ, ਇਹਨਾਂ ਨਾਲ ਦੀ ਸੋਹਜ ਬਖਸ਼ੀਸ਼ ਕੋਈ ਨਾ । ਸਦਾਚਾਰ ਸੁਗੰਧੀ ਪਰ ਜੋ ਵੰਡੇ, ਹੁੰਦੀ ਇਹਨਾਂ ਤੋਂ ਓਸ ਦੀ ਰੀਸ ਕੋਈ ਨਾ ।",
  "56": "ਚੰਦਨ, ਧੂਫ ਤੋਂ ਜੋ ਖ਼ੁਸ਼ਬੋ ਆਉਂਦੀ, ਓਹ ਚੀਜ਼ ਤਾਂ ਰਤੀ ਰਵਾਲ ਹੁੰਦੀ । ਸਦਾਚਾਰ ਤੋਂ ਜੋ ਸੁਗੰਧ ਆਏ, ਓਹੀ ਅਸਲ ਵਿਚ ਹੈ ਕਮਾਲ ਹੁੰਦੀ । ਓਹੀ ਹੁੰਦੀ ਖ਼ੁਸ਼ਬੋਈ ਹੈ ਸਰਬ-ਉੱਤਮ, ਓਹਦੇ ਨਾਲ ਹੀ ਚਾਰ ਚੁਫੇਰ ਮਹਿਕੇ । ਲਪਟਾਂ ਓਹਦੀਆਂ ਨਾਲ ਤਾਂ ਦੇਵਤੇ ਵੀ, ਸਦਾ ਖ਼ੁਸ਼ੀ ਤੇ ਖੇੜੇ ਵਿਚ ਰਹਿਣ ਟਹਿਕੇ ।",
  "57": "ਸਦਾਚਾਰ ਦੀ ਜਿਨ੍ਹਾਂ ਦੇ ਕੋਲ ਪੂੰਜੀ, ਜੋ ਵੀ ਜਾਗਦੇ ਸਦਾ ਚੈਤੰਨ ਰਹਿੰਦੇ । ਦੂਰ ਰੱਖ ਕੇ ਆਲਸ ਤੇ ਨੇਸਤੀ ਨੂੰ, ਬੜੇ ਚਿੱਤ ਦੇ ਵਿਚ ਪਰਸੰਨ ਰਹਿੰਦੇ । ਉਹ ਮੁਕਤ ਗਿਆਨ ਦੇ ਨਾਲ ਹੋਏ, ਕੋਈ ਉਹਨਾਂ ਨੂੰ ਹਟਕ ਨਾ ਟੋਕ ਸਕੇ । ਮੋਹ ਮਾਇਆ ਦੀ ਫੇਰ ਮਜਾਲ ਕੀ ਹੈ, ਰਾਹ ਉਹਨਾਂ ਦਾ ਲੱਭ ਜਾਂ ਰੋਕ ਸਕੇ ।",
  "58": "ਜਿਵੇਂ ਰਾਹ ਦੇ ਕੂੜੇ ਦੇ ਢੇਰ ਅੰਦਰ, ਕਮਲ ਉੱਗ ਆਉਂਦੇ ਸੁੰਦਰ ਰੂਪ ਵਾਲੇ । ਲਪਟਾਂ ਮਹਿਕਾਂ ਖਿਲਾਰਦੇ ਹਰ ਪਾਸੇ, ਪੁਸ਼ਪ ਸੁਗਮ ਸੁਗੰਧ ਅਨੂਪ ਵਾਲੇ ।",
  "59": "ਓਸੇ ਤਰ੍ਹਾਂ ਅਗਿਆਨ ਦੇ ਮਾਰਿਆਂ ਚੋਂ, ਅਕਸਰ ਛੇਕਿਆ ਜਿਨ੍ਹਾਂ ਨੂੰ ਜੱਗ ਹੁੰਦਾ । ਲਿਸ਼ਕੇ ਕੋਈ ਸੁਬੁੱਧ ਗਿਆਨ ਵਾਲਾ, ਜੀਹਦਾ ਨੂਰ ਤੇ ਤੇਜ ਸੁਲੱਗ ਹੁੰਦਾ ।",
  "chap5": "ਬਾਲ",
  "60": "ਹੁੰਦੀ ਰਾਤ ਲੰਮੀ ਜਾਗਣ ਵਾਲਿਆਂ ਲਈ, ਔਖੀ ਲੰਘਦੀ ਗਿਣਦਿਆਂ ਤਾਰਿਆਂ ਨੂੰ । ਮੰਜ਼ਲ ਦੂਰ ਦੁਰਾਡੜੀ ਜਾਪਦੀ ਹੈ, ਸਦਾ ਪਾਂਧੀਆਂ ਥੱਕਿਆਂ ਹਾਰਿਆਂ ਨੂੰ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਮੂੜ੍ਹ ਅਗਿਆਨੀਆਂ ਲਈ, ਦਿਲ ਜਿਨ੍ਹਾਂ ਦੇ ਵਾਂਗ ਮਨੂਰ ਹੁੰਦੇ । ਖਾਲੀ ਧਰਮ, ਗਿਆਨ ਦੀ ਸਾਰ ਬਾਝੋਂ, ਚੱਕਰ ਜ਼ਿੰਦਗੀ ਦੇ ਲੰਮੇ ਦੂਰ ਹੁੰਦੇ ।",
  "61": "ਮਿਲੇ ਜੇ ਨਾ ਜੀਵਨ ਦੇ ਪੰਧ ਅੰਦਰ, ਕੋਈ ਆਪਣੇ ਤੋਂ ਕਿਧਰੇ ਯਾਰ ਚੰਗਾ । ਮਿਲੇ ਕੋਈ ਜੇ ਆਪਣੇ ਨਾਲ ਸਾਵਾਂ, ਹੌਲਾ ਰਾਹ ਦੇ ਕਰੇ ਉਹ ਭਾਰ ਚੰਗਾ । ਤੁਰਨਾ ਪਏ ਜੇਕਰ ਕੱਲਮ-ਕੱਲਿਆਂ ਵੀ, ਤੁਰੀਏ ਨਾਲ ਜਿਗਰੇ, ਮੰਜ਼ਲ ਪਾਸ ਆਉਂਦੀ । ਬਿਨ੍ਹਾਂ ਮੂੜ੍ਹ ਹਮਰਾਹੀ ਦੇ ਸਫ਼ਰ ਚੰਗਾ, ਮੂਰਖ ਨਾਲ ਨਾ ਦੋਸਤੀ ਰਾਸ ਆਉਂਦੀ ।",
  "62": "'ਬੜੇ ਪੁੱਤ ਮੇਰੇ, ਦੌਲਤ ਮਾਲ ਮੇਰਾ', ਇਹਨਾਂ ਸੋਚਾਂ ਵਿਚ ਮੂੜ੍ਹ ਗ਼ਲਤਾਨ ਰਹਿੰਦਾ । ਇਹੀ ਚਿੰਤਾ ਘ੍ਰੋੜਦੀ ਰਹੇ ਉਹਨੂੰ, ਫਿਕਰ ਮਾਰਿਆ, ਤੇ ਪਰੇਸ਼ਾਨ ਰਹਿੰਦਾ । ਰਮਜ਼ ਏਸ ਨੂੰ ਜ਼ਰਾ ਪਛਾਣਦਾ ਨਹੀਂ, 'ਕਿਵੇਂ ਪੁੱਤ ਓਹਦੇ, ਕਿਵੇਂ ਮਾਲ ਓਹਦਾ' । ਹੋਰ ਗੱਲਾਂ ਤਾਂ ਰਹਿ ਗਈਆਂ ਇਕ ਪਾਸੇ, ਨਹੀਂ 'ਆਪਣਾ ਆਪ' ਵੀ ਨਾਲ ਓਹਦਾ ।",
  "63": "ਸਮਝੇ ਜੇ ਮੂਰਖ 'ਮੈਂ ਤਾਂ ਹਾਂ ਮੂਰਖ', ਅਕਲ ਸਮਝ ਦੇ ਨਾਲ ਆਰਾਸਤਾ ਨਹੀਂ । ਓਸ ਹੱਦ ਤਕ ਹੋ ਗਿਆ ਓਹ ਪੰਡਤ, ਓਹਦਾ ਮੂਰਖਾਂ ਨਾਲ ਫਿਰ ਵਾਸਤਾ ਨਹੀਂ । ਮੂਰਖ ਹੁੰਦਿਆਂ ਸਮਝਦਾ ਇਉਂ ਜੇਕਰ, 'ਪੰਡਤ, ਅਕਲ ਦਾ ਕੋਟ, ਵਿਦਵਾਨ ਹੈ ਉਹ'। ਅਸਲ ਵਿਚ ਫਿਰ ਜਾਣੀਏਂ ਮੂਰਖਾਂ ਦਾ, ਬਿਨਾਂ ਤਾਜ ਦੇ ਸ਼ਾਹ ਸੁਲਤਾਨ ਹੈ ਉਹ ।",
  "64": "ਕੋਲ ਪੰਡਤਾਂ ਬੈਠ ਕੇ ਮੂੜ੍ਹ ਕੋਈ, ਭਾਵੇਂ ਸਾਰੀ ਹੀ ਉਮਰ ਗੁਜ਼ਾਰ ਜਾਏ । ਖਾਲੀ ਗਿਆਨ ਤੋਂ ਰਹੇ ਅਣਭਿੱਜ ਪੱਥਰ, ਨਹੀਂ ਧਰਮ ਦੇ ਰਾਹ ਦੀ ਸਾਰ ਪਾਏ । ਹਾਲਤ ਓਸ ਦੀ ਕੜਛੀ ਦੇ ਵਾਂਗ ਹੁੰਦੀ, ਜਿਹੜੀ ਵੰਡਦੀ ਦਾਲ ਜਾਂ ਤਰੀ ਰਹਿੰਦੀ । ਨਾ ਪਰ ਜਾਣਦੀ ਉਹਦਾ ਸੁਆਦ ਕੀ ਹੈ ? ਭਾਵੇਂ ਮੂੰਹ ਵਿਚ ਦਾਲ ਹੈ ਭਰੀ ਰਹਿੰਦੀ ।",
  "65": "ਕੋਲ ਪੰਡਤਾਂ ਦੇ ਸਮਝਦਾਰ ਕੋਈ, ਇਕ ਪਲ ਵੀ ਭਾਵੇਂ ਗੁਜ਼ਾਰ ਜਾਏ । ਓਹ ਰਮਜ਼ ਗਿਆਨ ਦੀ ਸਮਝ ਲੈਂਦਾ, ਪਾ ਧਰਮ ਦੇ ਰਾਹ ਦੀ ਸਾਰ ਜਾਏ । ਉਹਦਾ ਜੀਭ ਦੇ ਵਾਂਗ ਵਿਹਾਰ ਸਮਝੋ, ਜਿਹੜੀ ਗੱਲ ਨੂੰ ਟੋਹ ਕੇ ਦੱਸ ਜਾਏ । ਇਹ ਚੰਗਾ ਸੁਆਦ ਜਾਂ ਹੈ ਮਾੜਾ, ਦਾਲ-ਤਰੀ ਨੂੰ ਛੋਹ ਕੇ ਦੱਸ ਜਾਏ ।",
  "66": "ਕੌਡੀ ਅਕਲ ਨਾ ਜਿਨ੍ਹਾਂ ਦੇ ਕੋਲ ਹੁੰਦੀ, ਮੂੜ੍ਹ ਕਦੇ ਨਾ ਚੱਜ ਦੀ ਕਾਰ ਕਰਦੇ । ਜਿਵੇਂ ਆਪਣੇ ਆਪ ਦੇ ਹੋਣ ਵੈਰੀ, ਇਉਂ ਆਪਣੇ ਨਾਲ ਵਿਹਾਰ ਕਰਦੇ । ਨਹੀਂ ਮੋੜਦੇ ਮੁੱਖ ਓਹ ਪਾਪ ਵੱਲੋਂ, ਕਰਦੇ ਰਹਿਣ ਓਹ ਮਾੜਿਆਂ ਧੰਦਿਆਂ ਨੂੰ । ਪੈਣ ਭੋਗਣੇ ਓਹਨਾਂ ਨੂੰ ਫਲ ਕੌੜੇ, ਸਦਾ ਲੱਗਦੇ ਜੋ ਕੰਮਾਂ ਮੰਦਿਆਂ ਨੂੰ ।",
  "67": "ਕਹੀ ਗੱਲ ਜੋ ਹੈ ਸਿਆਣਿਆਂ ਨੇ, ਉਪਰ ਓਸ ਦੇ ਸਦਾ ਵਿਚਾਰ ਕਰੀਏ । ਜਿਸ ਦੇ ਅੰਤ ਨੂੰ ਵੇਖ ਪਛਤਾਉਣਾ ਪਏ, ਕਦੇ ਭੁੱਲ ਕੇ ਓਹ ਨਾ ਕਾਰ ਕਰੀਏ । ਜਿਹੜਾ ਕੰਮ ਮਾੜਾ ਓਹਨੂੰ ਕਰਨ ਵਾਲਾ, ਸਦਾ ਅੰਤ ਨੂੰ ਬਾਜ਼ੀਆਂ ਹਾਰਦਾ ਏ । ਨੈਣੀਂ ਅੱਥਰੂ ਹੌਕਿਆਂ ਨਾਲ ਫਾਵਾ, ਰੋਂਦਾ ਕੂਕਦਾ ਤੇ ਢਾਹੀਂ ਮਾਰਦਾ ਏ ।",
  "68": "ਸਮਝੋ, ਕਾਜ ਸੁਹੇਲੜਾ ਓਹ ਥੀਆ, ਜੀਹਦਾ ਅੰਤ ਨਹੀਂ ਕਦੇ ਕਸਤਾਲ ਹੁੰਦਾ । ਜਿਸ ਨੂੰ ਕਰਦਿਆਂ ਆਦਮੀ ਰਹੇ ਰਾਜ਼ੀ, ਓਹਦੇ ਚਿੱਤ ਨੂੰ ਨਹੀਂ ਮਲਾਲ ਹੁੰਦਾ । ਐਸੇ ਕੰਮ ਦਾ ਜੋ ਹੈ ਕਰਨ ਹਾਰਾ, ਓਹ ਕਦੇ ਵੀ ਨਹੀਂ ਉਦਾਸ ਹੁੰਦਾ । ਕਰਦਾ ਸ਼ੁਕਰ ਤੇ ਮਾਣਦਾ ਨਿੱਤ ਖ਼ੁਸ਼ੀਆਂ, ਓਹਦੇ ਮਨ ਆਨੰਦ ਹੁਲਾਸ ਹੁੰਦਾ ।",
  "69": "ਕੱਚਾ ਫਲ ਗੁਨਾਹ ਦਾ ਜਦੋਂ ਤੀਕਰ, ਚੰਗੀ ਤਰ੍ਹਾਂ ਸਵਾਰ ਕੇ ਪੱਕਦਾ ਨਹੀਂ । ਮੂਰਖ ਸਮਝ ਕੇ ਓਸ ਨੂੰ ਸ਼ਹਿਦ ਮਿੱਠਾ, ਮੂੰਹ ਮਾਰਦਾ ਚੱਖਦਾ ਥੱਕਦਾ ਨਹੀਂ । ਜਦੋਂ ਫਲ ਗੁਨਾਹ ਦਾ ਪੱਕ ਜਾਏ, ਮੂੜ੍ਹ ਜੋ ਸੀ ਕੱਚੇ ਨੂੰ ਮੁੱਖ ਲਾਉਂਦਾ । ਕੌੜਾ ਓਹੀ ਫਿਰ ਓਹਦਾ ਸੁਆਦ ਚੱਖੇ, ਹਾਏ, ਹਾਏ ਕਰਦਾ ਬੜਾ ਦੁੱਖ ਪਾਉਂਦਾ ।",
  "70": "ਮੂੜ੍ਹ ਤਪੀ, ਜੋ ਤੱਤ ਪਛਾਣਦਾ ਨਹੀਂ, ਐਵੇਂ ਰੀਝਿਆ ਰਹੇ ਜੋ ਫੋਕ ਉਤੇ । ਭੋਰਾ ਭੋਜਨ ਦਾ ਸਾਲ ਛਮਾਈ ਖਾਏ, ਰੱਖ ਘਾਹ ਦੇ ਤੀਲੇ ਦੀ ਨੋਕ ਉਤੇ । ਓਹਦੀ ਫੇਰ ਵੀ ਕੋਈ ਪ੍ਰਾਪਤੀ ਨਾ, ਅਸਲ ਵਿੱਚ ਓਹ ਕੌਡੀ ਦੇ ਮੁੱਲ ਦਾ ਨਹੀਂ । ਓਹ ਧਰਮੀ ਦੇ ਪੈਰਾਂ ਦੀ ਖਾਕ ਵੀ ਨਹੀਂ, ਓਹ ਦੇ ਸੋਲ੍ਹਵੇਂ ਹਿੱਸੇ ਦੇ ਤੁੱਲ ਦਾ ਨਹੀਂ ।",
  "71": "ਜਿਵੇਂ ਸੱਜਰੇ ਦੁੱਧ ਨੂੰ ਦਹੀਂ ਛਿੱਟਾ, ਝਟਾ ਪਟ ਹੀ ਕਦੇ ਫਿਟਾਉਂਦਾ ਨਹੀਂ । ਪਾਪ-ਕਰਮ ਨੂੰ ਅੱਖ ਦੀ ਫੋਰ ਅੰਦਰ, ਫਲ ਲੱਗਦਾ ਜਾਂ ਬੂਰ ਆਉਂਦਾ ਨਹੀਂ । ਜਿਵੇਂ ਅੱਗ ਸੁਆਹ ਦੇ ਵਿੱਚ ਨੱਪੀ, ਰੂਪ ਧਾਰਦੀ ਤੁਰਤ ਅੰਗਿਆਰਿਆਂ ਦੇ । ਪਾਪ ਨੱਸਦੇ ਤਿਵੇਂ ਨੇ ਮੂੜ੍ਹ ਪਿੱਛੇ, ਬਿਨਾਂ ਆਖਿਆਂ, ਬਿਨਾਂ ਸ਼ਿਸ਼ਕਾਰਿਆਂ ਦੇ ।",
  "72": "ਜੋ ਵੀ ਮੂਰਖ ਦੇ ਕੋਲ ਗਿਆਨ ਹੋਵੇ, ਭਾਵੇਂ ਉਹਦਾ ਨਾ ਕੋਈ ਕਿਆਸ ਕਰਦਾ । ਓਹ ਗਿਆਨ ਹੀ ਮੂਰਖ ਦਾ ਹੋਏ ਵੈਰੀ, ਓਹੀ ਗਿਆਨ ਹੀ ਮੂਰਖ ਦਾ ਨਾਸ ਕਰਦਾ । ਓਹੀ ਗਿਆਨ ਹੀ ਮੂਰਖ ਤੇ ਵਾਰ ਕਰਦਾ, ਓਹਨੂੰ ਹਰ ਮੈਦਾਨ ਵਿਚ ਹਾਰ ਦਿੰਦਾ । ਧੌਣ ਸਦਾ ਲਈ ਓਸ ਦੀ ਕਰੇ ਨੀਵੀਂ, ਓਹਦੇ ਚੰਗਿਆਂ ਗੁਣਾਂ ਨੂੰ ਮਾਰ ਦਿੰਦਾ ।",
  "73": "ਰਹਿੰਦੀ ਲਾਲਸਾ ਮੂੜ੍ਹ ਨੂੰ ਚੰਬੜੀ ਇਹ, ਓਹਦਾ ਜੱਗ ਤੇ ਬੱਝ ਇਤਬਾਰ ਜਾਏ । ਮਠ-ਸੰਘ ਦੇ ਵਿਚ ਓਹ ਭਿਖਸ਼ੂਆਂ ਦਾ, ਵੱਡਾ ਸੱਭ ਦਾ ਬਣ ਸਰਦਾਰ ਜਾਏ । ਓਹਦੇ ਆਪਣੇ ਘਰ ਵਿਚ ਹਰ ਕੋਈ, ਸਦਾ ਓਸ ਦਾ ਆਗਿਆਕਾਰ ਹੋਵੇ । ਜਾਏ ਜਦੋਂ ਬਗਾਨਿਆਂ ਘਰਾਂ ਅੰਦਰ, ਓਹਦਾ ਰੱਜਵਾਂ ਮਾਣ ਸਤਕਾਰ ਹੋਵੇ ।",
  "74": "ਦੁਨੀਆਂਦਾਰ ਦੇ ਨਾਲ ਹੀ ਕੋਈ ਭਿਖਸ਼ੂ, ਰਹਿੰਦਾ ਚਿੱਤ ਵਿਚ ਆਪਣੇ ਸੋਚਦਾ ਏ । 'ਹਰ ਕੰਮ ਵਿਚ ਮੇਰੀ ਰਜ਼ਾ ਚੱਲੇ', ਮਰਜ਼ੀ ਆਪਣੀ ਠੋਸਣੀ ਲੋਚਦਾ ਏ । 'ਇਹ ਮਾਅਰਕਾ ਮੈਂ ਹੀ ਮਾਰਿਆ ਹੈ', ਫੁਰਨਾ, ਸੋਚ ਇਹ ਮੂੜ੍ਹ ਅਗਿਆਨ ਦੀ ਹੈ । ਤ੍ਰਿਸ਼ਨਾ ਕਾਮਨਾ ਏਸ ਤੋਂ ਹੋਰ ਭੜਕੇ, ਅੱਗ ਸਾੜਦੀ ਨਾਲ ਅਭਿਮਾਨ ਦੀ ਹੈ ।",
  "75": "ਸੱਚਾ ਸੇਵਕ ਜੇ ਬੁੱਧ ਮਹਾਤਮਾ ਦਾ, ਭਿਖਸ਼ੂ ਰਮਜ਼ ਇਹ ਖੂਬ ਪਛਾਣਦਾ ਏ । 'ਇਕ ਰਾਹ ਸੰਸਾਰ ਦੇ ਲਾਭ ਦਾ ਹੈ, ਸਿੱਧਾ ਦੂਸਰਾ ਰਾਹ ਨਿਰਵਾਣ ਦਾ ਏ' । ਏਸ ਭੇਦ ਨੂੰ ਪਾ ਲਏ ਜਦੋਂ ਭਿਖਸ਼ੂ, ਓਹ ਮਾਨ ਸਨਮਾਨ ਤਿਆਗਦਾ ਏ । ਓਹਦੇ ਮਨ ਵਿਚ ਮੋਹ ਤੋਂ ਦੂਰ ਜਾ ਕੇ, ਮਿੱਠਾ ਪਿਆਰ ਇਕਾਂਤ ਦਾ ਜਾਗਦਾ ਏ ।",
  "chap6": "ਪੰਡਿਤ",
  "76": "ਪਰਗਟ ਦੋਸ਼ ਜੋ ਕਰੇ ਨਿਧੜਕ ਹੋ ਕੇ, ਪੰਡਤ ਰੱਖਦਾ ਸੂਝ ਜ਼ਮਾਨਿਆਂ ਦੀ । ਓਹ ਤਾਂ ਓਸ ਸਿਆਣੇ ਦੇ ਵਾਂਗ ਹੁੰਦਾ, ਦੌਲਤ ਦੱਸੇ ਜੋ ਖੁਫ਼ੀਆ ਖਜ਼ਾਨਿਆਂ ਦੀ । ਏਸ ਤਰ੍ਹਾਂ ਦਾ ਮਿਲੇ ਜੇ ਕੋਈ ਪੰਡਤ, ਓਹਦੇ ਮੇਲ ਵਿਚ ਸੁੱਖ ਮਹਾਨ ਹੋਵੇ । ਓਹਦਾ ਨੇੜ ਹੈ ਸਦਾ ਕਲਿਆਣਕਾਰੀ, ਉਸ ਤੋਂ ਕਦੇ ਨਾ ਕੋਈ ਨੁਕਸਾਨ ਹੋਵੇ ।",
  "77": "ਪੁਰਸ਼ ਝਾੜਦਾ ਤਾੜਦਾ ਰਹੇ ਜਿਹੜਾ, ਮਾਰਗ-ਸੱਚ ਦਾ ਪਰ ਉਪਦੇਸ਼ ਦਿੰਦਾ । ਹੋੜ, ਮੋੜ ਕੇ ਮਾੜਿਆਂ ਕਾਰਿਆਂ ਤੋਂ, ਕੱਟ ਜੀਉ ਦੇ ਸਰਬ ਕਲੇਸ਼ ਦਿੰਦਾ । ਐਸੇ ਆਦਮੀ ਤੇ ਮੰਦੀ ਨੀਤ ਵਾਲੇ, ਰਹਿੰਦੇ ਈਰਖਾ ਦੇ ਸਦਾ ਵਾਰ ਕਰਦੇ । ਭਲੇ ਲੋਕ ਪਰ ਕਰਨ ਪਸੰਦ ਓਹਨੂੰ, ਸੱਜਣ ਸਮਝ ਕੇ ਬੜਾ ਪਿਆਰ ਕਰਦੇ ।",
  "78": "ਬਹੀਏ ਕੋਲ ਨਾ ਮੰਦਿਆਂ ਮਿਤਰਾਂ ਦੇ, ਦੂਰੋਂ ਉਹਨਾਂ ਨੂੰ ਸਾਹਿਬ ਸਲਾਮ ਕਰੀਏ । ਨੇੜੇ ਢੁੱਕ ਨਾ ਨੀਚ ਨਿਗੱਲਿਆਂ ਦੇ, ਕਦੇ ਆਪਣਾ ਨਾਮ ਬਦਨਾਮ ਕਰੀਏ । ਲਾਈਏ ਮੂੰਹ ਸੁਲੱਖਣੇ ਮਿੱਤਰਾਂ ਨੂੰ, ਉਹਨਾਂ ਨਾਲ ਹੀ ਸੋਚ ਵਿਚਾਰ ਕਰੀਏ । ਉਤਮ ਪੁਰਸ਼ ਦੇ ਸੰਗ ਹਮੇਸ਼ ਰਹੀਏ, ਨਿੱਤ ਚੰਗਿਆਂ ਨਾਲ ਪਿਆਰ ਕਰੀਏ ।",
  "79": "ਖ਼ੁਸ਼ੀਆਂ ਖੇੜਿਆਂ ਨਾਲ ਓਹ ਰਹਿਣ ਖੀਵੇ, ਮਹਾਂ-ਰਸ ਜੋ ਧਰਮ ਦਾ ਪੀਣ ਵਾਲੇ । ਨਿਰਮਲ ਮਨ ਤੇ ਸੋਚ ਸਵੱਛ ਰੱਖਣ, ਸਦਾ ਨਾਲ ਆਨੰਦ ਜੋ ਜੀਣ ਵਾਲੇ । ਲੈ ਕੇ ਮਹਾਂ ਉਪਦੇਸ਼ ਗਿਆਨੀਆਂ ਤੋਂ, ਕਰਨੀ ਸੋਚਣੀ ਜਿਨ੍ਹਾਂ ਦੀ ਸ਼ੁੱਧ ਹੁੰਦੀ । ਚਲਦੇ ਰਹਿਣ ਓਹ ਧਰਮ ਦੇ ਰਾਹ ਉੱਤੇ, ਮਿਲੇ ਸ਼ਾਂਤੀ ਤੇ ਉਜਲ ਬੁੱਧ ਹੁੰਦੀ ।",
  "80": "ਵਹਿਣ ਆਡਾਂ ਦੇ ਮਰਜ਼ੀ ਦੇ ਨਾਲ ਮੋੜਨ, ਜੱਟ ਖੇਤੀਆਂ ਨੂੰ ਪਾਣੀ ਲਾਉਣ ਵਾਲੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਤੀਰ ਲਿਫਾ ਲੈਂਦੇ, ਕਾਰੀਗਰ ਜੋ ਤੀਰ ਬਣਾਉਣ ਵਾਲੇ । ਮਰਜ਼ੀ ਨਾਲ ਤਰਖਾਣ ਜਿਓਂ ਲੱਕੜੀ ਨੂੰ, ਸਿੱਧੀ ਕਰਨ, ਲਿਫਾਉਂਦੇ, ਮੋੜਦੇ ਨੇ । ਪੰਡਤ ਆਪਣੇ ਆਪ ਤੇ ਪਾ ਕਾਬੂ, ਨਿਜ-ਮਨ ਬੁਰਾਈਆਂ ਤੋਂ ਹੋੜਦੇ ਨੇ ।",
  "81": "ਜਿਵੇਂ ਠੋਸ ਪਹਾੜ ਅਡੋਲ ਹੁੰਦਾ, ਓਹਦਾ ਕੋਈ ਨਹੀਂ ਕੁਛ ਵਗਾੜ ਸਕਦਾ । ਝੱਖੜ ਝੁੱਲਦਾ ਜ਼ੋਰ ਅਜ਼ਮਾਏ ਲੱਖਾਂ, ਓਹਨੂੰ ਜੜੋਂ ਨਹੀਂ ਕਦੇ ਉਖਾੜ ਸਕਦਾ । ਬੁੱਧੀਮਾਨ ਪੰਡਤ ਓਸੇ ਤਰ੍ਹਾਂ ਹੁੰਦਾ, ਟਿਕਿਆ ਦਿਲ ਰੱਖੇ, ਕਦੇ ਡੋਲਦਾ ਨਹੀਂ । ਨਹੀਂ ਰੀਝਦਾ ਸਿਫ਼ਤ ਸਲਾਹ ਸੁਣਕੇ, ਸੁਣ ਕੇ ਨਿੰਦਿਆ ਨੂੰ ਕੌੜਾ ਬੋਲਦਾ ਨਹੀਂ ।",
  "82": "ਹੋਏ ਜਿਸ ਤਰ੍ਹਾਂ ਝੀਲ ਜੇ ਕੋਈ ਡੂੰਘੀ, ਬਿਨਾਂ ਗਾਰ ਦੇ ਓਸ ਦਾ ਤਲ ਹੋਵੇ । ਸ਼ੀਸ਼ੇ ਵਾਂਗਰਾਂ ਸਾਫ਼ ਸ਼ਫਾਫ ਲਿਸ਼ਕੇ, ਨਿਰਮਲ ਬੜਾ ਹੀ ਓਸਦਾ ਜਲ ਹੋਵੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਧਰਮ ਦੀ ਕਾਰ ਵਾਲਾ, ਸ਼ਾਂਤ ਚਿੱਤ ਤੇ ਗਹਿਰ ਗੰਭੀਰ ਹੋਵੇ । ਖ਼ੁਸ਼ੀਆਂ ਖੇੜਿਆਂ ਨਾਲ ਭਰਪੂਰ ਰਹਿੰਦਾ, ਨਾ ਹੀ ਡੋਲੇ ਤੇ ਕਦੇ ਅਧੀਰ ਹੋਵੇ ।",
  "83": "ਭਲੇ ਆਦਮੀ ਵਾਸਤਾ ਰੱਖਦੇ ਨਹੀਂ, ਹੋਵੇ ਦੂਰ ਦੀ ਤੇ ਭਾਵੇਂ ਪਾਸ ਦੀ ਗੱਲ । ਕਿਧਰੇ ਭੁੱਲ ਕੇ ਵੀ ਕਦੇ ਛੇੜਦੇ ਨਹੀਂ, ਕਿਸੇ ਨਾਲ ਓਹ ਭੋਗ ਬਿਲਾਸ ਦੀ ਗੱਲ । ਲੱਛਣ ਇਹ ਨੇ ਸੱਚਿਆਂ ਪੰਡਤਾਂ ਦੇ, ਹਰਖ ਸੋਗ ਨੂੰ ਇੱਕ ਸਮਾਨ ਸਮਝਣ । ਦੁੱਖ, ਸੁੱਖ ਨੂੰ ਸਦਾ ਅਣਡਿੱਠ ਕਰ ਕੇ, ਚੁੱਪ ਰਹਿਣ ਵਿੱਚ ਆਪਣੀ ਸ਼ਾਨ ਸਮਝਣ ।",
  "84": "ਨਾ ਹੋਰਨਾਂ ਲਈ ਨਾ ਆਪਣੇ ਲਈ, ਕਰੇ ਇੱਛਿਆ, ਨਾ ਪੁੱਤਰ ਲਾਲ ਚਾਹੇ । ਨਹੀਂ ਮੰਗਦਾ ਧਨ ਤੇ ਦੌਲਤਾਂ ਜੋ, ਰਾਜ ਭਾਗ ਨਾ ਮਿਲਖ ਤੇ ਮਾਲ ਚਾਹੇ । ਮੁੱਖ ਫੇਰ ਕੇ ਆਪਣਾ ਧਰਮ ਤੋਂ ਜੋ, ਕਦੇ ਆਪਣੀ ਉੱਨਤੀ ਭਾਲਦਾ ਨਹੀਂ । ਉੱਜਲ ਬੁੱਧ ਤੇ ਸ਼ੁਭ-ਆਚਾਰ ਵਾਲਾ, ਧਰਮੀ ਕੋਈ ਵੀ ਓਸ ਦੇ ਨਾਲ ਦਾ ਨਹੀਂ ।",
  "85": "ਵਿਰਲੇ ਕੋਈ ਹੁੰਦੇ, ਕਿਧਰੇ ਘਾਲ ਵਾਲੇ, ਜਿਹੜੇ ਆਪਣੇ ਆਪ ਨੂੰ ਮਾਰ ਜਾਂਦੇ । ਲੰਘ ਔਝੜਾਂ ਤੇ ਘੁੰਮਣ-ਘੇਰੀਆਂ ਨੂੰ, ਹੋਣ ਸੁਰਖਰੂ ਤੇ ਪਰਲੇ ਪਾਰ ਜਾਂਦੇ । ਬਾਹਲੇ ਮਿਲਦੇ ਪਰ ਓਹ ਸੰਸਾਰੀਆਂ ਵਿਚ, ਜਿਹੜੇ ਸੱਚ ਦੀ ਗੱਲ ਤੋਂ ਕੌੜਦੇ ਨੇ । ਪਰਲੇ ਪਾਰ ਤਾਂ ਓਹਨਾਂ ਨੇ ਪੁੱਜਣਾ ਕੀ, ਰਹਿੰਦੇ ਕੰਢੇ ਉਰਾਰ ਤੇ ਦੌੜਦੇ ਨੇ ।",
  "86": "ਸੱਚੇ ਧਰਮ ਦੀ ਜਿਨ੍ਹਾਂ ਨੂੰ ਸਮਝ ਆਈ, ਸੁਣ ਕੇ ਮੰਨਿਆਂ ਧਰਮ ਉਪਦੇਸ਼ ਸੱਚਾ । ਤੁਰ ਪੈਣ ਜੋ ਧਰਮ ਦੇ ਰਾਹ ਉੱਤੇ, ਰਹੇ ਜਿਨ੍ਹਾਂ ਦਾ ਚਲਨ ਹਮੇਸ਼ ਉੱਚਾ । ਇਹੀ ਲੋਕ ਨੇ ਝੱਲ ਕੇ ਔਕੜਾਂ ਜੋ, ਮੰਜ਼ਲ ਮਾਰਦੇ ਤੇ ਪਰਲੇ ਪਾਰ ਜਾਂਦੇ । ਬਿਖੜਾ ਵੇਖ ਪੈਂਡਾ ਜ਼ਰਾ ਥਿੜਕਦੇ ਨਹੀਂ, ਲੰਘ ਮੌਤ ਦੀ ਮੱਲ-ਗੁਜ਼ਾਰ ਜਾਂਦੇ ।",
  "87": "ਸਦਾ ਚਾਹੀਦਾ ਪੰਡਤਾਂ ਦਾਨਿਆਂ ਨੂੰ, ਮੰਦੇ ਕੰਮਾਂ ਬੁਰਿਆਈਆਂ ਤੋਂ ਦੂਰ ਰਹਿਣਾ । ਚੰਗੀ ਗੱਲ ਦਾ ਨਿੱਤ ਅਭਿਆਸ ਕਰਨਾ, ਨੇਕੀ, ਖ਼ੁਸ਼ੀ ਦੇ ਨਾਲ ਮਖ਼ਮੂਰ ਰਹਿਣਾ । ਘਰ ਆਪਣਾ ਛੱਡ ਬੇ-ਘਰ ਹੋਣਾ, ਕਰਨੀ ਕਿਸੇ ਤੋਂ ਕੋਈ ਨਾ ਆਸ ਚਾਹੀਏ । ਖ਼ੁਸ਼ੀਆਂ ਸੌਖੀਆਂ ਹੱਥ ਨਾ ਆਉਣ ਜਿੱਥੇ, ਹੋਣਾ ਐਸੀ ਇਕਾਂਤ ਵਿਚ ਵਾਸ ਚਾਹੀਏ ।",
  "88": "ਕਰ ਕੇ ਆਪਣਾ ਵਿਚ ਇਕਾਂਤ ਵਾਸਾ, ਸਦਾ ਖ਼ੁਸ਼ੀਆਂ ਨੂੰ ਢੂੰਡਣਾ ਭਾਲਣਾ ਜੇ । ਕਾਮ, ਭੋਗ ਬਿਲਾਸ ਤਿਆਗ ਦੇਣੇ, ਮਿਲਖ ਮਾਲਕੀ ਨੂੰ ਹੱਥੀਂ ਜਲਣਾ ਜੇ । ਇਉਂ ਪੰਡਤਾ ! ਨਿੱਤ ਅਭਿਆਸ ਕਰ ਕੇ, ਫਸਤਾ ਮੋਹ ਤੇ ਮਾਇਆ ਦਾ ਵੱਢਣਾ ਈਂ । ਮਨ ਆਪਣਾ ਮਾਂਜ ਸਫਾ ਕਰਨਾ, ਵਿਚੋਂ ਮਾਰ ਬੁਰਿਆਈਆਂ ਨੂੰ ਕੱਢਣਾ ਈਂ ।",
  "89": "ਲੈਣ ਦੇਣ ਤੋਂ ਬੇ-ਨਿਆਜ਼ ਜਿਹੜੇ, ਲੇਖੇ ਜਿਨ੍ਹਾਂ ਦੇ ਕੁਲ ਬੇਬਾਕ ਹੋ ਗਏ । ਸੁੱਚੀ ਸੋਝੀ ਨੇ ਚਿੱਤ ਵਿਚ ਲਾਏ ਡੇਰੇ, ਪੱਲੇ ਜਿਨ੍ਹਾਂ ਦੇ ਪਾਪ ਤੋਂ ਪਾਕ ਹੋ ਗਏ । ਚਿਹਰੇ ਚਮਕਦੇ ਉਹਨਾਂ ਦੇ ਦਿਲ ਰੌਸ਼ਨ, ਦਰਜਾ ਉਹਨਾਂ ਨੂੰ ਬੜਾ ਮਹਾਨ ਮਿਲਿਆ । ਗਏ ਉਹਨਾਂ ਦੇ ਸਗਲ ਜੰਜਾਲ ਕੱਟੇ, ਜਗਤ ਵਿਚ ਹੀ ਪਦ ਨਿਰਬਾਣ ਮਿਲਿਆ ।",
  "chap7": "ਅਰਹੰਤ",
  "90": "ਮੰਜ਼ਲ ਆਪਣੀ ਤੇ ਜੋ ਵੀ ਪੁੱਜ ਗਿਆ, ਜਿਸ ਤੋਂ ਦੂਰ ਉਦਾਸੀਆਂ ਹੋ ਗਈਆਂ । ਕੋਈ ਗ਼ਮ-ਅੰਦੋਹ ਨਾ ਆਏ ਨੇੜੇ, ਸਗਲ ਬੰਦ ਖਲਾਸੀਆਂ ਹੋ ਗਈਆਂ । ਮਨ-ਗੁੰਝਲਾਂ ਜਿਸ ਦੀਆਂ ਖੁਲ੍ਹ ਗਈਆਂ, ਚਿੰਤਾ ਓਸਦਾ ਚਿੱਤ ਲਤਾੜਦੀ ਨਹੀਂ । ਤਪਦਾ ਹਿਰਦਾ ਵੀ ਓਸਦਾ ਭਏ ਸੀਤਲ, ਓਸ ਨੂੰ ਪੀੜ ਸੰਤਾਪ ਦੀ ਸਾੜਦੀ ਨਹੀਂ ।",
  "91": "ਆਲਸ ਨੇਸਤੀ ਛੱਡ ਚੇਤੰਨ ਹੋ ਕੇ, ਜਿਹੜੇ ਕਰਮ-ਗਿਆਨ ਵਿਚ ਮਸਤ ਰਹਿੰਦੇ । ਖ਼ੁਸ਼ੀਆਂ ਭਾਲਦੇ ਨਹੀਂ ਓਹ ਗ੍ਰਿਹਸਤ ਅੰਦਰ, ਨਹੀਂ ਧੰਦਿਆਂ ਵਿਚ ਵਿਅਸਤ ਰਹਿੰਦੇ । ਓਹ ਤਿਆਗਦੇ ਸਭ ਲਟਾਕਿਆਂ ਨੂੰ, ਇਓਂ ਛੱਡ ਕੇ ਘਰ ਤੇ ਬਾਰ ਜਾਂਦੇ । ਜਿਵੇਂ ਲਹਿਰਦੇ ਕੌਲ ਸਰੋਵਰਾਂ 'ਚੋਂ, ਰਾਜ ਹੰਸ ਉਡਾਰੀਆਂ ਮਾਰ ਜਾਂਦੇ ।",
  "92": "ਨਹੀਂ ਗੰਜ ਜੋੜੇ ਜਿਨ੍ਹਾਂ ਦੌਲਤਾਂ ਦੇ, ਸੰਜਮ ਨਾਲ ਜੋ ਅਲਪ-ਆਹਾਰ ਕਰਦੇ । ਰਹਿਣ ਸੁੰਨ ਦੇ ਵਿਚ ਸਮਾਏ ਹੋਏ, ਨਾਲ ਜੁਗਤ-ਨਿਰਵਾਣ ਪਿਆਰ ਕਰਦੇ । ਗਤੀ ਉਹਨਾਂ ਦੀ ਪਹੁੰਚ ਤੋਂ ਪਰੇ ਹੁੰਦੀ, ਨਹੀਂ ਆਉਂਦੀ ਸਮਝ ਗਿਆਨ ਅੰਦਰ । ਜਿਵੇਂ ਪੈੜ ਨਾ ਓਹਨਾਂ ਦੀ ਹੱਥ ਆਵੇ, ਪੰਛੀ ਉਡਦੇ ਜੋ ਅਸਮਾਨ ਅੰਦਰ ।",
  "93": "ਜਿਸ ਪ੍ਰਾਣੀ ਦੇ ਪਾਪ ਸਰਾਪ ਝੜ ਗਏ, ਨਿਰਾ ਖਾਣ ਦੇ ਨਾਲ ਨਾ ਵਾਹ ਰੱਖੇ । ਜਿਹੜਾ ਸੁੰਨ-ਸਮਾਉਣ ਨਿਰਵਾਣ ਪਦਵੀ, ਮੰਜ਼ਲ ਜਾਣ ਕੇ ਓਸ ਤੇ ਨਿਗ੍ਹਾ ਰੱਖੇ । ਓਹ ਸਮਝ, ਗਿਆਨ, ਤੋਂ ਪਰੇ ਹੋਵੇ, ਦਰਜਾ ਓਸ ਦਾ ਫੇਰ ਨਾ ਆਮ ਹੁੰਦਾ । ਉੱਡਦੇ ਵਿਚ ਅਕਾਸ਼ਾਂ ਦੇ ਪੰਛੀਆਂ ਤੋਂ, ਉੱਚਾ ਬਹੁਤ ਹੀ ਓਹਦਾ ਮਕਾਮ ਹੁੰਦਾ ।",
  "94": "ਇੰਦਰੀਆਂ ਜੀਹਦੀਆਂ ਸੀਤਲ ਤੇ ਸ਼ਾਂਤ ਹੋਈਆਂ. ਘੋੜੇ ਵੱਸ ਹੈ ਜਿਵੇਂ ਰਥਵਾਨ ਕਰਦਾ । ਹੋਵੇ ਜੋ ਨਾ 'ਪਾਪਾਂ ਦੇ ਸੰਗ ਭਰਿਆ', ਹਉਮੈਂ ਮਾਰਦਾ ਨਹੀਂ ਅਭਿਮਾਨ ਕਰਦਾ । ਪਦਵੀ ਓਸਦੀ ਮਹਾਂ ਸਨਮਾਨ ਵਾਲੀ, ਅਰਸ਼ਾਂ ਵਿਚ ਹੈ ਚਮਕਦਾ ਨਾਮ ਓਹਦਾ । ਰਹਿੰਦੇ ਦੇਵਤੇ ਵੀ ਸਦਾ ਲੋਚਦੇ ਨੇ, ਪਾਉਣ ਲਈ ਬੁਲੰਦ ਮੁਕਾਮ ਓਹਦਾ ।",
  "95": "ਜਿਗਰਾ ਧਰਤੀ ਦੇ ਵਾਂਗ ਵਿਸ਼ਾਲ ਕਰ ਕੇ, ਗੁੱਸੇ ਵਿਚ ਜੋ ਕਦੀ ਵੀ ਆਉਂਦਾ ਨਹੀਂ । ਇੰਦਰ-ਥੰਮ ਦੇ ਵਾਂਗ ਅਡੋਲ ਬੱਜਰ, ਆਹਢਾ ਕਿਸੇ ਦੇ ਨਾਲ ਵੀ ਲਾਉਂਦਾ ਨਹੀਂ । ਓਸ ਝੀਲ ਦੇ ਵਾਂਗਰਾਂ ਹੋਏ ਨਿਰਮਲ, ਜੀਹਦੇ ਜਲ ਦੇ ਹੇਠ ਨਾ ਗਾਰ ਪੈਂਦੀ । ਓਸ ਪੁਰਸ਼ ਤੇ ਔਕੜਾਂ ਤੰਗੀਆਂ ਦੀ, ਨਹੀਂ ਵਿਚ ਸੰਸਾਰ ਦੇ ਮਾਰ ਪੈਂਦੀ ।",
  "96": "ਬੰਧਨ ਜੋੜ ਕੇ ਸੱਚੇ ਗਿਆਨ ਦੇ ਨਾਲ, ਪ੍ਰਾਣੀ ਜੋ ਵੀ ਮੁਕਤ ਆਜ਼ਾਦ ਹੋਇਆ । ਜਿਸ ਨੇ ਇਸ ਤਰ੍ਹਾਂ ਠੰਢ ਤਸਕੀਨ ਪਾਈ, ਜੋ ਇਓਂ ਗੰਭੀਰ ਤੇ ਸ਼ਾਦ ਹੋਇਆ । ਓਹਦੇ ਮਨ ਦੇ ਵਿਚ ਟਿਕਾਓ ਆਏ, ਫਿੱਕਾ ਬੋਲ ਓਹ ਕਦੇ ਵੀ ਬੋਲਦਾ ਨਹੀਂ । ਸਗਲੇ ਕਾਜ ਸੁਹੇਲੜੇ ਥੀਂਵਦੇ ਨੇ, ਓਹ ਕਦੇ ਟਿਕਾਣਿਓਂ ਡੋਲਦਾ ਨਹੀਂ ।",
  "97": "ਹੋਵੇ ਅੰਧ ਵਿਸ਼ਵਾਸ ਦਾ ਧਾਰਨੀ ਨਾ, ਸਗਲ-ਮੋਹ ਜ਼ੰਜੀਰੀਆਂ ਤੋੜ ਜਾਏ । ਨਿਕਲ ਗਿਆ ਜੋ ਜਨਮਾਂ ਦੇ ਗੇੜ ਵਿਚੋਂ, ਤ੍ਰਿਸ਼ਨਾ, ਕਾਮਨਾ ਮਨੋਂ ਵਿਛੋੜ ਜਾਏ । ਜਿਹੜਾ ਤੱਤ ਨਿਰਵਾਣ ਦੀ ਸਾਰ ਸਮਝੇ, ਪੱਲੇ ਸੂਝ ਤੇ ਸੱਤ-ਗਿਆਨ ਹੁੰਦਾ । ਉੱਤਮ ਜਾਣੀਏ ਪੁਰਸ਼ ਓਹ ਜੱਗ ਅੰਦਰ, ਸੋਈ ਸਦਾ ਮਹਾਨ ਮਹਾਨ ਹੁੰਦਾ ।",
  "98": "ਭਾਵੇਂ ਨਗਰ ਜਾਂ ਕੋਈ ਗਰਾਂ ਹੋਵੇ, ਜੰਗਲ ਘਣਾ ਜਾਂ ਕੋਈ ਉਜਾੜ ਹੋਵੇ । ਮਾਰੂ ਥਲ ਤੇ ਰੇਤਲਾ ਹੋਏ ਟਿੱਬਾ, ਗੁਫਾ ਹੇਠ ਜਾਂ ਕਿਸੇ ਪਹਾੜ ਹੋਵੇ । ਕੋਈ ਥਾਂ ਹੋਵੇ, ਭਾਵੇਂ ਕਿਤੇ ਹੋਵੇ, ਹੋਵੇ ਦੂਰ ਹੋਵੇ, ਭਾਵੇਂ ਪਾਸ ਹੋਵੇ । ਓਹੀ ਧਰਤ ਸੁਹਾਵਣੀ ਹੋ ਜਾਂਦੀ, ਸੰਤਾਂ ਸਾਧੂਆਂ ਦਾ ਜਿੱਥੇ ਵਾਸ ਹੋਵੇ ।",
  "99": "ਜਿਨ੍ਹਾਂ ਵਣਾਂ ਅੰਦਰ ਜਾ ਕੇ ਆਮ ਲੋਕੀਂ, ਖ਼ੁਸ਼ੀਆਂ ਅਤੇ ਆਨੰਦ ਨਹੀਂ ਮਾਣ ਸਕਦੇ । ਹੁੰਦੀ ਵਣਾਂ ਦੀ ਕਿੰਨੀ ਇਕਾਂਤ ਸੋਹਣੀ, ਕਾਮੀ ਪੁਰਸ਼ ਨਾ ਕਦੇ ਵੀ ਜਾਣ ਸਕਦੇ । ਜਿਨ੍ਹਾਂ ਮਾਰਿਆ ਕਾਮ ਦੀ ਵਾਸ਼ਨਾ ਨੂੰ, ਜੋ ਭੋਗ ਬਿਲਾਸ ਤੋਂ ਦੂਰ ਰਹਿੰਦੇ । ਖ਼ੁਸ਼ੀਆਂ ਖੋਜ ਲੈਂਦੇ ਸੁੰਦਰ ਵਣਾਂ ਅੰਦਰ, ਸਦਾ ਮਨ ਆਨੰਦ ਮਖ਼ਮੂਰ ਰਹਿੰਦੇ ।",
  "chap8": "ਸਹੱਸ",
  "100": "ਬਿਨਾਂ ਅਰਥਾਂ ਦੇ ਜੋੜ ਕੇ ਵਾਕ-ਛਲੀਆਂ, ਇਕ ਥਾਂ ਤੇ ਬਾਝ ਤਾਸੀਰ ਕਰੀਏ । ਇਓਂ ਭਾਲ ਕੇ ਸੱਖਣੇ ਸ਼ਬਦ ਲੱਖਾਂ, ਭਾਵੇਂ ਕਈ ਹਜ਼ਾਰ ਤਕਰੀਰ ਕਰੀਏ । ਓਹ ਸਾਰੀਆਂ ਥੋਥੀਆਂ ਹੁੰਦੀਆਂ ਨੇ, ਨਹੀਂ ਓਹਨਾਂ ਦੇ ਹੇਠ ਜ਼ਮੀਨ ਹੁੰਦੀ । ਓਹਨਾਂ ਨਾਲੋਂ ਸੁਅਰਥ ਇੱਕ ਸ਼ਬਦ ਚੰਗਾ, ਜਿਸ ਨੂੰ ਸੁਣਦਿਆਂ ਦਿਲੀ ਤਸਕੀਨ ਹੁੰਦੀ ।",
  "101": "ਅਰਥੋਂ ਸੱਖਣੇ ਸ਼ਬਦਾਂ ਦੇ ਨਾਲ ਗੁੰਦੇ, ਲੱਖਾਂ ਸੋਹਣੀਆਂ ਤੁਕਾਂ ਦੇ ਹਾਰ ਹੋਵਣ । ਫੇਰ ਜੋੜ ਕੇ ਓਹਨਾਂ ਨੂੰ ਨਾਲ ਵਿਧੀਆਂ, ਰਚੇ ਮਹਿਮਾਂ ਦੇ ਗੀਤ ਹਜ਼ਾਰ ਹੋਵਣ । ਓਹਨਾਂ ਸਾਰਿਆਂ ਤੋਂ ਇਕੋ ਗੀਤ ਚੰਗਾ, ਓਹਦੀ ਉਸਤਤੀ ਅਸਲ ਪਰਬੀਨ ਹੋਵੇ । ਜਿਸ ਦਾ ਇਕ ਵੀ ਸ਼ਬਦ (ਸੁਅਰਥ) ਐਸਾ, ਜਿਸ ਨੂੰ ਸੁਣਦਿਆਂ ਦਿਲੀ ਤਸਕੀਨ ਹੋਵੇ ।",
  "102": "ਅਰਥੋਂ ਸੱਖਣੇ ਸ਼ਬਦਾਂ ਦੇ ਨਾਲ ਬੀੜੇ, ਸੁਰਾਂ ਮਿੱਠੀਆਂ ਨਾਲ ਸਜਾਏ ਕੋਈ । ਇਓਂ ਜੋੜ ਕੇ ਗੀਤ ਹਜ਼ਾਰ ਭਾਵੇਂ, ਸੋਹਲੇ ਉਪਮਾਂ ਦੇ ਝੂਮ ਕੇ ਗਾਏ ਕੋਈ । ਓਹਨਾਂ ਨਾਲੋਂ ਪਰ ਇੱਕੋ ਹੀ ਗੀਤ ਚੰਗਾ, ਜਿਸ ਦੀ ਉਪਮਾ ਦੇ ਹੇਠ ਜ਼ਮੀਨ ਹੋਵੇ । ਇੱਕੋ ਸ਼ਬਦ ਜਿਸਦਾ ਅਰਥਾਂ ਨਾਲ ਭਰਿਆ, ਜਿਸ ਨੂੰ ਸੁਣਦਿਆਂ ਸਾਰ ਤਸਕੀਨ ਹੋਵੇ ।",
  "103": "ਕੋਈ ਸੂਰਮਾ ਜੰਗ ਮੈਦਾਨ ਤੱਤੇ, ਜਾ ਕੇ ਤੇਗ਼ ਦੀ ਲੱਖ ਲਿਸ਼ਕਾਰ ਪਾਏ । ਫਿਰੇ ਗੱਜਦਾ ਵੈਰੀ ਦੇ ਦਲਾਂ ਅੰਦਰ, ਲੜਦਾ, ਮਾਰਦਾ ਜਿੱਤ ਹਜ਼ਾਰ ਪਾਏ । ਬਿਲਾ-ਸ਼ੱਕ ਓਹ ਤੇਗ਼ ਦਾ ਧਨੀ ਹੁੰਦਾ, ਮਾਲਕ ਜਾਣੀਏ ਮਹਾਂ ਬਲਕਾਰ ਦਾ ਏ । ਓਸ ਤੋਂ ਚੜ੍ਹਕੇ ਪਰ ਹੁੰਦਾ ਹੈ, ਸ਼ੂਰਮਾ ਓਹ, ਜਿਹੜਾ ਅਪਣੀ ਹਓਮੈ ਨੂੰ ਮਾਰਦਾ ਏ ।",
  "104": "ਜਿਸਨੇ ਆਪਣੇ ਆਪ ਨੂੰ ਜਿੱਤਿਆ ਹੈ, ਕੋਈ ਸੂਰਮਾ ਓਸਦੇ ਨਾਲ ਦਾ ਨਹੀਂ । ਓਸ ਦਿਗ-ਵਿਜਈ ਦੇ ਵਾਂਗ ਕੋਈ, ਵਿਚ ਜ਼ਿੰਦਗੀ ਦੇ ਸੰਜਮ ਪਾਲਦਾ ਨਹੀਂ ।",
  "105": "ਮਹਾਂਬਲੀ ਵਰਿਆਮ ਅਜਿੱਤ ਯੋਧਾ, ਕੋਈ ਓਸਦੇ ਤੁੱਲ ਨਹੀਂ ਹੋ ਸਕਦਾ । ਕਾਮਦੇਵ ਤੇ ਗਣ ਗੰਧਰਬ ਬ੍ਰਹਮਾ, ਮਾਰੀ ਓਸਦੀ ਮੱਲ ਨਹੀਂ ਖੋਹ ਸਕਦਾ ।",
  "106": "ਕੋਈ ਹਰ ਮਹੀਨੇ ਹੀ ਬਿਲਾ ਨਾਗਾ, ਰਹੇ ਸੈਂਕੜੇ ਵਰ੍ਹੇ ਜੇ ਦਾਨ ਕਰਦਾ । ਕਰੇ ਭੇਂਟ ਓਹ ਇੱਕ ਹਜ਼ਾਰ ਦਮੜਾ, ਨਿੱਜ ਇਸ਼ਟ ਦਾ ਮਾਨ ਸਨਮਾਨ ਕਰਦਾ । ਏਸ ਘਾਲਣਾ ਤੋਂ ਬਾਹਲਾ ਫਲ ਮਿਲਦਾ, ਇੱਕ ਛਿਨ ਜੇ ਓਹ ਧਿਆਨ ਧਰ ਕੇ । ਸ਼ੁੱਧ ਚਿੱਤ ਵਾਲੇ ਕਿਸੇ ਆਦਮੀ ਦਾ, ਵੇਖ ਲਏ ਜੇ ਮਾਨ ਸਨਮਾਨ ਕਰ ਕੇ ।",
  "107": "ਕੋਈ ਆਦਮੀ ਜੰਗਲਾਂ ਵਿਚ ਜਾ ਕੇ, ਧੰਦੇ ਅਤੇ ਸੰਸਾਰ ਵਸਾਰ ਦੇਵੇ । ਸਾਲ ਸੈਂਕੜੇ ਨੇਮ ਦੇ ਨਾਲ ਓਥੇ, ਅਗਨੀ ਪੂਜਾ ਦੇ ਵਿਚ ਗੁਜ਼ਾਰ ਦੇਵੇ । ਕਰਕੇ ਘੋਰ ਤਪੱਸਿਆ ਘਾਲ ਭਾਰੀ, ਆਸ ਰੱਖਦਾ ਫਲ ਵਰਦਾਨ ਦੀ ਓਹ । ਉਸ ਤੋਂ ਫਲ ਬਾਹਲਾ ਇੱਕ ਛਿਨ ਜੇਕਰ, ਪੂਜਾ ਕਰੇ ਜੇ ਨੇਕ ਇਨਸਾਨ ਦੀ ਓਹ ।",
  "108": "ਪੁੰਨ ਖੱਟਣਾ ਧਾਰ ਕੇ ਚਿੱਤ ਅੰਦਰ, ਕੋਈ ਆਪਣਾ ਨੇਮ ਸੁਲੱਗ ਕਰ ਲਏ । ਪੂਰਾ ਸਾਲ ਸਾਰਾ ਦਿਲ ਖੋਲ੍ਹ ਕੇ ਤੇ, ਕਰੇ ਹਵਨ ਤੇ ਸੈਂਕੜੇ ਯੱਗ ਕਰ ਲਏ । ਫਲ ਘਾਲ ਦਾ ਇੱਕ ਚੁਥਾਈ ਕੇਵਲ, ਓਸ ਫਲ ਦੇ ਕਦੇ ਨਹੀਂ ਤੁੱਲ ਹੁੰਦਾ । ਨੇਕ-ਦਿਲ ਨੂੰ ਭੇਂਟ ਸ਼ਰਧਾਂਜਲੀ ਦਾ, ਜਿਹੜਾ ਜੱਗ ਜਹਾਨ ਤੇ ਮੁੱਲ ਹੁੰਦਾ ।",
  "109": "ਕਰਦਾ ਰਹੇ ਨਿਰੰਤਰ ਜੋ ਅਭੀਵਾਦਨ, ਕੋਈ ਉਲਟੀ ਨਾ ਕਦੇ ਵੀ ਕਾਰ ਕਰਦਾ । ਸਦਾ ਬੁੱਢਿਆਂ, ਠੇਰਿਆਂ ਵੱਡਿਆਂ ਦਾ, ਪੂਰਾ ਮਾਨ ਸਨਮਾਨ ਸਤਕਾਰ ਕਰਦਾ । ਚਾਰ ਖੂਬੀਆਂ, ਗੁਣਾਂ ਵਿਚ ਹੋਏ ਵਾਧਾ, ਉਸ ਨੂੰ ਵਾਧਾ ਇਹ ਸਦਾ ਅਟੱਲ ਮਿਲਦਾ । ਰੂਪ, ਰੰਗ, ਸੋਹਣਾ, ਓਹਦੀ ਉਮਰ ਲੰਮੀ, ਜੀਵਣ-ਸੁਖ ਤੇ ਨਾਲ ਹੀ ਬਲ ਮਿਲਦਾ ।",
  "110": "ਦੁਰਾਚਾਰ ਦੇ ਵਿਚ ਬਦਮਸਤ ਰਹਿ ਕੇ, ਜੀਵੇ ਸੈਂਕੜੇ ਸਾਲ ਜੇ ਦੁਰਾਚਾਰੀ । ਕਾਬੂ ਆਪਣੇ ਆਪ ਤੇ ਨਾ ਰੱਖੇ, ਉਮਰ ਐਸ਼ ਦੇ ਵਿਚ ਲੰਘਾਏ ਸਾਰੀ । ਓਹਦੇ ਟਾਕਰੇ ਜ਼ਿੰਦਗੀ ਇੱਕ ਦਿਨ ਦੀ, ਪੁਰਸ਼ ਓਹ ਸੁਲੱਖਣੀ ਮਾਣਦਾ ਹੈ । ਸੀਲ ਸੰਜਮੀ ਤੇ ਧਿਆਨ-ਮਗਨ ਜਿਹੜਾ, ਠੀਕ ਆਪਣਾ ਮੂਲ ਪਛਾਣਦਾ ਹੈ ।",
  "111": "ਬਿਨਾਂ ਆਪਣੇ ਆਪ ਨੂੰ ਵੱਸ ਕੀਤੇ, ਕਰਕੇ ਰੱਜਵੇਂ ਕੂੜ ਪਸਾਰ ਜਾਏ । ਕੋਈ ਮੂਰਖਾਂ ਵਾਂਗ ਗਿਆਨ ਬਾਝੋਂ, ਉਮਰ ਸੈਂਕੜੇ ਸਾਲ ਗੁਜ਼ਾਰ ਜਾਏ । ਏਨੀ ਉਮਰ ਦੇ ਟਾਕਰੇ ਗੱਲ ਪੱਕੀ, ਇਕ ਦਿਨ ਦੀ ਜ਼ਿੰਦਗੀ ਓਹ ਭਾਰੀ । ਜਿਹੜੀ ਗਿਆਨ ਧਿਆਨ ਦੇ ਵਿਚ ਗੁਜ਼ਰੇ, ਹੋਏ ਅੰਦਰੋਂ ਹਊਮੈ ਦੀ ਅੰਸ਼ ਮਾਰੀ ।",
  "112": "ਕੋਈ ਆਲਸੀ, ਉੱਦਮ ਤੋਂ ਸੱਖਣਾ ਜੋ, ਭਾਵੇਂ ਉਮਰ ਓਹਦੀ ਦੋ ਸੌ ਸਾਲ ਹੋਵੇ । ਓਹਦੇ ਜੀਣ ਦਾ ਕੋਈ ਨਾ ਹੱਜ ਹੁੰਦਾ, ਓਹ ਅਸਲੋਂ ਹੀ ਮਾਤਾ ਦਾ ਮਾਲ ਹੋਵੇ । ਓਹਦੇ ਨਾਲੋਂ ਤਾਂ ਉੱਦਮੀ ਉਹ ਉੱਤਮ, ਉੱਦਮ ਸੁੱਚਾ ਸੁਚੇਤ ਜੋ ਕਰ ਜਾਏ । ਇਕੋ ਦਿਨ ਦੀ ਭੋਗ ਕੇ ਜ਼ਿੰਦਗਾਨੀ, ਭਾਵੇਂ ਤੁਰਦਿਆਂ ਫਿਰਦਿਆਂ ਮਰ ਜਾਏ ।",
  "113": "ਸੰਸਕਾਰਾਂ ਤੇ ਸੰਗਿਆ, ਵੇਦਨਾ ਦੀ, ਤੱਤ, ਰੂਪ, ਵਿਗਿਆਨ ਦੀ ਸਾਰ ਸਮਝੇ । ਇਹਨਾਂ ਤੱਤਾਂ ਨੇ ਉਭਰਨਾ ਨਾਸ਼ ਹੋਣਾ, ਉਮਰ ਘੜੀ ਦੀ ਵਿਚ ਇਸਰਾਰ ਸਮਝੇ । ਓਹ ਓਸ ਪਰਾਣੀ ਤੋਂ ਬੜਾ ਉੱਤਮ, ਸੌ ਸਾਲ ਜੋ ਉਮਰ ਗੁਜ਼ਾਰਦਾ ਏ । ਪੰਜ ਤੱਤ ਦਾ ਵਿਗਸਣਾ ਨਾ ਵੇਖੇ, ਨਾ ਹੀ ਝਾਤੀ ਵਿਨਾਸ਼ ਤੇ ਮਾਰਦਾ ਏ ।",
  "114": "ਉਮਰ ਸੈਂਕੜੇ ਸਾਲ ਦੀ ਕੋਈ ਲੰਮੀ, ਆਲਸ ਗ਼ਾਫ਼ਲੀ ਵਿਚ ਗੁਜ਼ਾਰ ਜਾਏ । ਜਿਹੜਾ ਰਾਹ ਨਿਰਵਾਣ ਦਾ ਭਾਲਦਾ ਨਹੀਂ, ਐਵੇਂ ਫੋਕੀਆਂ ਟੱਕਰਾਂ ਮਾਰ ਜਾਏ । ਓਸ ਨਾਲੋਂ ਤਾਂ ਜ਼ਿੰਦਗੀ ਇੱਕ ਦਿਨ ਦੀ, ਉੱਤਮ ਅਤੇ ਸੁਲੱਖਣੀ ਮਾਣਦਾ ਏ । ਜਿਹੜਾ ਪੁਰਸ਼, ਸੁਚੇਤ ਸੁਲਗਨ ਹੋ ਕੇ, ਰਹਿੰਦਾ ਭਾਲਦਾ ਰਾਹ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "115": "ਉਮਰ ਸੈਂਕੜੇ ਸਾਲ ਦੀ ਕੋਈ ਭੋਗੇ, ਜੇਕਰ ਧਰਮ ਦੀ ਸਾਰ ਨੂੰ ਜਾਣਦਾ ਨਹੀਂ । ਓਹ ਕੱਟਦਾ ਪਿਆ ਹੈ ਜੂਨ ਐਵੇਂ, ਓਹ ਅਸਲ ਵਿਚ ਜ਼ਿੰਦਗੀ ਮਾਣਦਾ ਨਹੀਂ । ਓਹਦੇ ਨਾਲੋਂ ਤਾਂ ਉੱਦਮੀ ਉਹ ਉੱਤਮ, ਹਰ ਥਾਂ ਤੇ ਸਮੇਂ ਸਤਕਾਰ ਪਾਏ । ਭਾਵੇਂ ਉਮਰ ਹੋਵੇ ਉਹਦੀ ਇੱਕ ਦਿਨ ਦੀ, ਪਰ ਓਹ ਧਰਮ ਸ੍ਰੇਸ਼ਟ ਦੀ ਸਾਰ ਪਾਏ ।",
  "chap9": "ਪਾਪ",
  "116": "ਪੁੰਨ ਕਰਦਿਆਂ ਰਤਾ ਨਾ ਢਿੱਲ ਕਰੀਏ, ਚਿੱਤ ਨੇਕੀਓਂ ਕਦੇ ਨਾ ਮੋੜਨਾ ਜੇ । ਜੇਕਰ ਲੋਚਦਾ ਮਨ ਬੁਰਿਆਈਆਂ ਨੂੰ, ਸਦਾ ਓਸ ਨੂੰ ਹਟਕਣਾ ਹੋੜਨਾ ਜੇ । ਨੇਕੀ ਕਰਦਿਆਂ ਆਲਸੀ ਕਰੇ ਜਿਹੜਾ, ਓਹ ਅਸਲ ਵਿਚ ਪੁੱਜ ਖਵਾਰ ਹੁੰਦਾ । ਕੀਤੀ ਕੱਤਰੀ ਓਸ ਦੀ ਖੂਹ ਪੈ ਜਾਏ, ਓਹਦੇ ਮਨ ਤੇ ਪਾਪ ਸਵਾਰ ਹੁੰਦਾ ।",
  "117": "ਉਸ ਨੂੰ ਝੱਟ ਆਰੰਭ ਵਿਚ ਰੋਕ ਦਈਏ, ਮੰਦੇ ਕੰਮ ਵਿਚ ਪੈਰ ਜੇ ਧਰੇ ਕੋਈ । ਫੇਰ ਟੋਕੀਏ, ਡੱਕੀਏ ਅਗ੍ਹਾਂ ਹੋ ਕੇ, ਵਾਰ ਵਾਰ ਗੁਨਾਹ ਜੇ ਕਰੇ ਕੋਈ । ਕਦੇ ਹੱਥ ਨਾ ਪਾਪਾਂ ਦੇ ਨਾਲ ਭਰੀਏ, ਇਹ ਜੀਣ ਦਾ ਸੋਨ-ਅਸੂਲ ਹੁੰਦਾ । ਕਦੇ ਸੰਚੀਏ ਪਾਪਾਂ ਨੂੰ ਭੁੱਲ ਕੇ ਨਾ, ਢੇਰ ਪਾਪਾਂ ਦਾ ਦੁੱਖਾਂ ਦਾ ਮੂਲ ਹੁੰਦਾ ।",
  "118": "ਕੋਈ ਆਦਮੀ ਪੁੰਨ ਜਾਂ ਕਰੇ ਨੇਕੀ, ਸਦਾ ਹੁੰਦੀਆਂ ਓਹਦੀਆਂ ਪੌਂ ਬਾਰਾਂ । ਸ਼ਾਲਾ ! ਨੇਕੀ ਦੀ ਕਾਰ ਕਮਾਈ ਜਾਵੇ, ਕਰੇ ਪੁੰਨ ਓਹ ਲੱਖ ਹਜ਼ਾਰ ਵਾਰਾਂ । ਸੁਰਤ ਸਦਾ ਓਹ ਨੇਕੀਆਂ ਨਾਲ ਜੋੜੇ, ਪੈਦਾ ਓਸ ਤੋਂ ਸਦਾ ਉਤਸ਼ਾਹ ਹੁੰਦਾ । ਪੁੰਨ, ਨੇਕੀਆਂ ਸੰਚਿਆਂ ਵਿਚ ਦੁਨੀਆਂ, ਖ਼ੁਸ਼ੀਆਂ ਬਹੁਤ, ਅਨੰਤ ਉਮਾਹ ਹੁੰਦਾ ।",
  "119": "ਪਾਪ ਕਰਦਿਆਂ ਸਮਝਦਾ ਨਹੀਂ ਪਾਪੀ, ਪੈਰ ਪੈਰ ਉੱਤੇ ਧੋਖਾ ਖਾਈ ਜਾਏ । ਜਦੋਂ ਤੀਕ ਨਾ ਪਾਪ ਦਾ ਫਲ ਮਿਲਦਾ, ਪੁੰਨ ਸਮਝ ਕੇ ਪਾਪ ਕਮਾਈ ਜਾਏ । ਲੱਗੇ ਪਾਪ ਨੂੰ ਆਣ ਜਦ ਫਲ ਕੌੜਾ, ਫੇਰ ਗੱਲ ਓਹ ਆਪਣੇ ਆਪ ਸਮਝੇ । ਪਾਪ ਨਜ਼ਰ ਆਏ ਉਸ ਨੂੰ ਚੌਂਹ ਪਾਸੀਂ, ਮੁੜਕੇ ਸਦਾ ਹੀ ਪਾਪ ਨੂੰ ਪਾਪ ਸਮਝੇ ।",
  "120": "ਜਦੋਂ ਤੀਕ ਨਾ ਪੁੰਨ ਦਾ ਫਲ ਮਿਲਦਾ, ਪੁੰਨ ਕਰਨ ਵਾਲਾ ਹਿੰਮਤ ਹਾਰ ਜਾਏ । ਸਮਝਣ ਲੱਗ ਪਏ ਪੁੰਨ ਨੂੰ ਪਾਪ ਭਾਰੀ, ਨਜ਼ਰੇ ਆਪਣੀ ਹੋ ਬੁਰਿਆਰ ਜਾਏ । ਮਿੱਠਾ ਫਲ ਜਦ ਪੁੰਨ ਨੂੰ ਆਣ ਲੱਗੇ, ਓਹ ਪੁੰਨ ਦੀ ਸਾਰ ਸਿਆਣਦਾ ਹੈ । ਨਜ਼ਰ ਪੁੰਨ ਦਾ ਅਸਲ ਸਰੂਪ ਆਏ, ਮਿੱਠਾ ਫਲ ਵੀ ਓਸਦਾ ਮਾਣਦਾ ਹੈ ।",
  "121": "ਮਤਾਂ ਏਸ ਭੁਲੇਖੇ ਵਿਚ ਰਹੇ ਕੋਈ, ਮੇਰੇ ਨੇੜੇ ਤਾਂ ਪਾਪ ਨੇ ਢੁੱਕਣਾ ਨਹੀਂ । ਕਿਉਂਕਿ ਪਾਪ ਦੀ ਰਗ ਹੀ ਵੱਖਰੀ ਏ, ਉਹਨੇ ਆਉਣ ਤੋਂ ਕਦੇ ਵੀ ਚੁੱਕਣਾ ਨਹੀਂ । ਤੁਪਕਾ ਤੁਪਕਾ ਜੇ ਪਾਣੀ ਦਾ ਸਿੰਮਦਾ ਰਹੇ, ਮੂੰਹੋਂ ਮੂੰਹ ਉਹ ਘੜੇ ਨੂੰ ਭਰ ਦਿੰਦਾ । ਉਸੇ ਤਰ੍ਹਾਂ ਪਾਪੀ ਥੋੜ੍ਹਾ ਥੋੜ੍ਹਾ ਕਰਕੇ, ਪਾਪ ਪਰਬਤਾਂ ਜੇਡ ਹੈ ਕਰ ਦਿੰਦਾ ।",
  "122": "ਇਓਂ ਸੋਚਣਾ ਬੜਾ ਨਿਰਮੂਲ ਹੁੰਦਾ, 'ਪੁੰਨ ਕਦੇ ਵੀ ਮੇਰੇ ਨਹੀਂ ਪਾਸ ਆਉਣਾ' । ਬੂੰਦ, ਬੂੰਦ ਕਰਕੇ ਘੜਾ ਜਿਵੇਂ ਭਰਦਾ, ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਪੁੰਨ ਨੇ ਰਾਸ ਆਉਣਾ । ਇਹੀ ਹੁੰਦਾ ਹੈ ਸ਼ਰਫ਼ ਸਿਆਣਿਆਂ ਨੂੰ, ਥੋੜ੍ਹਾ ਥੋੜ੍ਹਾ ਓਹ ਪੁੰਨ ਕਮਾਉਂਦੇ ਨੇ । ਕਰ ਲੈਣ ਪਰ ਥੋੜ੍ਹਿਓਂ ਬਹੁਤ ਬਹੁਤਾ, ਉਚੇ ਪੁੰਨ ਦੇ ਢੇਰ ਓਹ ਲਾਉਂਦੇ ਨੇ ।",
  "123": "ਨਾਲ ਹੋਰਨਾਂ ਦੇ ਛੋਟੇ ਕਾਫ਼ਲੇ ਵਿਚ, ਤੁਰਿਆ ਕੋਈ ਤਾਜਰ ਧਨੀ, ਸ਼ਾਹ ਜਾਏ । ਓਹ ਤਾੜ ਕੇ ਸਾਥ ਨਖੇੜ ਲੈਂਦਾ, ਖਤਰੇ ਵਾਲੇ ਨਾ ਕਦੇ ਵੀ ਰਾਹ ਜਾਏ । ਕੋਈ ਜੀਉੜਾ ਜ਼ਿੰਦਗੀ ਚਾਹੁਣ ਵਾਲਾ, ਅੱਖੀਂ ਵੇਖ ਕੇ ਜ਼ਹਿਰ ਨਾ ਕਦੇ ਖਾਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਚਾਹੀਦਾ ਆਦਮੀ ਨੂੰ, ਨੇੜੇ ਕਦੇ ਗੁਨਾਹਾਂ ਦੇ ਨਾ ਜਾਏ ।",
  "124": "ਲੱਗਾ ਜ਼ਖ਼ਮ ਝਰੀਟ ਜੇ ਨਾ ਹੋਵੇ, ਕੋਈ ਜ਼ਹਿਰ ਵੀ ਹੱਥਾਂ ਵਿਚ ਰਹੇ ਫੜਦਾ । ਓਹਦਾ ਅਸਰ ਨਾ ਰਤਾ ਰਵਾਲ ਹੋਵੇ, ਜ਼ਖ਼ਮ ਬਾਝ ਨਾ ਜ਼ਹਿਰ ਹੈ ਕਦੇ ਚੜ੍ਹਦਾ । ਓਸੇ ਤਰ੍ਹਾਂ ਜੇ ਰਮਜ਼ ਪਛਾਣ ਲਈਏ, ਫੇਰ ਕਦੇ ਨਾ ਦੁੱਖ ਸੰਤਾਪ ਲੱਗੇ । ਮੰਦਾ ਕੰਮ ਜੋ ਭੁੱਲ ਕੇ ਨਹੀਂ ਕਰਦਾ, ਨੇੜੇ ਓਸ ਦੇ ਕਦੇ ਨਾ ਪਾਪ ਲੱਗੇ ।",
  "125": "ਜਿਹੜਾ ਕਿਸੇ ਨਿਰਦੋਸ਼ ਤੇ ਦੋਸ਼ ਲਾਵੇ, ਪਾਕ ਸਾਫ਼ ਨੂੰ ਵੀ ਗੁਨ੍ਹਾਗਾਰ ਦੱਸੇ । ਨਿਰਮਲ ਆਦਮੀ ਤੇ ਲਾਏ ਸੌ ਊਜਾਂ, ਬੋਲ, ਬੋਲ ਕੁਬੋਲ ਹਜ਼ਾਰ ਦੱਸੇ । ਊਜ ਲਾਉਣ ਵਾਲੇ ਐਸੇ ਮੂਰਖਾਂ ਤੇ, ਉਲਟੀ ਪਾਪਾਂ ਦੀ ਇਸ ਤਰ੍ਹਾਂ ਮਾਰ ਪੈਂਦੀ । ਮਿੱਟੀ ਸਾਹਮਣੀ ਹਵਾ ਤੇ ਕੋਈ ਸੁੱਟੇ, ਜਿਵੇਂ ਉਡਕੇ ਓਸ ਤੇ ਛਾਰ ਪੈਂਦੀ ।",
  "126": "ਗਰਭ ਜੂਨ ਵਿਚ ਕਈਆਂ ਨੂੰ ਪਏ ਜਾਣਾ, ਨਰਕੀਂ ਸੜਦੇ ਨੇ ਪਾਪ ਕਮਾਉਣ ਵਾਲੇ । ਕਰਨ ਜਾ ਬਹਿਸ਼ਤਾਂ ਦੇ ਵਿਚ ਮੌਜਾਂ, ਜੀਵਣ ਨੇਕੀਆਂ ਦੇ ਲੇਖੇ ਲਾਉਣ ਵਾਲੇ । ਗੱਲ ਸੌ ਦੀ ਇੱਕ ਇਉਂ ਮੁਕਦੀ ਏ, ਪੱਲੇ ਪਾਪਾਂ ਤੋਂ ਜੋ ਬਚਾਉਣ ਵਾਲੇ । ਸਫਲ ਆਪਣੀ ਘਾਲ ਕਮਾਈ ਕਰਕੇ, ਹੁੰਦੇ ਪਦ ਨਿਰਬਾਣ ਨੂੰ ਪਾਉਣ ਵਾਲੇ ।",
  "127": "ਚੜ੍ਹਕੇ ਕੋਈ ਅਸਮਾਨ ਤੇ ਬੈਠ ਜਾਏ, ਆਸਣ ਲਾਏ ਜਾਂ ਸਾਗਰਾਂ ਖਾਰਿਆਂ ਵਿਚ । ਭਾਵੇਂ ਕਿਸੇ ਪਹਾੜ ਦੀ ਖੋਹ ਅੰਦਰ, ਜਾਵੇ ਛੁਪ ਉਹ ਗੁਫ਼ਾ ਦੇ ਹਾਰਿਆਂ ਵਿਚ । ਮਿਲੇ ਫੇਰ ਨਾ ਓਸ ਨੂੰ ਢੋਈ ਕਿਧਰੇ, ਭਾਵੇਂ ਸਭ ਸੰਸਾਰ ਵਿਚ ਭਾਲ ਵੇਖੇ । ਕਿਸੇ ਥਾਂ ਨਾ ਪਾਪਾਂ ਦਾ ਫਲ ਟਲਦਾ, ਲੱਖ ਆਦਮੀ ਓਸ ਨੂੰ ਟਾਲ ਵੇਖੇ ।",
  "128": "ਟੀਸੀ ਅੱਧ ਅਸਮਾਨ ਦੀ ਚੜ੍ਹੇ ਕੋਈ, ਚੁੱਭੀ ਲਾਏ ਜਾਂ ਸਾਗਰਾਂ ਖਾਰਿਆਂ ਵਿਚ । ਭਾਵੇਂ ਖੋਹ ਪਹਾੜ ਦੀ ਜਾ ਮੱਲੇ, ਲੁਕ ਜਾਵੇ ਜਾਂ ਗੁਫ਼ਾ ਦੇ ਹਾਰਿਆਂ ਵਿਚ । ਮਿਲੇ ਫੇਰ ਵੀ ਢੋਈ ਨਾ ਕਿਤੇ ਓਹਨੂੰ, ਭਾਵੇਂ ਸਭ ਸੰਸਾਰ ਵਿਚ ਭਾਲ ਵੇਖੇ । ਕਿਸੇ ਥਾਂ ਵੀ ਟਾਲਿਆਂ ਨਹੀਂ ਟਲਦੀ, ਲੱਖ ਆਦਮੀ ਮੌਤ ਨੂੰ ਟਾਲ ਵੇਖੇ ।",
  "chap10": "ਦੰਡ",
  "129": "ਡੰਡੇ, ਮੌਤ ਕੋਲੋਂ ਡਰਦਾ ਹਰ ਕੋਈ, ਭਿਖਸ਼ੂ, ਤੱਤ ਨੂੰ ਇਓਂ ਵਿਚਾਰਦਾ ਈ । ਵਰਗੇ ਆਪਣੇ ਸਮਝ ਕੇ ਸਾਰਿਆਂ ਨੂੰ, ਮਾਰਨ ਦਏ ਨਾ ਕਿਸੇ ਨੂੰ ਮਾਰਦਾ ਈ ।",
  "130": "ਡਰਦਾ ਡੰਡੇ ਦੀ ਮਾਰ ਤੋਂ ਹਰ ਕੋਈ, ਨਾਲੇ ਜ਼ਿੰਦਗੀ ਤਾਈਂ ਪਿਆਰਦਾ ਈ । ਭਿਖਸ਼ੂ, ਸਮਝ ਸਮਾਨ ਪਰਾਣੀਆਂ ਨੂੰ, ਮਾਰਨ ਦਏ ਨਾ ਕਿਸੇ ਨੂੰ ਮਾਰਦਾ ਈ ।",
  "131": "ਖਾਤਰ ਆਪਣੇ ਸੁੱਖ ਦੇ ਮੂੜ੍ਹ ਕੋਈ, ਸੁੱਖ-ਭਾਲਕਾਂ ਨੂੰ ਡੰਡੇ ਜੇ ਮਾਰੇ । ਮਰਨ ਮਗਰੋਂ ਵੀ ਸੁੱਖ ਨਾ ਮਿਲੇ ਓਹਨੂੰ, ਬੇੜੀ ਡੋਬਦੇ ਓਸਦੀ ਇਹ ਕਾਰੇ ।",
  "132": "ਪਰ ਜੇ ਆਪਣੇ ਸੁੱਖ ਨੂੰ ਚਾਹੁਣ ਵਾਲਾ, ਸੁੱਖ-ਭਾਲਕਾਂ ਤੇ ਡੰਡਾ ਚੁੱਕਦਾ ਨਹੀਂ । ਓਹਨੂੰ ਮਰਨ ਮਗਰੋਂ ਮਿਲਦਾ ਸੁੱਖ ਏਨਾਂ, ਜਿਹੜਾ ਕਦੇ ਨਿਖੁੱਟਦਾ ਮੁੱਕਦਾ ਨਹੀਂ ।",
  "133": "ਅੱਗੋਂ ਫਿੱਕਾ ਜਵਾਬ ਹੈ ਪਰਤ ਆਉਂਦਾ, ਫਿੱਕਾ ਬੋਲ ਜ਼ਬਾਨ ਤੋਂ ਬੋਲੀਏ ਨਾ । ਮਗਰੋਂ ਭੁਗਤਣਾ ਪੈਂਦਾ ਹੈ ਦੰਡ ਕਰੜਾ, ਅੱਤ ਚੁੱਕੀਏ ਤੇ ਕੁਫ਼ਰ ਤੋਲੀਏ ਨਾ ।",
  "134": "ਹੋਵੇ ਕਹੇਂ ਦੇ ਭਾਂਡੇ ਨੂੰ ਤੇੜ ਆਈ, ਓਹਦੇ ਵਾਂਗ ਜੋ ਬੋਲਦਾ ਖੜਕਦਾ ਨਹੀਂ । ਓਹ ਪਦ ਨਿਰਬਾਣ ਨੂੰ ਪਾ ਜਾਏ, ਕੋਈ ਰੇੜਕਾ ਦਿਲੇ ਵਿਚ ਰੜਕਦਾ ਨਹੀਂ ।",
  "135": "ਜਿਵੇਂ ਆਪਣੇ ਵੱਗ ਨੂੰ ਕੋਈ ਵਾਗੀ, ਸੋਟਾ ਮਾਰ ਕੇ ਘਰਾਂ ਨੂੰ ਮੋੜਦਾ ਏ ।",
  "136": "ਓਸੇ ਤਰ੍ਹਾਂ ਯਮਰਾਜ ਪ੍ਰਾਣੀਆਂ ਨੂੰ, ਬੁੱਢੀ ਉਮਰ ਤੋਂ ਆਣ ਵਿਛੋੜਦਾ ਏ । ਪਾਪ ਕਰਦਿਆਂ ਸੋਚਦਾ ਨਹੀਂ ਮੂਰਖ, ਰੀਝ ਪਾਪ ਦੀ ਗੱਲ ਵਗਾੜਦੀ ਏ । ਪਿਛੋਂ ਦੁਖੀ ਇਉਂ ਚਾਂਗਰਾਂ ਪਿਆ ਮਾਰੇ, ਜਿਵੇਂ ਅੱਗ ਸਰੀਰ ਨੂੰ ਸਾੜਦੀ ਏ ।",
  "137": "ਜਿਹੜਾ ਕੋਈ ਨਿਰਦੋਸ਼ ਨਿਹੱਥਿਆਂ ਨੂੰ, ਨਾਲ ਡੰਡੇ ਦੇ ਕੁੱਟਦਾ ਮਾਰਦਾ ਏ । ਓਹਨੂੰ ਆਪਣੀ ਕੀਤੀ ਦਾ ਫਲ ਮਿਲਦਾ, ਪਾਪ ਲੱਗਦਾ ਦਸ ਪਰਕਾਰ ਦਾ ਏ ।",
  "138": "ਲੱਤ-ਬਾਂਹ ਭੱਜੇ, ਤਿੱਖਾ ਸੂਲ ਹੋਵੇ, ਮੋਹਲਕ ਰੋਗ ਦਾ ਹੋ ਸ਼ਿਕਾਰ ਜਾਏ । ਦੁਬਧਾ, ਚਿੰਤਾ ਜਾਂ ਚਿੱਤ ਨੂੰ ਪੀੜਦੀ ਏ, ਜਾਂ ਓਹ ਕਿਸੇ ਮੈਦਾਨ ਵਿਚ ਹਾਰ ਜਾਏ ।",
  "139": "ਮਿਲੇ ਰਾਜ ਦਰਬਾਰ ਤੋਂ ਦੰਡ ਕਰੜਾ, ਓਹਨੂੰ ਫੁੰਡਦਾ ਭੰਡੀ ਪਰਚਾਰ ਹੋਵੇ । ਹੋਏ ਨਾਸ਼ ਜਾਂ ਸਾਕਾਂ ਸਰਬੰਧੀਆਂ ਦਾ, ਜੀਵਣ ਸਾਧਨਾਂ ਤੇ ਗੜੇ ਮਾਰ ਹੋਵੇ ।",
  "140": "ਜਾਂ ਫਿਰ ਓਸਦੇ ਘਰ ਨੂੰ ਅੱਗ ਸਾੜੇ, ਅਕਲ ਮੂੜ੍ਹ ਤੋਂ ਹੋ ਫ਼ਰਾਰ ਜਾਏ । ਓਹ ਜਦੋਂ ਤਿਆਗ ਕੇ ਤੁਰੇ ਕਾਇਆਂ ? ਕੁੰਭੀ ਨਰਕ ਦੇ ਵੱਲ ਸਿਧਾਰ ਜਾਏ ।",
  "141": "ਕੋਈ ਜਟਾਧਾਰੀ ਫਿਰੇ ਸਾਧ ਨਾਂਗਾ, ਰੱਖੇ ਵਰਤ ਭਬੂਤ ਰਮਾਏ ਕੋਈ । ਭਾਵੇਂ ਸਾਰੇ ਸਰੀਰ ਤੇ ਲਿੰਬ ਚਿੱਕੜ, ਗੋਡੇ-ਓਕੜੂ ਚੌਕੜੀ ਲਾਏ ਕੋਈ । ਕਰੜੀ ਭੋਂ ਤੇ ਲੇਟਦਾ ਰਹੇ ਭਾਵੇਂ, ਕਦੇ ਸਫ਼ਲ ਨਾ ਇਉਂ ਕਮਾਈ ਹੁੰਦੀ । ਜਿੰਨਾ ਚਿਰ ਨਾ ਅੰਦਰੋਂ ਭਰਮ ਜਾਏ, ਓਹਦੀ ਸ਼ੁਧੀ ਨਾ ਕੋਈ ਸਫ਼ਾਈ ਹੁੰਦੀ ।",
  "142": "ਬਣਿਆ, ਤਣਿਆ, ਸ਼ਿੰਗਾਰਿਆ ਹੋਏ ਭਾਵੇਂ, ਜੇਕਰ ਸ਼ਾਂਤ ਓਹ ਮਨੋਂ ਹੈ ਬ੍ਰਹਮਚਾਰੀ । ਹਿੰਸਾ ਸਾਰਿਆਂ ਪ੍ਰਤੀ ਤਿਆਗ ਦਿੰਦਾ, ਹਉਮੈ ਅੰਦਰੋਂ ਜਿਸ ਨੇ ਹੋਏ ਮਾਰੀ । ਆਪਾ ਸਾਧਿਆ ਇਸ ਤਰ੍ਹਾਂ ਹੋਏ ਜਿਸ ਨੇ, ਬ੍ਰਹਮਣ ਓਹ ਹੈ ਅਸਲ ਵਿਚ ਜਾਣ ਲਈਏ । ਓਹੀ ਸ਼੍ਰਮਣ ਤੇ ਭਿਖਸ਼ੂ ਦਾ ਰੂਪ ਸਮਝੋ, ਕੋਈ ਦੂਸਰਾ ਨਹੀਂ, ਪਛਾਣ ਲਈਏ ।",
  "143": "ਕਈ ਪੁਰਸ਼ ਸੰਸਾਰ ਵਿਚ ਹੋਣ ਐਸੇ, ਸ਼ਰਮ ਆਪਣੀ ਜਿਨ੍ਹਾਂ ਨੂੰ ਮਾਰਦੀ ਏ । ਏਸੇ ਕਾਰਨ ਹੀ ਪਾਪਾਂ ਤੋਂ ਬਚੇ ਰਹਿੰਦੇ, ਏਹੋ ਝਿਜਕ ਹੀ ਓਹਨਾਂ ਨੂੰ ਤਾਰਦੀ ਏ । ਉਮਦਾ ਨਸਲ ਤੇ ਰਵੇ ਦੇ ਜਿਵੇਂ ਘੋੜੇ, ਛਾਟ, ਛਾਂਟੇ ਦੀ ਜ਼ਰਾ ਸਹਾਰਦੇ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਪੁਰਸ਼ ਸੰਕੋਚ ਵਾਲੇ, ਹੋਵੇ ਨਿੰਦਿਆ ਚਿੱਤ ਚਿਤਾਰਦੇ ਨਹੀਂ ।",
  "144": "ਵਧੀਆ ਨਸਲ ਤੇ ਰਵੇ ਦਾ ਜਿਵੇਂ ਘੋੜਾ, ਛੋਹੇ ਛਾਂਟ ਕਮਾਲ ਦਾ ਹੋ ਜਾਏ । ਲਾਏ ਜ਼ੋਰ ਤੇ ਚਾਲ ਨੂੰ ਕਰੇ ਤਿੱਖਾ, ਬਸ ! ਹਵਾ ਦੇ ਨਾਲ ਦਾ ਹੋ ਜਾਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਚਾਹੀਦਾ ਆਦਮੀ ਦਾ, ਸ਼ੁੱਧ ਕਰਮ ਤੇ ਸੱਚ ਆਚਾਰ ਹੋਵੇ । ਸ਼ਰਧਾ, ਧਰਮ ਦੇ ਵਿਚ ਵਿਸ਼ਵਾਸ ਪੱਕਾ, ਕਰਕੇ ਦੁੱਖਾਂ ਦੇ ਸਾਗਰੋਂ ਪਾਰ ਹੋਵੇ ।",
  "145": "ਪਾਣੀ ਲਾਏ ਕਿਰਸਾਣ ਜੋ ਖੇਤੀਆਂ ਨੂੰ, ਜਿਧਰ ਚਾਹੇ ਓਹ ਪਾਣੀ ਨੂੰ ਮੋੜ ਲੈਂਦਾ । ਜਿਵੇਂ ਚਾਹੁੰਦਾ ਤੀਰ ਬਣਾਉਣ ਵਾਲਾ, ਘੜਦਾ ਤੀਰ ਤੇ ਮੁੱਖੀ ਨੂੰ ਜੋੜ ਲੈਂਦਾ । ਮਨ ਭਾਉਂਦੀ ਤੱਛਦਾ ਲੱਕੜੀ ਨੂੰ, ਤੇਸਾ ਜਦੋਂ ਤਰਖਾਣ ਉਲਾਰਦਾ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਆਦਮੀ ਨੇਕ-ਨੀਅਤ, ਸਦਾ ਆਪਣੇ ਆਪ ਨੂੰ ਮਾਰਦਾ ਏ ।",
  "chap11": "ਜਰਾ",
  "146": "ਹੋਵੇ ਚਾਰ ਚੁਫੇਰ ਨੂੰ ਅੱਗ ਲੱਗੀ, ਫੇਰ ਖ਼ੁਸ਼ੀ ਕਾਹਦੀ, ਫੇਰ ਹੱਸਣਾ ਕੀ ? ਚਾਰੇ ਪਾਸੇ ਹੀ ਘੋਰ ਅੰਧਿਆਰ ਛਾਇਆ, ਕਿਹੜਾ ਰਾਹ ਤੇ ਕਿਸੇ ਨੇ ਨੱਸਣਾ ਕੀ ? ਜਦੋਂ ਹੱਥ ਪਸਾਰਿਆਂ ਨਹੀਂ ਦਿਸਦਾ, ਕਿਓਂ ਆਪਣਾ ਆਪ ਸੰਭਾਲਦੇ ਨਹੀਂ । ਮੰਜ਼ਲ ਵੱਲ ਨੂੰ ਰਾਹ ਦੀ ਪਏ ਝਾਤੀ, ਦੀਵਾ ਕਿਉਂ ਓਹ ਲੱਭਦੇ ਭਾਲਦੇ ਨਹੀਂ ।",
  "147": "ਸਜੇ ਹੋਏ ਸਰੀਰ ਦਾ ਬੁੱਤ ਵੇਖੋ, ਜ਼ਖ਼ਮਾਂ ਨਾਲ ਜੋ ਅੰਦਰੋਂ ਚੂਰ ਹੋਇਆ । ਐਵੇਂ ਬੱਝਿਆ ਖੜਾ ਹੈ ਆਸਰੇ ਤੇ, ਕਈਆਂ ਰੋਗਾਂ ਦੇ ਨਾਲ ਭਰਪੂਰ ਹੋਇਆ । ਇਹਦੇ ਮਨ ਵਿਚ ਭਰੇ ਸੰਕਲਪ ਲੱਖਾਂ, ਭਾਵੇਂ ਓਹਨਾਂ ਦੀ ਦਿਸਦੀ ਛਾਂ ਕੋਈ ਨਾ । ਰਹਿੰਦਾ ਭਟਕਦਾ, ਡੋਲਦਾ, ਥਿੜਕਦਾ ਇਹ, ਮਿਲੇ ਇਹਨੂੰ ਟਿਕਾਣੇ ਦੀ ਥਾਂ ਕੋਈ ਨਾ ।",
  "148": "ਬੁੱਢੀ, ਜਰ-ਜਰੀ, ਕੋਝੀ, ਕਰੂਪ, ਕਾਇਆਂ, ਸਮਝੋ ਆਹਲਣਾ ਨਿਰਾ ਬੀਮਾਰੀਆਂ ਦਾ । ਭਰੀਆਂ ਏਸ ਦੇ ਵਿਚ ਨੇ ਸੜੇਹਾਨਾ, ਭਾਂਡਾ ਗੰਦੀਆਂ ਵਸਤੂਆਂ ਸਾਰੀਆਂ ਦਾ । ਚਾਣਚੱਕ ਹੀ ਏਸ ਨੇ ਭੱਜਣਾ ਏਂ, ਇਕ ਜਗਤ ਪਰਸਿੱਧ ਅਖੌਤ ਸਮਝੋ । ਗੱਲ ਇਹ ਹੈ ਪੱਥਰ ਤੇ ਲੀਕ ਵਾਂਗੂੰ, ਮੰਜ਼ਲ ਜ਼ਿੰਦਗੀ ਦੀ ਆਖਰ ਮੌਤ ਸਮਝੋ ।",
  "149": "ਸੁੱਟੀ ਹੋਈ ਲੌਹਕੀ ਜਿਵੇਂ ਸਰਦੀਆਂ ਵਿਚ, ਭੂਰਾ ਹੱਡੀਆਂ ਦਾ ਰੰਗ ਹੋ ਜਾਏ । ਕੌਣ ਵੇਖ ਕੇ ਓਹਨਾਂ ਨੂੰ ਖ਼ੁਸ਼ੀ ਹੋਵੇ, ਝਾਤੀ ਮਾਰਨੇ ਲਈ ਖਲੋ ਜਾਏ ।",
  "150": "ਇਸ ਨੂੰ ਲਿੰਬਿਆ ਲਹੂ ਤੇ ਮਾਸ ਦੇ ਨਾਲ, ਬਣਿਆ ਹੱਡੀਆਂ ਦਾ ਵੱਡਾ ਸ਼ਹਿਰ ਹੋਇਆ । ਸਣੇ ਮੌਤ, ਅਭੀਮਾਨ ਤੇ ਉਮਰ ਬੁੱਢੜੀ, ਭਰਿਆ ਏਸ ਵਿਚ ਦੰਭ ਦਾ ਜ਼ਹਿਰ ਹੋਇਆ ।",
  "151": "ਕਰਕੇ ਰੰਗ ਸ਼ਿੰਗਾਰਿਆ ਰੱਥ ਸ਼ਾਹੀ, ਸਮਾਂ ਪਾ ਕੇ ਤੇ ਖੱਦਾ ਹੋ ਜਾਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਇਹ ਅਰੋਗ ਕਾਂਇਆਂ, ਬੁਢੀ ਉਮਰ ਤੇ ਪਹੁੰਚ ਖਲੋ ਜਾਏ । ਐਪਰ ਧਰਮੀਆਂ, ਸੰਤਾਂ ਤੇ ਸਾਧੂਆਂ ਤੇ, ਜ਼ਾਲਮ ਕਦੇ ਬੁਢਾਪਾ ਨਾ ਆਉਂਦਾ ਹੈ । ਭਲਾ ਆਦਮੀ ਜੋ ਭਲੇ ਆਦਮੀ ਨੂੰ, ਇਹੀ ਧੁਰਾਂ ਤੋਂ ਭੇਦ ਸਮਝਾਉਂਦਾ ਹੈ ।",
  "152": "ਹੋਵੇ ਆਦਮੀ ਜੋ ਥੋੜ੍ਹੀ ਮੱਤ ਵਾਲਾ, ਵਾਂਗ ਸਾਹਨ ਦੇ ਫਿੱਟਦਾ ਜਾਂਵਦਾ ਏ । ਉਹਦੀ ਮੱਤ ਵਿਚ ਰਤਾ ਨਾ ਹੋਏ ਵਾਧਾ, ਹੱਡ-ਮਾਸ ਦੀ ਹੀ ਭਰਤੀ ਪਾਂਵਦਾ ਏ ।",
  "153": "ਫਿਰਿਆ ਭਾਲਦਾ ਜਨਮ ਜਨਮਾਤਰਾਂ ਵਿਚ, ਕਾਂਇਆਂ ਮਹਿਲ ਨੂੰ ਕਿਨ੍ਹੇ ਉਸਾਰਿਆ ਏ । ਪਈ ਭਾਲ ਤੇ ਘਾਲ ਨਾ ਥਾਏਂ ਮੇਰੀ, ਮੁੜ ਮੁੜ ਜੰਮਣ ਦੇ ਦੁੱਖਾਂ ਨੇ ਮਾਰਿਆ ਏ ।",
  "154": "ਇਹ ਘਰ-ਅਟਾਰੀ ਬਣਾਉਣ ਵਾਲੇ, ਮੈਂ ਪਾ ਲਿਆ ਏ, ਤੈਨੂੰ ਪਾ ਲਿਆ ਏ । ਘਰ ਇਹ ਨਾ ਤੂੰ ਬਣਾਈਂ ਮੁੜ ਕੇ, ਥੰਮਾਂ, ਤੋੜਿਆਂ ਨੂੰ ਘੁਣ ਖਾ ਲਿਆ ਏ । ਲੜੀਆਂ ਇਹਦੀਆਂ ਸਾਰੀਆਂ ਟੁੱਟ ਗਈਆਂ, ਬੁਰਜ ਸਿਖਰ ਦਾ ਵੀ ਸਾਰਾ ਢਹਿ ਗਿਆ ਏ । ਮਨ ਹੋਇਆ ਆਜ਼ਾਦ ਹੈ ਬੰਧਨਾਂ ਤੋਂ, ਮਗਰੋਂ ਤ੍ਰਿਸ਼ਨਾ ਦਾ ਰੋਗ ਵੀ ਲਹਿ ਗਿਆ ਏ ।",
  "155": "ਕੀਤੀ ਸਾਧਨਾ ਹੋ ਨਾ ਬ੍ਰਹਮਚਾਰੀ, ਚੜ੍ਹਦੀ ਉਮਰ ਵੀ ਜਦੋਂ ਵੀਰਾਨ ਜਾਏ । ਮੱਛੀ, ਡੱਡੀ ਬਿਨ ਝੀਲ ਦੇ ਜਾ ਕੰਢੇ, ਬਗਲੇ ਵਾਂਗਰਾਂ ਬਿਰਧ ਧਿਆਨ ਲਾਏ ।",
  "156": "ਕੀਤੀ ਸਾਧਨਾ ਹੋ ਨਾ ਬ੍ਰਹਮਚਾਰੀ, ਚੜ੍ਹਦੀ ਉਮਰ ਵੀ ਜਦੋਂ ਵੀਰਾਨ ਜਾਏ । ਬੁਢੜਾ ਬੀਤਿਆਂ ਦਿਨਾਂ ਨੂੰ ਝੂਰਦਾ ਏ, ਝੁਕ ਵਾਂਗ ਉਹ ਰੱਦੀ ਕਮਾਨ ਜਾਏ ।",
  "chap12": "ਅੱਤ",
  "157": "ਤੈਨੂੰ ਆਪੇ ਦੇ ਨਾਲ ਪਿਆਰ ਜੇਕਰ, ਉਸ ਨੂੰ ਕੀਮਤੀ ਸਮਝ ਸੰਭਾਲਣਾ ਈਂ । ਇਕ ਪਹਿਰ ਤਾਂ ਜਾਗਦੇ ਰਹਿਣ ਪੰਡਤ, ਵਕਤ ਗ਼ਾਫ਼ਲੀ ਵਿਚ ਨਾ ਗਾਲਣਾ ਈਂ ।",
  "158": "ਫੇਰ ਦਏ ਨਸੀਹਤਾਂ ਹੋਰਨਾਂ ਨੂੰ, ਪਹਿਲਾਂ ਆਪ ਜੋ ਨੇਕੀ ਦੀ ਕਾਰ ਕਰਦਾ । ਓਸੇ ਪੰਡਤ ਦੀ ਘਾਲ ਸੁਲੱਖਣੀ ਏ, ਕੋਈ ਦੁੱਖ ਨਾ ਓਸ ਤੇ ਵਾਰ ਕਰਦਾ ।",
  "159": "ਦੇਣਾ ਚਾਹੇ ਉਪਦੇਸ਼ ਜੋ ਹੋਰਨਾਂ ਨੂੰ, ਓਹੀ ਆਪਣੇ ਆਪ ਕਮਾਏ ਪਹਿਲਾਂ । ਰੋਕ ਆਪਣੇ ਆਪ ਨੂੰ ਨਾਲ ਸੰਜਮ, ਹਓਮੈ ਆਪਣੀ ਮਾਰ ਗਵਾਏ ਪਹਿਲਾਂ । ਕਰੇ ਜਾਏ ਕੇ ਦਮਨ ਫਿਰ ਦੂਜਿਆਂ ਦਾ, ਜੀਹਦੇ ਨਾਲ ਕਲਿਆਣ ਉਧਾਰ ਹੁੰਦਾ । ਇਹੀ ਤੱਤ ਵਿਰੋਲਿਆ ਪੰਡਤਾਂ ਨੇ, ਸੌਖਾ ਆਪਣਾ ਆਪ ਨਹੀਂ ਮਾਰ ਹੁੰਦਾ ।",
  "160": "ਹੁੰਦਾ ਹੋਰ ਨਾ ਕਿਸੇ ਦਾ ਕੋਈ ਸਵਾਮੀ, ਅਸਲੋਂ ਆਦਮੀ ਫੇਅਲ-ਮੁਖਤਾਰ ਹੋਵੇ । ਹੋਰ ਕੌਣ ਹੈ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਜਿਸਦਾ ਆਦਮੀ ਤਾਬਿਆਦਾਰ ਹੋਵੇ । ਜਦੋਂ ਆਪਣੇ ਆਪ ਨੂੰ ਮਾਰ ਲਈਏ, ਵੱਡਾ ਫੇਰ ਹੈ ਸ਼ਾਹ ਸੁਲਤਾਨ ਮਿਲਦਾ । ਜਿਸ ਨੂੰ ਸਮਝਦੇ ਨੇ ਮੁਸ਼ਕਿਲ ਸਾਰਿਆਂ ਤੋਂ, ਓਹ ਜੀਵ ਨੂੰ ਪਰਮ ਨਿਰਵਾਣ ਮਿਲਦਾ ।",
  "161": "ਕੀਤਾ ਆਪਣੇ ਆਪ ਦਾ ਪਾਪ ਹੋਇਆ, ਜਾਇਆ ਆਪਣਾ ਪਾਪ ਈ ਮਾਰਦਾ ਏ । ਹੱਥੀਂ ਆਪ ਸਹੇੜੀਏ ਪਾਪ ਜਿਹੜਾ, ਓੜਕ ਆਣ ਕੇ ਓਹੀ ਦੁਰਕਾਰਦਾ ਏ । ਸਦਾ ਆਪਣੇ ਪਾਪ ਦੀ ਮਾਰ ਤਿਖੀ, ਇਓਂ ਮੂੜ੍ਹ ਨੂੰ ਚੀਰਦੀ ਪਾੜਦੀ ਏ । ਸਖ਼ਤ ਪੱਥਰਾਂ ਦੀ ਜਿਵੇਂ ਸੱਟ ਕਰੜੀ, ਕਿਸੇ ਚੀਜ਼ ਨੂੰ ਪਈ ਦਰਾੜਦੀ ਏ ।",
  "162": "ਜਿਵੇਂ ਸਾਲ ਦੇ ਰੁੱਖ ਨੂੰ ਘੇਰਨੇ ਲਈ, ਅਮਰ-ਵੇਲ ਦਾ ਜਾਲ-ਆਕਾਰ ਫੈਲੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਢਾਹੁਣ ਲਈ ਆਦਮੀ ਨੂੰ, ਓਹਦਾ ਆਪਣਾ ਹੀ ਦੁਰਾਚਾਰ ਫੈਲੇ । ਸੱਚੀ ਗੱਲ ਹੈ ਆਦਮੀ ਜਿਸ ਵੇਲੇ, ਦੁਰਾਚਾਰ ਦੇ ਵੱਸ ਹੈ ਹੋ ਜਾਂਦਾ । ਜਿਹੜੀ ਭਾਂਵਦੀ ਓਸ ਦੇ ਵੈਰੀਆਂ ਨੂੰ, ਓਸੇ ਥਾਂ ਤੇ ਆਣ ਖਲੋ ਜਾਂਦਾ ।",
  "163": "ਗੱਲਾਂ ਮਾੜੀਆਂ ਕਰਨੀਆਂ ਸੌਖੀਆਂ ਨੇ, ਏਸ ਬਾਤ ਨੂੰ ਜ਼ਰਾ ਵਿਚਾਰਨਾ ਜੇ । ਇਹ ਤਾਂ ਆਪਣਾ ਕਰਨ ਨੁਕਸਾਨ ਭਾਰਾ, ਹੱਥੀਂ ਪੈਰ ਕੁਹਾੜੇ ਨੂੰ ਮਾਰਨਾ ਜੇ । ਉਸਦੇ ਉਲਟ ਪਰ ਚੰਗੀਆਂ ਸਾਊ ਗੱਲਾਂ, ਲਾਭ ਜਿਨ੍ਹਾਂ ਦਾ ਬੜਾ ਮਹਾਨ ਹੁੰਦਾ । ਮੁਸ਼ਕਲ ਓਹਨਾਂ ਦੇ ਬਾਰੇ ਹੈ ਇਹ ਬਣਦੀ, ਕਰਨਾ ਓਹਨਾਂ ਨੂੰ ਨਹੀਂ ਆਸਾਨ ਹੁੰਦਾ ।",
  "164": "ਸਿਆਣੇ, ਸਾਊ, ਗੁਣਵੰਤ ਤੇ ਨੇਕਨੀਅਤ, ਹੁੰਦੇ ਲੋਕ ਜੋ ਮਾਨ ਸਨਮਾਨ ਵਾਲੇ । ਜਿਹੜੇ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਰਹਿਣ ਤੁਰਦੇ, ਉੱਜਲ-ਬੁੱਧ ਤੇ ਗਿਆਨ ਧਿਆਨ ਵਾਲੇ । ਕਰੇ ਇਹਨਾਂ ਦੀ ਨਿੰਦਿਆ ਮੂੜ੍ਹ ਕੋਈ, ਮੰਦੀ ਭਾਵਨਾ ਵੱਸ, ਅਪਮਾਨ ਕਰਦਾ । ਜਿਵੇਂ ਵੰਝਾਂ ਨੂੰ ਵੰਝਾਂ ਦੇ ਫੁੱਲ ਖਾਂਦੇ, ਮੂੜ੍ਹ ਆਪਣਾ ਤਿਵੇਂ ਨੁਕਸਾਨ ਕਰਦਾ ।",
  "165": "ਓਹੀ ਆਪਣੀ ਬੁੱਧ ਨੂੰ ਕਰੇ ਮੈਲਾ, ਕੀਤਾ ਆਪਣੇ ਆਪ ਜੋ ਪਾਪ ਹੋਵੇ । ਨਾਲ ਪਾਪ ਜੇ ਹੱਥ ਨਾ ਭਰੇ ਕੋਈ, ਨਹੀਂ ਓਸ ਨੂੰ ਰੋਗ ਸੰਤਾਪ ਹੋਵੇ । ਅਸਲ, ਓਹ ਤਾਂ ਆਪਣਾ ਪਾਪ ਹੀ ਹੈ, ਜਿਸ ਦੇ ਕੀਤਿਆਂ ਸ਼ੁੱਧ ਅਸ਼ੁੱਧ ਹੋਵੇ । ਕੋਈ ਆਦਮੀ ਵੀ ਕਿਸੇ ਦੂਸਰੇ ਦੇ, ਨਹੀਂ ਕੀਤਿਆਂ ਕਦੇ ਵੀ ਸ਼ੁੱਧ ਹੋਵੇ ।",
  "166": "ਹੋਣ ਹੋਰਾਂ ਦੇ ਹਿਤ ਹਜ਼ਾਰ ਭਾਵੇਂ, ਬਾਹਲਾ ਗੌਲੀਏ ਓਹਨਾਂ ਨੂੰ ਫੋਲੀਏ ਨਾ । ਐਵੇਂ ਕਿਸੇ ਦੇ ਹਿਤਾਂ ਦੀ ਰੱਖਿਆ ਲਈ, ਹਿਤ ਆਪਣਾ ਮਿੱਟੀ ਵਿਚ ਰੋਲੀਏ ਨਾ । ਸਦਾ ਆਪਣਾ ਜਾਣੀਏਂ ਹਿਤ ਕਿਹੜਾ, ਨਜ਼ਰ ਸਾਹਮਣੇ ਓਹਨੂੰ ਸੰਭਾਲਣਾਂ ਜੇ । ਬਿਨਾਂ ਥਿੜਕਿਆਂ, ਸਦਾ ਪਰਯਤਨ ਕਰ ਕੇ, ਓਹਨੂੰ ਪਾਲਣਾ ਏਂ, ਓਹਨੂੰ ਪਾਲਣਾ ਜੇ ।",
  "167": "ਭਲੇ ਆਦਮੀ ! ਸਦਾ ਸੁਚੇਤ ਰਹਿਣਾ, ਨੀਚ ਧਰਮ ਨੂੰ ਕਦੇ ਨਾ ਪਾਲਣਾ ਈਂ । ਖਬਰਦਾਰ, ਹੁਸ਼ਿਆਰ ਚੇਤੰਨ ਸੋਮਨ, ਉਮਰ ਗ਼ਾਫ਼ਲੀ ਵਿਚ ਨਾ ਗਾਲਣਾ ਈਂ । ਮਗਰ ਲੱਗ ਕੇ ਮੰਦੀਆਂ ਧਾਰਨਾਂ ਦੇ, ਕੋਝਾ ਕੰਮ ਹੈ ਬਿਨਾਂ ਗਿਆਨ ਰਹਿਣਾ । ਮਾੜੇ ਪਿੱਟਣੇ ਬਹੁਤ ਸਹੇੜ ਲੈਣੇ, ਫੋਕਾ ਧੰਦਿਆਂ ਵਿਚ ਗ਼ਲਤਾਨ ਰਹਿਣਾ ।",
  "chap13": "ਲੋਕ",
  "168": "ਆਲਸ. ਗ਼ਾਫ਼ਲੀ ਨੂੰ ਮਨ ਤੋਂ ਝਾੜ ਦਈਏ, ਸਦਾ ਆਦਮੀ ਚੁਸਤ ਹੁਸ਼ਿਆਰ ਚੰਗਾ । ਹੋਰ ਸਾਰਿਆਂ ਕੰਮਾਂ ਤੋਂ ਵਿਚ ਦੁਨੀਆਂ, ਉੱਤਮ ਧਰਮ ਦਾ ਸੁੱਚ ਵਿਹਾਰ ਚੰਗਾ । ਜੋ ਵੀ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਜਾਏ ਤੁਰਦਾ, ਸਫਲ ਓਸੇ ਦਾ ਜੱਗ ਤੇ ਜੀਵਣਾ ਈਂ । ਓਹਦੇ ਕਾਜ ਸੁਹੇਲੜੇ ਰਾਸ ਆਉਂਦੇ, ਸੁਖੀ ਲੋਕ ਪਰਲੋਕ ਵਿਚ ਥੀਵਣਾ ਈਂ ।",
  "169": "ਉੱਤਮ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਤੁਰਨ ਵਾਲੇ, ਪੱਲੇ ਸੱਚ ਆਚਾਰ ਨੂੰ ਬੰੱਨ੍ਹਣਾ ਈਂ । ਦੁਰਾਚਾਰ, ਕੁਕਰਮਾਂ ਤੋਂ ਦੂਰ ਰਹਿਣਾ, ਭਾਂਡਾ ਕੂੜ ਦਾ ਤੋੜਨਾ ਭੰਨਣਾਂ ਈਂ । ਜੋ ਵੀ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਜਾਣ ਤੁਰਦੇ, ਸਫਲ ਓਹਨਾਂ ਦਾ ਜੱਗ ਤੇ ਜੀਵਣਾ ਈਂ । ਸੱਭ ਕਾਜ ਸੁਹੇਲੜੇ ਕਰ ਓਹਨਾਂ, ਸੁਖੀ ਲੋਕ ਪਰਲੋਕ ਵਿਚ ਥੀਵਣਾ ਈਂ ।",
  "170": "ਜਿਹੜਾ ਏਸ ਸੰਸਾਰ ਨੂੰ ਇਓਂ ਜਾਣੇ, ਇਹ ਤਾਂ ਨਿਰਾ ਹੀ ਬੁਲਬੁਲਾ ਆਬ ਦਾ ਏ । ਮਾਰੂਥਲ ਅੰਦਰ ਧੋਖਾ ਨਜ਼ਰ ਦਾ ਹੈ, ਹੁੰਦਾ ਝਾਉਲਾ ਜਿਵੇਂ ਸਰਾਬ ਦਾ ਏ । ਜਿਸ ਵੀ ਆਦਮੀ ਨੂੰ ਪਏ ਇਹ ਸੋਝੀ, ਓਹ ਰਾਹ ਨਿਰਵਾਣ ਦੇ ਜਾ ਸਕਦਾ । ਲੱਖ ਟੱਕਰਾਂ ਪਿਆ ਯਮਰਾਜ ਮਾਰੇ, ਓਹਦੀ ਗਰਦ ਨੂੰ ਕਦੇ ਨਹੀਂ ਪਾ ਸਕਦਾ ।",
  "171": "ਆਓ ! ਜ਼ਰਾ ਸੰਸਾਰ ਤੇ ਪਾਓ ਝਾਤੀ, ਕਿਵੇਂ ਰੰਗਾਂ ਦੇ ਨਾਲ ਨਿਖਾਰਿਆ ਏ । ਕਿਵੇਂ ਲਿਸ਼ਕਿਆ, ਪੋਚਿਆ, ਸੱਜਦਾ ਏ, ਜੰਗੀ ਰੱਥ ਜਿਓਂ ਕਿਸੇ ਸ਼ਿੰਗਾਰਿਆ ਏ । ਮੂੜ੍ਹ ਜਾਣਦੇ ਜੋ ਨਾ ਅਸਲ ਇਹਦਾ, ਫਸਕੇ ਭਰਮ ਅੰਦਰ ਅਵਾਜ਼ਾਰ ਹੁੰਦੇ । ਗਿਆਨੀ ਪੁਰਸ਼ ਜੋ ਸਾਰ ਪਛਾਣ ਲੈਂਦੇ, ਓਹ ਨਾ ਔਝੜੀਂ ਪੈ ਖਵਾਰ ਹੁੰਦੇ ।",
  "172": "ਰਿਹਾ ਆਲਸੀ, ਗ਼ਾਫ਼ਲੀ ਜੋ ਕਰਦਾ, ਮਗਰੋਂ ਆਣ ਪਰ ਹੋ ਹੁਸ਼ਿਆਰ ਜਾਏ । ਹੇਠ ਪੁੰਨ ਦੇ ਢੱਕ ਲਏ ਪਾਪ ਆਪਣੇ, ਜਿਹੜਾ ਆਪਣਾ ਆਪ ਸੁਧਾਰ ਜਾਏ ।",
  "173": "ਓਹ ਕਾਇਆਂ ਸੰਸਾਰ ਦੀ ਪਲਟ ਦੇਵੇ, ਇਓਂ ਧਰਤੀ ਦਾ ਰੂਪ ਨਿਖਾਰਦਾ ਏ । ਨਿਕਲ ਬੱਦਲਾਂ ਓਹਲਿਓਂ ਚੰਦ ਮਾਮਾ, ਚਾਨਣ ਆਪਣਾ ਜਿਵੇਂ ਖਿਲਾਰਦਾ ਏ ।",
  "174": "ਹੋ ਗਿਆ ਹੈ ਸਗਲ ਸੰਸਾਰ ਅੰਨ੍ਹਾ, ਥੋੜ੍ਹੇ ਲੋਕ ਨੇ ਨਜ਼ਰ ਪਛਾਣ ਵਾਲੇ । ਵਿਰਲਾ ਜਾਲ 'ਚੋਂ ਨਿਕਲਦਾ ਜਿਵੇਂ ਪੰਛੀ, ਬੜੇ ਘਟ ਨਿਰਵਾਣ ਨੂੰ ਪਾਣ ਵਾਲੇ ।",
  "175": "ਸੂਰਜ ਵੱਲ ਉਡਾਰੀਆਂ ਹੰਸ ਲਾਉਂਦੇ, ਜੋਗੀ ਸਿਧ ਜੋ ਫਿਰਨ ਅਸਮਾਨ ਅੰਦਰ । ਗਿਆਨੀ ਜਿੱਤ ਸ਼ੈਤਾਨ ਨੂੰ ਸਣੇ ਸੈਨਾ, ਜਾਣ ਸੁਰਖਰੂ ਹੋ ਜਹਾਨ ਅੰਦਰ ।",
  "176": "ਇਕ ਵਾਰ ਵੀ ਫਿਸਲ ਕੇ ਪੁਰਸ਼ ਜਿਹੜਾ, ਮੁੱਖ ਧਰਮ ਦੇ ਰਾਹ ਤੋਂ ਮੋੜਦਾ ਏ । ਨਹੀਂ ਫ਼ਿਕਰ ਪਰਲੋਕ ਦਾ ਜ਼ਰਾ ਕਰਦਾ, ਰਹਿੰਦਾ ਕੂੜ ਕਹਾਣੀਆਂ ਜੋੜਦਾ ਏ । ਇਓਂ ਚਿੰਤਾ-ਵਿਹੂਣ ਜੇ ਹੋਏ ਕੋਈ, ਝੋਲੀ ਨਾਲ ਗੁਨਾਹਾਂ ਦੇ ਭਰ ਸਕਦਾ । ਹੋਣਾ ਪਾਪ ਨਾ ਜੱਗ ਤੇ ਕੋਈ ਐਸਾ, ਐਸਾ ਆਦਮੀ ਜੋ ਨਹੀਂ ਕਰ ਸਕਦਾ ।",
  "177": "ਗੱਲ ਠੀਕ ਹੈ, ਲੋਕ ਕੰਜੂਸ ਜਿਹੜੇ, ਦੇਵ-ਲੋਕ ਦੇ ਵਿਚ ਨਹੀਂ ਜਾ ਸਕਦੇ । ਮੂਰਖ ਦਾਨ ਦੀ ਕਦੇ ਨਹੀਂ ਸਿਫ਼ਤ ਕਰਦੇ, ਹੁੰਦੀ ਸਿਫ਼ਤ ਨਾ ਵੇਖ ਪਚਾ ਸਕਦੇ । ਹੁੰਦੀ ਖ਼ੂਬੀ ਪਰ ਪੰਡਤਾਂ ਸਿਆਣਿਆਂ ਦੀ, ਸਿਫ਼ਤ ਦਾਨ ਵਰਦਾਨ ਦੀ ਕਰ ਜਾਂਦੇ । ਸੁਖੀ ਸਦਾ ਸੰਸਾਰ ਵਿਚ ਹੋ ਜਾਂਦੇ, ਇਸੇ ਕਰਮ ਦੇ ਨਾਲ ਹੀ ਤਰ ਜਾਂਦੇ ।",
  "178": "ਕੋਈ ਸੁਰਗਾਂ ਵਿਚ ਜਾਏ ਕੇ ਫਿਰੇ ਭਉਂਦਾ, ਵੱਡਾ ਧਰਤੀ ਤੇ ਕਿਸੇ ਦਾ ਰਾਜ ਹੋਵੇ । ਸਵਾਮੀ ਲੋਕ ਪਰਲੋਕ ਦਾ ਹੋ ਜਾਏ, ਓਹਦੇ ਸੀਸ ਤੇ ਸ਼ੋਭਦਾ ਤਾਜ ਹੋਵੇ । ਇਹਨਾਂ ਸਾਰੀਆਂ ਅਜ਼ਮਤਾਂ ਪਦਵੀਆਂ ਤੋਂ, ਦਰਜਾ ਸਾਧਕ ਦਾ ਬੜਾ ਬਲੰਦ ਹੁੰਦਾ । ਜਿਹੜਾ ਮਿਲੇ ਨਿਰਵਾਣ ਦਾ ਵਹਿਣ ਤਰਿਆਂ, ਓਸ ਫਲ ਦਾ ਮਹਾਂ ਆਨੰਦ ਹੁੰਦਾ ।",
  "chap14": "ਬੁੱਧ",
  "179": "ਜਿਸ ਦੀ ਜਿੱਤ ਨਾ ਹਾਰ ਵਿਚ ਬਦਲਦੀ ਏ, ਜਿੱਤੇ ਹੋਏ ਨਾ ਸਿਰ ਉਠਾ ਸਕਦੇ । ਇਉਂ ਕੁਚਲੇ ਨੇ ਮੋਹ ਤੇ ਕਾਮ ਜਿਸਨੇ, ਮੁੜਕੇ ਉਹਨੂੰ ਭਰਮਾਉਣ ਨਹੀਂ ਆ ਸਕਦੇ । ਓਹ ਬੁੱਧ, ਅਲੇਪ, ਅਨੰਤ-ਗੋਚਰ, ਮੋਹ ਵਾਸ਼ਨਾ ਦੇ ਜਿਸ ਦੇ ਪੈਰ ਹੈ ਨਹੀਂ । ਐਸੇ ਬੁੱਧ ਨੂੰ ਵੱਸ ਜੋ ਕਰਨ ਆਏ, ਮਾਰ-ਕੰਨਿਆਂ ਦੀ ਸਮਝੋ ਖ਼ੈਰ ਹੈ ਨਹੀਂ ।",
  "180": "ਤ੍ਰਿਸ਼ਨਾ ਜ਼ਹਿਰ-ਭਿੱਜੀ ਜਿਹੜੀ ਬੁੱਧ ਤਾਈਂ, ਕਦੇ ਰਾਹੋਂ ਕੁਰਾਹੇ ਨਹੀਂ ਪਾ ਸਕਦੀ । ਜਾਲ ਘੱਤ ਕੇ ਵਾਂਗ ਸ਼ਿਕਾਰੀਆਂ ਦੇ, ਫਾਹੀ ਵਿਚ ਨਾ ਉਸ ਨੂੰ ਫਸਾ ਸਕਦੀ । ਓਹ ਬੁੱਧ, ਅਲੇਪ, ਅਨੰਤ-ਗੋਚਰ, ਮੋਹ ਵਾਸ਼ਨਾ ਦੇ ਜਿਸ ਦੇ ਪੈਰ ਹੈ ਨਹੀਂ । ਐਸੇ ਬੁੱਧ ਨੂੰ ਵੱਸ ਜੋ ਕਰਨ ਆਏ, ਮਾਰ-ਕੰਨਿਆਂ ਦੀ ਸਮਝੋ ਖ਼ੈਰ ਹੈ ਨਹੀਂ ।",
  "181": "ਕੋਈ ਸਾਧਕ ਜੋ ਸਦਾ ਅਟੰਕ ਹੋ ਕੇ, ਮਸਤ ਵਿਚ ਗਿਆਨ ਧਿਆਨ ਰਹਿੰਦਾ । ਭੱਜ-ਨੱਸ ਤਿਆਗ ਕੇ ਖ਼ੁਸ਼ ਹੋਵੇ, ਚਿੱਤ ਸ਼ਾਂਤ ਓਹ ਵਿਚ ਨਿਰਵਾਣ ਰਹਿੰਦਾ । ਐਸੇ ਬੁੱਧ ਦੀ ਹੁੰਦੀ ਜੋ ਮਹਾਂ ਪਦਵੀ, ਮਿਲਦੀ ਨਹੀਂ ਹੈ ਕਿਸੇ ਨੂੰ ਸੌਖ ਦੇ ਨਾਲ । ਰਹਿ ਗਏ ਮਨੁੱਖ ਤਾਂ ਇਕ ਪਾਸੇ, ਪੁੱਜਣ ਦੇਵਤੇ ਓਸ ਨੂੰ ਔਖ ਦੇ ਨਾਲ ।",
  "182": "ਮਾਨਸ ਜਨਮ ਪਰਾਪਤੀ ਬੜੀ ਮੁਸ਼ਕਿਲ, ਇਹ ਨਹੀਂ ਹੈ ਜੇ ਬਾਰਮਬਾਰ ਹੁੰਦਾ । ਇਹ ਜਨਮ ਦੁਰਲੱਭ ਜੇ ਮਿਲ ਜਾਏ, ਜੀਵਣ ਜੀਉਣਾ ਵੀ ਬੜਾ ਦੁਸ਼ਵਾਰ ਹੁੰਦਾ । ਸੱਚ, ਧਰਮ, ਉਪਦੇਸ਼ ਦਾ ਧਿਆਨ ਧਰਨਾ, ਹੋਵੇ ਸਾਧਕਾਂ ਲਈ ਨਾ ਗੱਲ ਔਖੀ । ਆਉਂਦੇ ਬੁੱਧ ਭਗਵਾਨ ਹਨ ਯੁਗਾਂ ਮਗਰੋਂ, ਪਰਗਟ ਹੋਣਾ ਨਾ ਓਹਨਾਂ ਦਾ ਗੱਲ ਸੌਖੀ ।",
  "183": "ਇਹ ਚਾਹੀਦਾ ਸਾਧਕਾਂ, ਸਾਦਕਾਂ ਨੂੰ, ਹਰ ਪਾਪ ਤੋਂ ਸਦਾ ਪਰਹੇਜ਼ ਕਰਨਾ । ਸਾਫ਼ ਲਿਸ਼ਕਦਾ ਰਹੇ ਐਮਾਲ ਨਾਮਾ, ਉਸ ਨੂੰ ਨੇਕੀਆਂ ਨਾਲ ਲਬਰੇਜ਼ ਕਰਨਾ । ਮਨ ਉਹਨਾਂ ਦਾ ਕਰੇ ਨਾ ਮੋਹ ਮੈਲਾ, ਮਨ ਰੱਖਣਾ ਸ਼ੁੱਧ ਹਮੇਸ਼ ਹੁੰਦਾ । ਗਿਆਨਵਾਨ ਨਿਰਵਾਣ ਨੂੰ ਹੋ ਪੁੱਜੇ, ਮਹਾਂ ਬੁਧਾਂ ਦਾ ਇਹੀ ਉਪਦੇਸ਼ ਹੁੰਦਾ ।",
  "184": "ਸਹਿਣ-ਸ਼ੀਲਤਾ, ਕਿਸੇ ਨੂੰ ਖਿਮਾ ਕਰਨੀ, ਉਹ ਸਮਝੀਏ, ਤਪ ਮਹਾਨ ਹੁੰਦਾ । ਖ਼ੁਸ਼ੀ ਨਾਲ ਸੰਸਾਰ ਤਿਆਗ ਦੇਣਾ, ਪਾਉਣ ਅਸਲ ਵਿਚ ਪਰਮ ਨਿਰਵਾਣ ਹੁੰਦਾ । ਦੁਨੀਆਂ ਵਿਚ ਆਜ਼ਾਦੀ ਦੇ ਨਾਲ ਭਉਂਦੇ, ਓਹ ਕਦੇ ਨਹੀਂ ਕਿਸੇ ਦਾ ਘਾਤ ਕਰਦੇ । 'ਸ਼ਮਣ' ਉਹ ਨਾ ਆਖੀਏ ਕਿਸੇ ਨੂੰ ਜੋ, ਕੋਈ ਦੁੱਖ ਪੁਚਾਉਣ ਦੀ ਬਾਤ ਕਰਦੇ ।",
  "185": "ਕਰੀਏ ਨਿੰਦਿਆ ਨਾ, ਗਾਲਾਂ ਕੱਢੀਏ ਨਾ, ਧਰਮ-ਮੋਖ ਦੇ ਮਾਰਗ ਤੇ ਜਾਵਣਾ ਈਂ । ਬਹਿਣਾ, ਉੱਠਣਾ, ਸੌਣਾ ਇਕਾਂਤ ਅੰਦਰ, ਖਾਣਾ ਸਦਾ ਹਿਸਾਬ ਦਾ ਖਾਵਣਾ ਈਂ । ਉੱਚੇ ਖ਼ਿਆਲਾਂ ਦੇ ਮੰਡਲਾਂ ਵਿਚ ਭੰਵੀਏ, ਫੇਰ ਕਦੇ ਨਾ ਕੋਈ ਕਲੇਸ਼ ਹੁੰਦਾ । ਬੁੱਧਾਂ ਪਰਮ-ਨਿਰਵਾਣ ਨੂੰ ਪੁੱਜਿਆਂ ਦਾ, ਇਹੋ ਸਦਾ ਹੈ ਸ਼ੁਭ ਉਪਦੇਸ਼ ਹੁੰਦਾ ।",
  "186": "ਭਾਵੇਂ ਹੋਵੇ ਰੁਪਈਆਂ ਦਾ ਮੀਂਹ ਵਰ੍ਹਦਾ, ਤ੍ਰਿਪਤੇ ਕਾਮ ਨਾ ਹੋਰ ਵੀ ਭੜਕਦਾ ਏ । ਸਵਾਦ ਕਰਮ ਤੇ ਭੋਗ ਦਾ ਛਿਨ-ਭੰਗਰ, ਫੇਰ ਦੁੱਖ ਦੇ ਵਾਂਗਰਾਂ ਰੜਕਦਾ ਏ ।",
  "187": "ਭੇਦ ਸਮਝ ਪੰਡਤ ਦੇਵ ਲੋਕ ਅੰਦਰ, ਨਹੀਂ ਭੋਗਾਂ ਦੇ ਵਿਚ ਵਿਸ਼ਵਾਸ ਕਰਦਾ । ਬਣ ਕੇ ਬੁੱਧ ਭਗਵਾਨ ਦਾ ਉਹ ਚੇਲਾ, ਤ੍ਰਿਸ਼ਨਾ, ਕਾਮ ਨੂੰ ਮਾਰਦਾ ਨਾਸ਼ ਕਰਦਾ ।",
  "188": "ਡਰਕੇ ਆਦਮੀ ਨੱਸਦੇ ਖਤਰਿਆਂ ਤੋਂ, ਸ਼ਰਨ ਜਾ ਪਹਾੜਾਂ ਵਿਚ ਭਾਲਦੇ ਨੇ । ਰੁੱਖਾਂ, ਬਾਗ਼ਾਂ ਤੇ ਵਣਾਂ ਦੀ ਕਰਨ ਪੂਜਾ, ਉਮਰਾਂ ਪਾਕ ਮੁਕਾਮਾਂ ਤੇ ਗਾਲਦੇ ਨੇ ।",
  "189": "ਪੂਜਾ ਏਸ ਦਾ ਹੋਏ ਨਾ ਲਾਭ ਕਾਈ, ਏਸ ਸ਼ਰਨ ਵਿਚ ਨਹੀਂ ਧਰਵਾਸ ਹੁੰਦਾ । ਸ਼ਰਨ ਆਏ ਨੂੰ ਇਹ ਨਾ ਕੰਠ ਲਾਏ, ਨਹੀਂ ਦੁੱਖਾਂ ਕਲੇਸ਼ਾਂ ਦਾ ਨਾਸ਼ ਹੁੰਦਾ ।",
  "190": "ਸੰਘ, ਬੁੱਧ ਭਗਵਾਨ ਤੇ ਧਰਮ ਸੰਧੀ, ਸ਼ਰਨ ਜੋ ਵੀ ਆਦਮੀ ਮਾਣ ਗਿਆ ।",
  "191": "ਉੱਜਲ ਮੱਤ ਤੇ ਗਿਆਨ ਦੀ ਸੂਝ ਸਦਕਾ, ਚੌਹਰਾ-ਸੱਚ ਪਵਿਤ ਪਛਾਣ ਗਿਆ । 'ਦੁੱਖ ਹੈ ਕੀ ਏ ? ਦੁੱਖ ਕਿਵੇਂ ਉਪਜੇ ? ਦੁੱਖ ਕਿਵੇਂ ਬਿਨਸੇ ? ਅਸ਼ਟ ਅੰਗ ਮਾਰਗ' ।",
  "192": "ਉੱਤਮ ਸ਼ਰਨ ਇਹ ਰੱਖਿਆ ਕਰਨ ਵਾਲੀ, ਆਇਆ ਏਸ ਵਿਚ ਦੁੱਖਾਂ ਤੋਂ ਹੋਏ ਫ਼ਾਰਗ ।",
  "193": "ਪੂਰਨ ਪੁਰਖ ਹੈ ਬੜਾ ਦੁਰਲੱਭ ਮਿਲਦਾ, ਵਿਰਲੇ ਘਰੀਂ ਅਵਤਾਰ ਉਹ ਧਾਰਦਾ ਏ । ਉਹਦਾ ਜਨਮ ਸੁਲੱਖਣਾ ਸੁਖਦਾਇਕ, ਉਹ ਪੀਹੜੀਆਂ ਤੇ ਕੁਲਾਂ ਤਾਰਦਾ ਏ ।",
  "194": "ਧੰਨ ! ਬੁੱਧਾਂ ਦਾ ਜਨਮ ਸੁਹੇਲੜਾ ਏ, ਧੰਨ ! ਸੰਘ ਦੇ ਵਿਚ ਪਰਵੇਸ਼ ਕਰਨਾ । ਧੰਨ ! ਘਾਲ ਤਪੱਸਿਆ ਸਦਾ ਕਰਨੀ, ਧੰਨ ! ਧਰਮ ਦਾ ਸਦਾ ਉਪਦੇਸ਼ ਕਰਨਾ ।",
  "195": "ਜਿਵੇਂ ਬੁੱਧ ਭਗਵਾਨ ਦੇ ਨਾਲ ਚੇਲੇ, ਰੋਗ ਸੋਗ ਦੀ ਜੂਹ ਤੋਂ ਪਾਰ ਹੋਏ । ਜਿਹੜੇ ਭੈ ਨਾ ਕਿਸੇ ਦਾ ਜਾਣਦੇ ਨੇ, ਦੁਖਾਂ ਸਾਹਮਣੇ ਨਹੀਂ ਲਾਚਾਰ ਹੋਏ ।",
  "196": "ਓਹੀ ਪੂਜਾ ਕਰਾਉਣ ਦੇ ਯੋਗ ਹੁੰਦੇ, ਜੋ ਵੀ ਉਹਨਾਂ ਨੂੰ ਪੂਜ ਸਤਕਾਰਦਾ ਏ । ਏਡਾ ਫਲ ਮਰਾਤਬਾ ਮਿਲੇ ਓਹਨੂੰ, ਜਿਹੜਾ ਕਥਨ ਬਿਆਨ ਤੋਂ ਬਾਹਰ ਦਾ ਏ ।",
  "chap15": "ਸੁਖ",
  "197": "ਆਓ ! ਵੈਰੀਆਂ ਵਿਚ ਨਿਰਵੈਰ ਹੋ ਕੇ, ਖ਼ੁਸ਼ੀ ਅਤੇ ਆਨੰਦ ਨੂੰ ਮਾਣ ਲਈਏ । ਰਹਿਣਾ ਵੈਰੀਆਂ ਵਿਚ ਨਿਰਵੈਰ ਕਿੱਦਾਂ, ਏਸ ਭੇਦ ਵਿਹਾਰ ਨੂੰ ਜਾਣ ਲਈਏ ।",
  "198": "ਆਓ ਦੁੱਖ ਨੂੰ ਆਪ ਅਣ-ਡਿੱਠ ਕਰਕੇ, ਰਹੀਏ ਖ਼ੁਸ਼ੀ ਦੇ ਨਾਲ ਦੁਖਿਆਰਿਆਂ ਵਿਚ । ਰਹਿਣ ਦੁੱਖ ਤੋਂ ਬੇਨਿਆਜ਼ ਕਿਦਾਂ ? ਕਰਨਾ ਕਿਵੇਂ ਵਿਹਾਰ ਦੁਖਿਆਰਿਆਂ ਵਿਚ ।",
  "199": "ਲਿਪਤ ਲੋਕਾਂ ਦੇ ਵਿਚ ਨਿਰਲਿਪਤ ਹੋ ਕੇ, ਖ਼ੁਸ਼ੀ ਅਤੇ ਆਨੰਦ ਨੂੰ ਮਾਣ ਲਈਏ । ਕਿਵੇਂ, ਲਿਪਤਾਂ ਦੇ ਵਿਚ ਨਿਰਲਿਪਤ ਰਹਿਣਾ, ਏਸ ਭੇਦ ਵਿਹਾਰ ਨੂੰ ਜਾਣ ਲਈਏ ।",
  "200": "ਕੌਡੀ ਮਾਲ ਨਾ ਅਸਾਂ ਦੇ ਕੱਖ ਪੱਲੇ, ਕਿਉਂ ਅਸੀਂ ਆਨੰਦ ਨਾ ਮਾਣ ਲਈਏ । ਨੂਰੀ ਦੇਵਤੇ ਜਿਸ ਤਰ੍ਹਾਂ ਕਰਨ ਮੌਜਾਂ, ਖ਼ੁਸ਼ੀਆਂ ਸਬਰ ਸਬੂਰੀ ਵਿਚ ਮਾਣ ਲਈਏ ।",
  "201": "ਇਹ ਗੱਲ ਹੈ ਪੱਥਰ ਤੇ ਲੀਕ ਵਾਂਗੂੰ, ਜਿੱਤ ਸਦਾ ਹੀ ਵੈਰ ਉਭਾਰਦੀ ਏ । ਜਿਹੜਾ ਹਾਰ ਜਾਂਦਾ, ਬੜਾ ਦੁੱਖੀ ਰਹਿੰਦਾ, ਕਿਉਂਕਿ ਉਹਨੂੰ ਸ਼ਰਮਿੰਦਗੀ ਮਾਰਦੀ ਏ । ਹੋਇਆ 'ਰਾਗ-ਦਵੇਸ਼' ਤੋਂ ਮੁਕਤ ਜਿਹੜਾ, ਚਿੱਤ ਸ਼ਾਂਤ ਉਹਦਾ ਕਦੇ ਡੋਲਦਾ ਨਹੀਂ । ਸੱਚੇ ਸਾਧਕਾਂ ਵਾਂਗ ਓਹ ਖ਼ੈਰ ਖ਼ੁਸ਼ੀਆਂ, ਕਦੇ ਜਿੱਤ ਜਾਂ ਹਾਰ ਵਿਚ ਟੋਲਦਾ ਨਹੀਂ ।",
  "202": "ਰਾਗ ਕਾਮਨਾ, ਤੇ ਤ੍ਰਿਸ਼ਨਾ ਕਾਮ ਨਾਲੋਂ, ਕੋਈ ਹੋਰ ਅਗਨੀ ਬਾਹਲਾ ਸਾੜਦੀ ਨਹੀਂ । ਘਿਰਨਾ, ਈਰਖਾ, ਵੈਰ, ਦਵੈਸ਼ ਨਾਲੋ, ਸ਼ੈਅ, ਭਾਗਾਂ ਨੂੰ ਹੋਰ ਵਿਗਾੜਦੀ ਨਹੀਂ । ਰੂਪ, ਵੇਦਨਾ, ਸੰਗਿਆ, ਸੰਸਕਾਰੋਂ, ਹੋਰ ਕੋਈ ਨਾ ਚੀਜ਼ ਦੁਖਦਾਈ ਹੋਵੇ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਵੱਧ ਨਿਰਵਾਣ ਨਾਲੋਂ, ਕੋਈ ਗੱਲ ਨਾ ਹੋਰ ਸੁਖਦਾਈ ਹੋਵੇ ।",
  "203": "ਮਿਲਦਾ ਨਹੀਂ ਸੰਸਾਰ ਦੇ ਵਿਚ ਕਿਧਰੇ, ਹੋਰ ਰੋਗ ਕੋਈ ਵੱਡਾ ਭੁੱਖ ਵਰਗਾ । ਦੁੱਖ ਹੋਰ ਨੇ ਜੱਗ ਤੇ ਬਹੁਤ ਸਾਰੇ, ਦੁੱਖ ਹੋਰ ਨਾ ਸੰਸੇ ਦੇ ਦੁੱਖ ਵਰਗਾ । ਸਾਧਕ ਜੋ ਵੀ ਸਮਝਿਆ ਸਾਰ ਤਾਈਂ, ਏਸ ਤੱਤ ਦਾ ਰੂਪ ਪਛਾਣਦਾ ਏ । ਓਹ ਭੁੱਲ ਭੁਲਾ ਕੇ ਹੋਰ ਖ਼ੁਸ਼ੀਆਂ, ਉੱਤਮ ਖ਼ੁਸ਼ੀ ਨਿਰਵਾਣ ਨੂੰ ਜਾਣਦਾ ਏ ।",
  "204": "ਏਸ ਗੱਲ ਦੇ ਵਿਚ ਨਾ ਸ਼ੱਕ ਕਾਈ, ਪਰਮ ਲਾਭ ਅਰੋਗਤਾ ਜਾਣ ਲਈਏ । ਪਰਮ-ਧਨ ਸੰਤੋਖ ਵਿਚ ਲੱਭਦਾ ਏ, ਏਸ ਤੱਤ ਦਾ ਰੂਪ ਪਛਾਣ ਲਈਏ । ਕਿਧਰੇ ਹੋਰ ਵਿਸ਼ਵਾਸ ਦੇ ਨਾਲ ਦਾ ਜੇ, ਦੁਨੀਆਂ ਵਿਚ ਨਾ ਸਾਕ ਸਰਬੰਸ ਹੁੰਦਾ । ਖ਼ੁਸ਼ੀਆਂ ਹੋਰ ਨਿਰਵਾਣ ਤੋਂ ਸਭ ਹੇਠਾਂ, ਉਸ ਦੇ ਵਿਚ ਹੈ ਮਹਾਂ ਆਨੰਦ ਹੁੰਦਾ ।",
  "205": "ਧਿਆਨ ਮਗਨ ਇਕਾਂਤ ਵਿਚ ਬੈਠ ਕੋਈ, ਪਰਮ ਸ਼ਾਂਤੀ ਰਸ ਨੂੰ ਪੀਂਵਦਾ ਏ । ਓਹਦੇ ਦੁੱਖ ਤੇ ਡਰ ਕਾਫ਼ੂਰ ਹੁੰਦੇ, ਮੰਗਲ, ਸੁੱਖ ਦੇ ਨਾਲ ਉਹ ਜੀਂਵਦਾ ਏ । ਜਿਹੜਾ ਧਰਮ ਉਪਦੇਸ਼ ਦਾ ਰਸ ਪੀਵੇ, ਨਾਲੇ ਜਿਸ ਨੂੰ ਸਬਰ ਕਰਾਰ ਹੁੰਦਾ । ਉਹਦੇ ਪਾਪ ਕਲੇਸ਼ ਨੇ ਹਰੇ ਜਾਂਦੇ, ਬੇੜਾ ਓਸ ਦਾ ਭਵਜਲੋਂ ਪਾਰ ਹੁੰਦਾ ।",
  "206": "ਦਰਸ਼ਣ ਸੱਜਣਾਂ ਦੇ ਉੱਤਮ ਗੱਲ ਹੁੰਦੀ, ਰਹਿਣ ਉਹਨਾਂ ਦੇ ਨਾਲ ਮਸ਼ਹੂਰ ਹੋਣਾ । ਮੱਥੇ ਕਦੇ ਵੀ ਮੂੜ੍ਹ ਦੇ ਲੱਗੀਏ ਨਾ, ਉਹ ਤਾਂ ਹੁੰਦਾ ਹੈ ਖ਼ੁਸ਼ੀ ਤੋਂ ਦੂਰ ਹੋਣਾ ।",
  "207": "ਤੁਰੀਏ ਮੂੜ੍ਹ ਦੇ ਨਾਲ ਤਾਂ ਦੁੱਖ ਪਾਈਏ, ਵਾਂਗਰ ਵੈਰੀਆਂ ਮੂੜ੍ਹ ਦਾ ਸੰਗ ਕਰਦਾ । ਰੱਖੇ ਕੋੜਮੇ ਵਾਂਗਰਾਂ ਖ਼ੁਸ਼ੀ ਹਰਦਮ, ਬੁੱਧੀਵਾਨ ਦਾ ਸੰਗ ਨਾ ਤੰਗ ਕਰਦਾ ।",
  "208": "ਇਸੇ ਕਰਕੇ ਗਿਆਨੀਆਂ ਪਾਸ ਜਾਈਏ, ਬੜੇ ਸੰਜਮੀ ਤੇ ਸ਼ੀਲਵਾਨ ਜਿਹੜੇ । ਜਿਨ੍ਹਾਂ ਸਾਧਿਆ ਆਪਣੀ ਜ਼ਿੰਦਗੀ ਨੂੰ, ਸਾਊ, ਪਾਰਸਾਂ, ਨੇਕ ਇਨਸਾਨ ਜਿਹੜੇ । ਖ਼ੁਸ਼ੀਆਂ ਸੱਚੀਆਂ ਹੋਣ ਤੇ ਸੁੱਖ ਮਿਲਦਾ, ਕਰੀਏ ਭਾਲ ਜੇ ਇਸ ਤਰ੍ਹਾਂ ਸਾਰਿਆਂ ਦੀ । ਜਿਵੇਂ ਚੰਦ ਅਸਮਾਨ ਵਿਚ ਫਿਰੇ ਭਉਂਦਾ, ਉਪਰ ਪੈੜ ਨਛਤਰਾਂ ਤਾਰਿਆਂ ਦੀ ।",
  "chap16": "ਪਿਯ",
  "209": "ਕੰਮਾਂ ਮੰਦਿਆਂ ਵਿਚ ਗ਼ਲਤਾਨ ਹੋ ਕੇ, ਮੁੱਖ ਚੰਗਿਆਂ ਕੰਮਾਂ ਤਂ ਮੋੜਦਾ ਜੋ । ਮਾਰਗ ਸੱਚਾ ਪਰਮਾਰਥ ਦਾ ਛੱਡ ਕੇ ਤੇ ਸੁਰਤ ਨਾਲ ਸੰਸਾਰ ਦੇ ਜੋੜਦਾ ਜੋ । ਉਸ ਨੂੰ ਚਾਹੀਦਾ ਹੈ, ਤਿਆਗ ਮੋਹ ਮਾਇਆ, ਰਾਹ ਪਾਪ ਦੇ ਤੋਂ ਪਿੱਛੇ ਮੁੜ ਜਾਏ । ਹੋਵੇ ਵੱਸ ਜਿਸ ਆਪਣਾ ਆਪ ਕੀਤਾ, ਓਸ ਆਦਮੀ ਦੇ ਨਾਲ ਜੁੜ ਜਾਏ ।",
  "210": "ਕਰਨਾ ਮਾੜਾ ਹੈ ਸੰਗ ਪਿਆਰਿਆਂ ਦਾ, ਉਸ ਵਿਚੋਂ ਹੈ ਸਦਾ ਹੀ ਦੁੱਖ ਮਿਲਦਾ । ਕਰੀਏ ਸੰਗ ਜੇਕਰ ਦੁਪਿਆਰਿਆਂ ਦਾ, ਉਸ ਵਿਚੋਂ ਵੀ ਕਦੇ ਨਾ ਸੁੱਖ ਮਿਲਦਾ । ਬੜੀ ਆਦਮੀ ਪੀੜ ਮਨਾਉਂਦਾ ਏ, ਵਿੱਛੜ ਜਾਏ ਜੇ ਸਾਥ ਪਿਆਰਿਆਂ ਦਾ । ਉਹ ਵੀ ਬੜਾ ਹੀ ਦੁੱਖ ਦਾ ਬਣੇ ਕਾਰਨ, ਪਏ ਸੰਗ ਕਰਨਾ ਦੁਪਿਆਰਿਆਂ ਦਾ ।",
  "211": "ਇਸੇ ਕਰਕੇ ਪਿਆਰੀਆਂ ਸੂਰਤਾਂ ਨਾਲ, ਕਦੇ ਭੁੱਲ ਨਾ ਮੋਹ ਪਿਆਰ ਪਾਈਏ । ਕਿਉਂਕਿ ਦੁੱਖ ਵਿਜੋਗ ਦਾ ਬੜਾ ਡੂੰਘਾ, ਇਹ ਤੱਥ ਨਾ ਕਦੇ ਵਿਸਾਰ ਜਾਈਏ । ਓਹੀ ਪੁਰਸ਼ ਖ਼ੁਸ਼ਹਾਲ ਨਿਹਾਲ ਰਹਿੰਦਾ, ਉਸ ਨੂੰ ਕੋਈ ਕਲੇਸ਼ ਨਾ ਮਾਰਦਾ ਏ । ਬੰਧਨ ਮੋਹ ਪਿਆਰ ਦੇ ਨਹੀਂ ਪਾਉਂਦਾ, ਨਾ ਹੀ ਕਿਸੇ ਨੂੰ ਉਹ ਦੁਰਕਾਰਦਾ ਏ ।",
  "212": "ਮਿਲਦਾ ਦੁੱਖ ਹੈ ਸਦਾ ਪਿਆਰਿਆਂ ਤੋਂ, ਡਰ ਵੀ ਓਹਨਾਂ ਤੋਂ ਸਦਾ ਉਤਪੰਨ ਹੁੰਦਾ । ਮੁਕਤ ਹੋਇਆ ਜੋ ਮੋਹ ਤੋਂ ਪਿਆਰਿਆਂ ਦੇ, ਓਹੀ ਸੁਖੀ, ਨਿਰਭੈ ਪਰਸੰਨ ਹੁੰਦਾ ।",
  "213": "ਚਾਹਤ, ਪਿਆਰ ਤਾਂ ਸਦਾ ਹੀ ਦੁਖਦਾਇਕ, ਨਾਲੇ ਉਪਜਦਾ ਉਹਨਾਂ ਤੋਂ ਡਰ ਵੀ ਹੈ । ਜਿਸ ਨੇ ਤੋੜਿਆ ਮੋਹ ਦੇ ਬੰਧਨਾਂ ਨੂੰ, ਡਰ, ਦੁੱਖ ਤੋਂ ਓਹ ਬਾਲਾ-ਤਰ ਵੀ ਹੈ ।",
  "214": "ਬਾਹਲਾ ਕਿਸੇ ਦੇ ਨਾਲ ਨਾ ਤੇਹ ਕਰੀਏ, ਪੈਦਾ ਓਸ ਤੋਂ ਭੈਅ ਤੇ ਦੁੱਖ ਹੋਵੇ । ਜਿਹੜੇ ਪੁਰਸ਼ ਨੂੰ ਤੇਹ ਤੋਂ ਮਿਲੇ ਮੁਕਤੀ, ਦੁੱਖ ਭੈਅ ਬਿਨਸੇ ਸਦਾ ਸੁੱਖ ਹੋਵੇ ।",
  "215": "ਕਾਮ ਵਾਸ਼ਨਾ ਸਦਾ ਹੈ ਦੁਖਦਾਈ, ਕਾਮੀ ਪੁਰਸ਼ ਨੂੰ ਮਾਰਦਾ ਡਰ ਰਹਿੰਦਾ । ਕਾਮ-ਮੁਕਤ ਹੋਇਆਂ, ਦੁੱਖ, ਭੈਅ ਬਿਨਸੇ, ਪ੍ਰਾਣੀ ਸੁੱਖ ਆਨੰਦ ਦੇ ਘਰ ਰਹਿੰਦਾ ।",
  "216": "ਤ੍ਰਿਸ਼ਨਾ, ਕਾਮਨਾ ਸੋਗ ਦਾ ਮੂਲ ਸਮਝੋ, ਤ੍ਰਿਸ਼ਨਾ ਸਦਾ ਉਪਜਾਉਂਦੀ ਡਰ ਵੀ ਹੈ । ਤ੍ਰਿਸ਼ਨਾ ਮਾਰਿਆਂ ਸੋਗ ਤੇ ਭੈਅ ਬਿਨਸੇ, ਮਿਲਦਾ ਰਹਿਣ ਨੂੰ ਸੁੱਖਾਂ ਦਾ ਘਰ ਵੀ ਹੈ ।",
  "217": "ਸੀਲਵਾਨ, ਸਮਦਰਸੀ ਤੇ ਸਦਾਚਾਰੀ, ਸੱਚ ਬੋਲਦਾ ਜੋ ਫ਼ਰਜ਼ ਪਾਲਦਾ ਏ । ਐਸੇ ਧਰਮੀ ਨੂੰ ਲੋਕ ਪਿਆਰ ਕਰਦੇ, ਸਦਾ ਸਮਝਦੇ 'ਆਪਣੇ ਨਾਲ ਦਾ ਏ' ।",
  "218": "ਜੀਹਦੇ ਅੰਦਰੋਂ ਉਪਜੀ ਹੈ ਅਭਿਲਾਸ਼ਾ, 'ਮਿਲ ਮੈਨੂੰ ਅਕੱਥ ਨਿਰਵਾਣ ਜਾਏ' । ਮਨ ਕੁੰਗੂ ਦੇ ਵਾਂਗਰਾਂ ਸਾਫ਼ ਜਿਸ ਦਾ, ਪਦਵੀ ਉੱਚੀ ਨੂੰ ਪਹੁੰਚ ਇਨਸਾਨ ਜਾਏ । ਜਿਹਨੂੰ ਵਿਸ਼ੇ-ਵਿਕਾਰਾਂ ਨੇ ਬੰ੍ਹਨਿਆ ਨਹੀਂ, ਰਹੇ ਮਸਤ ਜੋ ਧਰਮ-ਧਿਆਨ ਅੰਦਰ । ਤਰਦਾ ਜਾਏ ਓਹ ਉਪਰ ਸਰੋਤ ਵੱਲ ਨੂੰ, ਲਹਿਰਾਂ ਮਾਰਦੇ ਵਹਿਣ ਨਿਰਵਾਣ ਅੰਦਰ ।",
  "219": "ਜਿਵੇਂ ਦੂਰ ਪਰਦੇਸ ਤੋਂ ਚਿਰਾਂ ਪਿੱਛੋਂ, ਕੋਈ ਸੁੱਖੀ ਸਾਂਦੀ ਘਰੀਂ ਆਉਂਦਾ ਏ । ਚਾਅ ਚੜ੍ਹ ਜਾਂਦੇ ਸਾਕਾਂ ਮਿੱਤਰਾਂ ਨੂੰ, ਹਰ ਇਕ ਉਸ ਨੂੰ ਜੱਫੀਆਂ ਪਾਉਂਦਾ ਏ ।",
  "220": "ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਨੇਕ ਕਮਾਈ ਵਾਲੇ, ਜਿਸ ਵੇਲੇ ਪਰਲੋਕ ਸਿਧਾਰਦੇ ਨੇ । ਖ਼ੁਸ਼ੀਆਂ ਨਾਲ ਅੱਗੋਂ ਪੁੰਨ ਲੈਣ ਆਉਂਦੇ, ਕਰਨ ਪੁਸ਼ਪ-ਵਰਖਾ, ਪਾਣੀ ਵਾਰਦੇ ਨੇ ।",
  "chap17": "ਕੋਧ",
  "221": "ਜਿਹੜਾ ਬਸ਼ਰ ਕ੍ਰੋਧ ਨੂੰ ਕਰੇ ਕਾਬੂ, ਨਾਲੇ ਵੱਸ ਜੋ ਗਰਬ ਹੰਕਾਰ ਕਰਦਾ । ਤੋੜ ਤਾੜ ਕੇ ਸਾਰਿਆਂ ਬੰਧਨਾਂ ਨੂੰ, ਸੱਭੇ ਔਖੀਆਂ ਘਾਟੀਆਂ ਪਾਰ ਕਰਦਾ । ਨਹੀਂ ਰੂਪ, ਪਰਸਿੱਧੀ ਤੇ ਰੀਝਦਾ ਜੋ, ਪੱਲੇ ਰਿਜਕ ਜਾਂ ਮਾਲ ਨੂੰ ਬੰਨ੍ਹਦਾ ਨਹੀਂ । ਸਦਾ ਸੁੱਖੀ ਸੁਹੇਲੜਾ ਥੀ ਜਾਏ, ਉਸ ਨੂੰ ਦੁੱਖ ਫਿਰ ਮਾਰਦਾ ਭੰਨਦਾ ਨਹੀਂ ।",
  "222": "ਮੂੰਹ-ਜ਼ੋਰ ਘੋੜੇ ਜੁੱਤੇ ਰੱਥ ਅੱਗੇ, ਨੱਸੇ ਜਾਣ ਜਿਉਂ ਕੋਈ ਤੂਫ਼ਾਨ ਆਉਂਦਾ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਆਪੇ ਤੋਂ ਬਾਹਰ ਹੋਵੇ, ਗੁੱਸੇ ਵਿਚ ਹੈ ਜਦੋਂ ਇਨਸਾਨ ਆਉਂਦਾ । ਜਿਹੜਾ ਦੌੜਦਾ ਗੁੱਸੇ ਦਾ ਰੱਥ ਥੰਮੇ, ਓਹੀ ਅਸਲ ਦੇ ਵਿਚ ਰਥਵਾਨ ਸਮਝੋ । ਐਵੇਂ ਹੋਰ ਲਗਾਮਾਂ ਨੂੰ ਫਿਰਨ ਚੁੱਕੀ, ਏਸ ਪੱਖ ਤੋਂ ਨਿਰੇ ਨਾਦਾਨ ਸਮਝੋ ।",
  "223": "ਨਾਲ ਸ਼ਾਂਤੀ ਕ੍ਰੋਧ ਤੇ ਵਿਜੇ ਪਾਈਏ, ਲਈਏ ਮਾਰ ਬੁਰਿਆਈ, ਭਲਿਆਈ ਦੇ ਨਾਲ । ਜਿੱਤ ਲਈਏ ਕੰਜੂਸ ਨੂੰ ਦਾਨ ਕਰ ਕੇ, ਝੂਠ ਜਿੱਤੀਏ ਸਦਾ ਸਚਿਆਈ ਦੇ ਨਾਲ ।",
  "224": "ਭਾਵੇਂ ਕੋਲ ਥੋੜ੍ਹਾ, ਮੋੜੇ ਮੰਗਤਾ ਨਾ, ਸੱਚ ਬੋਲਦਾ, ਗੁੱਸੇ ਨੂੰ ਥੁੱਕਦਾ ਏ । ਇਹਨਾਂ ਤਿੰਨਾਂ ਹੀ ਥਾਵਾਂ ਤੇ ਖੜਾ ਜਿਹੜਾ, ਓਹੀ ਦੇਵਤੇ ਦੇ ਨੇੜੇ ਢੁੱਕਦਾ ਏ ।",
  "225": "ਜੋਗੀ ਜਿਨ੍ਹਾਂ ਨੇ ਕਾਂਇਆਂ ਨੂੰ ਸਾਧਿਆ ਹੈ, ਦਿੰਦੇ ਦੁੱਖ ਨਾ ਕਿਸੇ ਨੂੰ ਮਾਰਦੇ ਨੇ । ਪਾਉਣ ਓਹ ਅਬਿਨਾਸ ਨਿਰਵਾਣ ਪਦਵੀ, ਸਗਲੇ ਆਪਣੇ ਦੁੱਖ ਨਿਵਾਰਦੇ ਨੇ ।",
  "226": "ਆਲਸ ਦੂਰ ਕਰ ਸਦਾ ਚੇਤੰਨ ਰਹਿ ਕੇ, ਦਿਨੇ ਰਾਤ ਜੋ ਜੋਗ ਅਭਿਆਸ ਕਰਦੇ । ਸਗਲੇ ਪਾਪ ਨੇ ਓਹਨਾਂ ਦੇ ਹਰੇ ਜਾਂਦੇ, ਓਹੀ ਘਰ ਨਿਰਵਾਣ ਦੇ ਵਾਸ ਕਰਦੇ ।",
  "227": "ਇਹ ਧੁਰਾਂ ਤੋਂ ਗੱਲ ਹੈ ਅੱਜ ਦੀ ਨਾ, 'ਆਤੁਲ' ਰੱਖੀਏ ਇਹਨੂੰ ਵਿਚਾਰ ਅੰਦਰ । ਜਿਸ ਦੀ ਕੋਈ ਵੀ ਨਿੰਦਿਆ ਨਹੀਂ ਕਰਦਾ, ਐਸਾ ਪੁਰਖ ਨਾ ਕੋਈ ਸੰਸਾਰ ਅੰਦਰ ।",
  "228": "ਜਾਵੇ ਨਿੰਦਿਆ, ਚੁੱਪ ਵੀ ਬਹੇ ਜਿਹੜਾ, ਬਾਹਲਾ ਬੋਲਦਾ ਜੋ ਓਹਨੂੰ ਭੰਡਦੇ ਨੇ । ਜਿਹੜਾ ਸੰਜਮ ਹਿਸਾਬ ਦੇ ਨਾਲ ਬੋਲੇ, ਲੋਕੀਂ ਉਸ ਨੂੰ ਵੀ ਭੰਡਦੇ ਛੰਡਦੇ ਨੇ ।",
  "229": "ਜਿਸ ਦੀ ਜ਼ਿੰਦਗੀ ਵਿਚ ਨਾ ਖੋਟ ਕੋਈ, ਸ਼ੀਲਵਾਨ ਤੇ ਸੁੱਚਾ ਆਚਾਰ ਦਾ ਏ । ਪੰਡਤ ਲੋਕ ਵੀ ਜਾਣ ਕੇ ਕਰਨ ਉਪਮਾ, ਗਿਆਨੀ ਪੁਰਖ ਓਹ ਖਰਾ ਵਿਚਾਰ ਦਾ ਏ ।",
  "230": "ਖਰੇ ਸੋਨੇ ਦੀ ਮੋਹਰ ਨੂੰ ਕੌਣ ਨਿੰਦੇ, ਹਰ ਕੋਈ ਓਹਦੀ ਵਾਹ ਵਾਹ ਕਰਦਾ । ਹੋਰ ਦੇਵਤੇ ਰਹਿ ਗਏ ਇੱਕ ਪਾਸੇ, ਓਹਦੀ 'ਬ੍ਰਹਮਾ' ਵੀ ਸਿਫ਼ਤ-ਸਲਾਹ ਕਰਦਾ ।",
  "231": "ਬਚੀਏ ਸਦਾ ਸਰੀਰ ਦੇ ਦੁਰਾਚਾਰੋਂ, ਸੰਜਮ ਕਰ ਸਰੀਰ ਸੰਭਾਲੀਏ ਜੀ । ਕਰੀਏ ਨਾਲ ਸਰੀਰ ਨਾ ਕੰਮ ਮਾੜੇ, ਇਉਂ ਵਿਸ਼ੇ-ਵਿਕਾਰਾਂ ਨੂੰ ਟਾਲੀਏ ਜੀ ।",
  "232": "ਮੰਦੇ ਬੋਲ ਵਿਗਾੜ ਤੋਂ ਦੂਰ ਰਹੀਏ, ਸਦਾ ਨਾਲ ਸੰਜਮ ਮੂੰਹੋਂ ਬੋਲੀਏ ਜੀ । ਦੁਰਾਚਾਰ ਜ਼ਬਾਨ ਦਾ ਤਿਆਗ ਏਦਾਂ, ਸੁਖੀ ਜ਼ਿੰਦਗੀ ਦਾ ਰਸਤਾ ਟੋਲੀਏ ਜੀ ।",
  "233": "ਮਨ ਦੇ ਦੁਰ-ਆਚਰਣ ਤੋਂ ਸਦਾ ਬਚੀਏ, ਸਦਾ ਮਨ ਬੁਰਿਆਈਆਂ ਤੋਂ ਮੋੜਨਾ ਜੇ । ਇਹਨੂੰ ਮੰਦਿਆਂ ਕੰਮਾਂ ਤੋਂ ਮੋੜਕੇ ਤੇ, ਉੱਤਮ ਜ਼ਿੰਦਗੀ ਦੇ ਸੰਗ ਜੋੜਨਾ ਜੇ ।",
  "234": "ਕਾਂਇਆਂ ਸਾਧ ਲਈ ਜਿਨ੍ਹਾਂ ਸਿਆਣਿਆਂ ਨੇ, ਨਾਲੇ ਆਪਣੀ ਵੱਸ ਜ਼ਬਾਨ ਕਰ ਲਈ । ਮਨ ਉਹਨਾਂ ਨੇ ਆਪਣਾ ਨੱਥਿਆ ਹੈ, ਸੌਖੀ, ਸੁਖੀ ਹੈ ਆਪਣੀ ਜਾਨ ਕਰ ਲਈ ।",
  "chap18": "ਮਲ",
  "235": "ਪੀਲੇ ਪੱਤ ਵਾਂਗਰ ਤੇਰਾ ਰੰਗ ਲੱਥਾ, ਬੈਠ ਗਏ ਯਮਦੂਤ ਨੇ ਪਾ ਘੇਰਾ । ਪੱਲੇ ਬੰ੍ਹਨਿਆਂ ਰਾਹ ਦਾ ਖਰਚ ਨਹੀਂਓਂ, ਸਮਾਂ ਕੂਚ ਦਾ ਗਿਆ ਈ ਆ ਤੇਰਾ ।",
  "236": "ਵਾਂਗ ਪੰਡਤਾਂ ਘਾਲ ਕਮਾਈ ਕਰ ਕੇ, ਲੱਭੀਂ ਠਾਹਰ ਦੇ ਲਈ ਅਸਥਾਨ ਚੰਗਾ । ਧੋ ਲੈ, ਪਾਪਾਂ ਗੁਨਾਹਾਂ ਦੀ ਮੈਲ ਸਾਰੀ, ਮਿਲੇ ਮਰਤਬਾ ਓਸ ਜਹਾਨ ਚੰਗਾ ।",
  "237": "ਤੇਰੀ ਜ਼ਿੰਦਗੀ ਦੀ ਖੇਡ ਖ਼ਤਮ ਹੋਈ, ਕੀਤਾ ਪੇਸ਼ ਯਮਦੂਤਾਂ ਦਰਗਾਹ ਅੰਦਰ । ਖਰਚ ਮਾਲ ਨਾ ਬੰ੍ਹਨਿਆਂ ਤੂੰ ਪੱਲੇ, ਨਹੀਂ ਥਾਂ ਸਸਤਾਉਣ ਲਈ ਰਾਹ ਅੰਦਰ ।",
  "238": "ਜਾਗ ਏਸ ਪੜਾਅ ਤੇ ਪੁੱਜ ਕੇ ਵੀ, ਵਾਂਗ ਪੰਡਤਾਂ ਵਕਤ ਸੰਭਾਲ ਵੀਰਾ । ਧੋ ਲੈ, ਪਾਪਾਂ ਗੁਨਾਹਾਂ ਦੀ ਮੈਲ ਸਾਰੀ, ਜੰਮਣ ਮਰਨ ਦਾ ਜਾਏ ਜੰਜਾਲ ਵੀਰਾ ।",
  "239": "ਮੱਠੀ ਅੱਗ ਤੇ ਚਾਂਦੀ ਦਾ ਖੋਟ ਜਿੱਦਾਂ, ਫੂਕਾਂ ਮਾਰ ਸੁਨਿਆਰ ਉਤਾਰਦਾ ਏ । ਬੁੱਧੀਵਾਨ ਵੀ ਉਸ ਤਰ੍ਹਾਂ ਮੈਲ ਧੋ ਕੇ, ਮਨ ਆਪਣਾ ਸਦਾ ਨਿਖਾਰਦਾ ਏ ।",
  "240": "ਹੋ ਕੇ ਲੋਹੇ ਦੇ ਵਿਚੋਂ ਜੰਗਾਲ ਪੈਦਾ, ਓਸੇ ਲੋਹੇ ਨੂੰ ਖੁਰਚਦਾ ਖਾਰਦਾ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਕੁਰਾਹੀਏ ਕੁ-ਹੱਢ ਤਾਈਂ, ਉਹਦਾ ਆਪਣਾ ਪਾਪ ਹੀ ਮਾਰਦਾ ਏ ।",
  "241": "ਪਾਠ ਨਾ ਕਰਿਆਂ, ਮੰਤਰ ਹੋਣ ਮੈਲੇ, ਮੈਲਾ ਘਰ ਜੇ ਝਾੜ-ਬੁਹਾਰੀਏ ਨਾ । ਪਹਿਰੇਦਾਰ ਨੂੰ ਮੈਲ ਹੈ ਗ਼ਾਫ਼ਲੀ ਦੀ, ਮੈਲੀ ਵਸਤ ਜੇ ਵਰਤ ਉਜਿਆਰੀਏ ਨਾ ।",
  "242": "ਮੈਲੀ ਇਸਤਰੀ ਜੋ ਦੁਰਾਚਾਰ ਕਰਦੀ, ਹੋਵੇ ਨਾਲ ਕੰਜੂਸੀ ਦੇ ਦਾਨ ਮੈਲਾ । ਖੋਟੇ ਧਰਮ ਕਾਰਨ ਦੁਨੀਆਂ ਏਹ ਮੈਲੀ, ਓਹਦੇ ਨਾਲ ਹੀ ਅਗਲਾ ਜਹਾਨ ਮੈਲਾ ।",
  "243": "ਦਸੇ ਉਪਰ ਜੋ ਖੋਟ ਨੇ ਬੜੇ ਮਾੜੇ, ਸ਼ੱਕ ਇਹਦੇ ਵਿਚ ਰਤੀ ਰਵਾਲ ਦਾ ਨਹੀਂ । ਹੁੰਦਾ ਖੋਟ ਜੋ ਮਗਰ ਅਵਿੱਦਿਆ ਦਾ, ਮਾੜਾ ਕੋਈ ਵੀ ਓਸ ਦੇ ਨਾਲ ਦਾ ਨਹੀਂ । ਭਿਖਸ਼ੂ ਸੱਜਣੋ ! ਬੰ੍ਹ ਕੇ ਗੱਲ ਪੱਲੇ, ਪ੍ਰੱਣ ਚਿੱਤ ਅੰਦਰ ਇਹੋ ਧਾਰਨਾ ਜੇ । ਕਰਕੇ ਦੂਰ ਅਵਿੱਦਿਆ ਆਪਣੀ ਨੂੰ, ਮਨੋ ਖੋਟ ਤੇ ਮੈਲ ਉਤਾਰਨਾ ਜੇ ।",
  "244": "ਜਿਨ੍ਹਾਂ ਘੋਟ ਕੇ ਪੀ ਲਿਆ ਲੱਜਿਆ ਨੂੰ, ਜੀਣਾ ਉਹਨਾਂ ਲਈ ਬੜਾ ਅਸਾਨ ਹੋਵੇ । ਉਹ ਵੀ ਨਾਲ ਆਰਾਮ ਦੇ ਜੱਗ-ਜੀਵੇ, ਬਕੜਵਾਹ ਕਰਦਾ, ਆਕੜ ਖਾਨ ਹੋਵੇ । ਕਾਂਵਾਂ ਵਾਂਗ ਸੁਆਰਥੀ ਸੂਰਮੇ ਜੋ, ਵਿਚ ਜ਼ਿੰਦਗੀ ਉਹਨਾਂ ਦੀ ਸ਼ਾਨ ਹੁੰਦੀ । ਏਥੇ ਲਾਲੀਆਂ ਚੜ੍ਹਨ ਅਧਰਮੀਆਂ ਨੂੰ, ਪਤਿਤ, ਪਾਪੀਆਂ ਦੀ ਸੌਖੀ ਜਾਨ ਹੁੰਦੀ ।",
  "245": "ਸਦਾ ਸ਼ਰਮ ਹਯਾ ਨੂੰ ਪਾਲਦਾ ਜੋ, ਉਹਦੀ ਜ਼ਿੰਦਗੀ ਬੜੀ ਦੁਸ਼ਵਾਰ ਹੋਵੇ । ਉੱਪਰ ਕੰਡਿਆਂ ਦੇ ਰਹਿੰਦਾ ਲੇਟਦਾ ਉਹ, ਜੀਹਦਾ ਸੱਚ ਦੇ ਨਾਲ ਵਿਹਾਰ ਹੋਵੇ । ਮਿੱਠ-ਬੋਲੜਾ, ਦੀਨ ਤੇ ਨੇਕ, ਸਾਊ, ਜੀਹਦਾ ਨਾਲ ਹੰਕਾਰ ਦੇ ਵਾਸਤਾ ਨਹੀਂ । ਉਹਦੀ ਜ਼ਿੰਦਗੀ ਮੁਸ਼ਕਿਲਾਂ ਵਿਚ ਗੁਜ਼ਰੇ, ਕਦੇ ਸੌਖ ਦੇ ਨਾਲ ਆਰਾਸਤਾ ਨਹੀਂ ।",
  "246": "ਜੀਵ ਹੱਤਿਆ ਕਰੇ ਤੇ ਝੂਠ ਬੋਲੇ, ਖਾਂਦਾ ਰਹੇ ਪਰਾਇਆਂ ਦਾ ਮਾਲ ਜਿਹੜਾ । ਯਾਰੀ ਲਾ, ਬਗਾਨੀਆਂ ਨਾਰੀਆਂ ਨੂੰ, ਫਿਰਦਾ ਬਗਲ ਦੇ ਵਿਚ ਲੈ ਨਾਲ ਜਿਹੜਾ ।",
  "247": "ਨਸ਼ਿਆਂ, ਦਾਰੂਆਂ ਨਾਲ ਜੋ ਧੁੱਤ ਹੋ ਕੇ, ਰਹਿੰਦਾ ਝੂਮਦਾ ਥਿੜਕਦਾ ਡੋਲਦਾ ਏ । ਜੜ੍ਹ ਆਪਣੀ ਏਸ ਜਹਾਨ ਅੰਦਰ, ਹੱਥੀਂ ਆਪਣੀ ਕੱਟਦਾ, ਫੋਲਦਾ ਏ ।",
  "248": "ਓਏ ਭਲੇ ਪੁਰਖਾ ! ਸੁਣੀ ਧਿਆਨ ਧਰਕੇ, ਏਸ ਗੱਲ ਨੂੰ ਮਨੋਂ ਨਾ ਟਾਲਣਾ ਈਂ । ਖੋਟੇ ਧਰਮ ਦੇ ਝੂਠੇ ਵਿਸ਼ਵਾਸ ਜਿਹੜੇ, ਜੀਵਨ ਉਹਨਾਂ ਦੇ ਪੰਧ ਨਾ ਗਾਲਣਾ ਈਂ । ਸੰਜਮ-ਹੀਣ ਕੁਕਰਮਾਂ ਨੂੰ ਜਾਣ ਲੈਣਾ, ਲਬ, ਲੋਭ ਤੇ ਪਾਪ ਤਿਆਗਣਾ ਈਂ । ਇਹਨਾਂ ਮਾੜਿਆਂ ਧੰਦਿਆਂ ਵਿਚ ਪੈ ਕੇ, ਐਵੇਂ ਦੁੱਖ ਨਾ ਪਿਆਰਿਆ ਝਾਗਣਾ ਈਂ ।",
  "249": "ਖ਼ੁਸ਼ੀ ਨਾਲ ਵਿਸ਼ਵਾਸ ਅਨੁਸਾਰ ਕੋਈ, ਜਿੰਨਾ ਹੋ ਸਕੇ ਹਥੋਂ ਦਾਨ ਕਰਦਾ । ਜਰੇ ਵੇਖ ਨਾ ਖਾਂਦਿਆਂ ਪੀਂਦਿਆਂ ਨੂੰ, ਨਿਸਦਿਨ ਆਪਣਾ ਚੈਨ ਵੀਰਾਨ ਕਰਦਾ ।",
  "250": "ਏਸ ਤਰ੍ਹਾਂ ਦੀ ਲਾਲਚੀ ਮਨੋਬਿਰਤੀ, ਜੋ ਵੀ ਜੜ੍ਹਾਂ ਤੋਂ ਧੂਹ ਕੇ ਮਾਰਦਾ ਏ । ਨਿਸ ਦਿਨ ਓਸ ਨੂੰ ਚੈਨ ਕਰਾਰ ਆਏ, ਇਉਂ ਆਪਣਾ ਕਾਜ ਸਵਾਰਦਾ ਏ ।",
  "251": "ਹੋਰ ਲਾਲਸਾ ਵਾਂਗ ਨਾ ਅੱਗ ਕੋਈ, ਜਿਹੜੀ ਰੂਹ ਤੇ ਜਿਸਮ ਨੂੰ ਸਾੜਦੀ ਏ । ਨਫ਼ਰਤ ਨਾਲ ਦਾ ਹੋਰ ਗਰੱਹੁ ਕੋਈ ਨਾ, ਘੁੱਗ ਵੱਸਦੇ ਘਰ ਉਜਾੜਦੀ ਏ । ਤ੍ਰਿਸ਼ਨਾ ਵਾਂਗ ਨਾ ਬਹੇ ਦਰਿਆ ਕਿਧਰੇ, ਸਾਰੇ ਪਾਸਿਆਂ ਨੂੰ ਢਾਹ ਲਾਈ ਜਾਏ । ਮਾਇਆ ਮੋਹ ਸਮਾਨ ਨਾ ਜਾਲ ਕੋਈ, ਹਰ ਪ੍ਰਾਣੀ ਨੂੰ ਫਾਹੇ ਫਸਾਈ ਜਾਏ ।",
  "252": "ਹੋਵੇ ਅੱਖ ਦੇ ਵਿਚ ਸ਼ਹਿਤੀਰ ਫਸਿਆ, ਆਪਣੇ ਆਪ ਨੂੰ ਨਜ਼ਰ ਨਹੀਂ ਆ ਸਕਦਾ । ਤਿਲ ਦੂਜੇ ਦੀ ਅਖ ਵਿਚ ਜ਼ਰਾ ਮਾਸਾ, ਸੌਖਾ ਓਸ ਨੂੰ ਵੇਖਿਆ ਜਾ ਸਕਦਾ । ਦੋਸ਼ ਵੇਖ ਕੇ ਆਦਮੀ ਦੂਜਿਆਂ ਦੇ, ਤੂੜੀ ਮਿੱਟੀ ਦੇ ਵਾਂਗ ਉਡਾਉਂਦਾ ਏ । ਦੋਸ਼ ਆਪਣੇ ਵਾਂਗ ਜੁਆਰੀਆਂ ਦੇ, ਖਚਰੀ 'ਚਾਲ' ਦੇ ਵਾਂਗ ਲੁਕਾਉਂਦਾ ਏ ।",
  "253": "ਦੋਸ਼ ਤਾੜਦਾ ਰਹੇ ਜੋ ਹੋਰਨਾਂ ਦੇ, ਨੁਕਸ-ਬੀਨੀਆਂ ਨਾਲ ਜੋ ਵਾਹ ਰੱਖੇ । ਝਾੜ ਸੁਣਦਿਆਂ ਸਾਰ ਜੋ ਪਏ ਕਾਹਲਾ, ਬਾਹਲਾ ਚਿੜਚਿੜਾ ਜਿਹੜਾ ਸੁਭਾਅ ਰੱਖੇ । ਐਸੇ ਪੁਰਸ਼ ਦਾ ਜਾਣੀਏ ਚਿੱਤ ਹਰਦਮ, ਪਾਪ-ਮੈਲ ਦੇ ਨਾਲ ਭਰਪੂਰ ਰਹਿੰਦਾ । ਮੰਦੇ ਕਰਮਾਂ ਦੇ ਵਿਚ ਓਹ ਰਹੇ ਫਾਥਾ, ਸਦਾ ਪਾਪ-ਵਿਨਾਸ਼ ਤੋਂ ਦੂਰ ਰਹਿੰਦਾ ।",
  "254": "ਨਹੀਂ ਰਾਹ ਅਕਾਸ਼ ਦੇ ਵਿਚ ਕੋਈ, ਬੋਧੀ ਪੰਥ ਤੋਂ ਬਾਹਰ ਵਿਰੱਕਤ ਕਿੱਥੇ ? ਹੋਰ ਲੋਕ ਪਰਪੰਚਾਂ ਦੇ ਵਿਚ ਰੁਝੇ, ਤਥਾਗਤਾਂ ਨੂੰ ਏਸ ਲਈ ਵਕਤ ਕਿੱਥੇ ।",
  "255": "ਨਹੀਂ ਰਾਹ ਅਕਾਸ਼ ਦੇ ਵਿਚ ਜਿੱਦਾਂ, ਬੋਧੀ ਪੰਥ ਤੋਂ ਸ਼ਾਖ ਨਾ ਬਾਹਰ ਕੋਈ । ਕਦੇ ਬੁੱਧ ਨਾ ਬੁੱਧਾਂ ਦੀ ਹੋਏ ਚੰਚਲ, ਅਸਥਿਰ ਓਹਨਾਂ ਦਾ ਨਾ ਸੰਸਕਾਰ ਕੋਈ ।",
  "chap19": "ਧੰਮੱਠ",
  "256": "ਐਵੇਂ ਕਿਸੇ ਨੂੰ ਬਿਨਾਂ ਵਿਚਾਰਿਆਂ ਦੇ, ਜੇਕਰ ਗੱਲ ਇਨਸਾਫ਼ ਦੀ ਸੁੱਝ ਜਾਏ । ਉਹ ਨਾ ਮੁਨਸਫ਼ ਧਰਮਾਤਮਾ ਹੋ ਜਾਂਦਾ, ਨਾ ਹੀ ਸੱਚ ਦੇ ਰਾਹ ਨੂੰ ਬੁੱਝ ਜਾਏ ।",
  "257": "ਅਸਲ ਵਿਚ ਧਰਮਾਤਮਾ ਓਹ 'ਸਿਆਣਾ', ਝੂਠ, ਸੱਚ ਵਿਚਾਰ ਨਿਤਾਰਦਾ ਏ । ਸ਼ਾਂਤ ਚਿੱਤ, ਨਿਰਪੱਖ, ਸੁਚੇਤ ਹੋ ਕੇ, ਜਿਹੜਾ ਹੋਰਾਂ ਨੂੰ ਪਾਰ ਉਤਾਰਦਾ ਏ ।",
  "258": "ਜਿਹੜਾ ਕੋਈ ਵੀ ਬੋਲਦਾ ਰਹੇ ਬਾਹਲਾ, ਗੱਲ ਸੋਚਦਾ ਅਤੇ ਵਿਚਾਰਦਾ ਨਹੀਂ । ਉਹਦਾ ਹੋਏ ਪ੍ਰਭਾਵ ਨਾ ਰਤਾ ਮਾਸਾ, ਪਤਿਤ ਸਮਝਕੇ ਕੋਈ ਸਤਕਾਰਦਾ ਨਹੀਂ । ਜਿਹੜਾ ਕਿਸੇ ਦੇ ਨਾਲ ਨਾ ਵੈਰ ਕਰਦਾ, ਸਹਿਣ-ਸ਼ੀਲ, ਨਿਰਭੈ ਨਿਝੱਕ ਹੁੰਦਾ । ਹੋਵੇ ਸਬਰ, ਸੰਤੋਖ ਦੇ ਨਾਲ ਰਹਿੰਦਾ, ਉਹਨੂੰ ਪੰਡਤ ਕਹਾਉਣ ਦਾ ਹੱਕ ਹੁੰਦਾ ।",
  "259": "ਧਰਮਵਾਨ ਨਾ ਸਮਝੀਏ ਓਸ ਤਾਈਂ, ਕਿਉਂਕਿ ਪੁਰਖ ਕੋਈ ਬਾਹਲਾ ਬੋਲਦਾ ਏ । ਐਪਰ ਕੋਈ ਜੋ ਥੋੜ੍ਹੀ ਵਿਚਾਰ ਕਰ ਕੇ, ਮਾਰਗ ਧਰਮ ਦਾ ਲੱਭਦਾ ਟੋਲਦਾ ਏ । ਕਾਂਇਆਂ ਆਪਣੀ ਧਰਮ ਅਨੁਸਾਰ ਸਾਧੇ, ਸਦਾ ਸੱਚ ਦਾ ਚੱਜ ਆਚਾਰ ਕਰਦਾ । ਕਰਕੇ ਗ਼ਾਫ਼ਲੀ, ਮੁੱਖ ਜੋ ਮੋੜਦਾ ਨਹੀਂ, ਧਰਮਧਾਰੀ ਉਹ ਧਰਮ ਵਿਹਾਰ ਕਰਦਾ ।",
  "260": "ਐਵੇਂ ਓਹਨੂੰ ਬਜੁਰਗ ਨਾ ਸਮਝ ਲਈਏ, ਸਿਰ ਕਿਸੇ ਦਾ ਹੋ ਜੇ ਜਾਏ ਧੌਲਾ । ਧੁੱਪੇ ਬੈਠ ਕੇ ਬਾਲ ਸਫ਼ੈਦ ਕੀਤੇ, ਲੋਕੀਂ ਉਹਦੇ ਸੰਬੰਧ ਵਿਚ ਪਾਉਣ ਰੌਲਾ ।",
  "261": "ਇਹਦੇ ਉਲਟ, ਜੋ ਸੱਚ ਦੇ ਤੁਰੇ ਮਾਰਗ, ਸੰਜਮ-ਸ਼ੀਲ, ਕਰ ਪਾਪ ਨਿਵਾਰਦਾ ਏ । ਇਹੋ ਜਿਹੇ ਅਹਿੰਸਾ ਦੇ ਨੇਮੀਆਂ ਨੂੰ, ਹਰ ਕੋਈ 'ਪੂਜ' 'ਬਜ਼ੁਰਗ' ਉਚਾਰਦਾ ਏ ।",
  "262": "ਹੋਵੇ ਝੂਠ, ਮੱਕਾਰੀ, ਬਦਨੀਤ ਪੱਲੇ, ਹਿਰਦਾ ਈਰਖਾ ਨਾਲ ਭਰਪੂਰ ਹੋਵੇ । ਸੁੰਦਰ ਮੁੱਖ ਭਾਵੇਂ ਵਕਤਾ ਹੋਏ ਸੋਹਣਾ, ਨਹੀਂ ਚੇਹਰੇ ਤੇ ਫੇਰ ਵੀ ਨੂਰ ਹੋਵੇ ।",
  "263": "ਜੋ ਵੀ ਅੰਦਰੋਂ ਇਹਨਾਂ ਬੁਰਿਆਂਈਆਂ ਨੂੰ, ਪੁੱਟ ਜੜ੍ਹਾਂ ਤੋਂ ਚਿੱਤ ਨਿਖਾਰਦਾ ਏ । ਓਹੀ ਪੁਰਖ ਹੈ ਸਾਧ-ਸਰੂਪ ਹੁੰਦਾ, ਨੂਰ ਮੁੱਖੜੇ ਤੇ ਡਲ੍ਹਕਾਂ ਮਾਰਦਾ ਏ ।",
  "264": "ਤ੍ਰਿਸ਼ਨਾ-ਲੋਭ ਦੇ ਜਾਲ ਵਿਚ ਜੋ ਫਸਿਆ, ਝੂਠ ਬੋਲਦਾ, 'ਬਚਨ' ਨੂੰ ਪਾਲਦਾ ਨਹੀਂ । ਸਿਰ ਤੇ ਉਸਤਰਾ ਫੇਰ ਕੇ ਹੋ ਜਾਂਦਾ, ਬੋਧੀ-ਸੰਗ ਵਿਰਕਤਾਂ ਦੇ ਨਾਲ ਦਾ ਨਹੀਂ ।",
  "265": "ਜਿਹੜਾ ਹੂੰਝ ਕੇ ਚਾਰ ਚੁਫੇਰ ਵਿਚੋਂ, ਛੋਟੇ, ਵੱਡਿਆਂ ਪਾਪਾਂ ਨੂੰ ਮਾਰਦਾ ਏ । ਬੋਧੀ-ਸੰਗ ਵਿਰਕਤ ਦਾ ਮਾਣ ਪਾਏ, ਦੁੱਖ, ਰੋਗ, ਸੰਤਾਪ ਨਿਵਾਰਦਾ ਏ ।",
  "266": "ਭਿਖਸ਼ੂ ਨਹੀਂ ਉਹ ਜੋ ਗੁਜ਼ਰਾਨ ਦੇ ਲਈ, ਦਰ ਦਰ ਤੋਂ ਭਿੱਖਿਆ ਮੰਗਦਾ ਏ । ਨਾ ਹੀ ਉਹ ਭਿਖਸ਼ੂ ਵਿਖਮ-ਧਰਮ ਅੰਦਰ, ਫਾਹੇ ਆਪਣੀ ਜਾਨ ਜੋ ਟੰਗਦਾ ਏ ।",
  "267": "ਅਸਲ ਵਿਚ ਤਾਂ ਜਾਣੀਏ ਉਹੀ ਭਿਖਸ਼ੂ, ਪੁੰਨ-ਪਾਪ ਦਾ ਸੰਗ ਤਿਆਗਦਾ ਜੋ । ਗਿਆਨੀ ਹੋਏ ਬ੍ਰਹਮਚਰਜ ਦਾ ਕਰੇ ਪਾਲਣ, ਕਰਦਾ ਆਲਸੀ ਨਾ ਸਦਾ ਜਾਗਦਾ ਜੋ ।",
  "268": "ਮੂੜ੍ਹ, ਸੱਖਣਾ ਗਿਆਨ ਤੇ ਵਿੱਦਿਆ ਤੋਂ, ਮੌਨ ਧਾਰਿਆਂ ਮੁਨੀ ਨਾ ਹੋ ਜਾਏ । ਪੰਡਤ ਪਕੜ ਇਨਸਾਫ਼ ਦਾ ਧਰਮ-ਕੰਡਾ, ਤੋਲਣ ਦੋਵੇਂ ਜਹਾਨ ਖਲੋ ਜਾਏ ।",
  "269": "ਨਾਲੇ ਉਹ ਗੁਨਾਹਾਂ ਤੋਂ ਕਰੇ ਤੋਬਾ, ਤੋਲ ਸੱਚ ਦਾ ਤੋਲ ਵਿਖਾਉਂਦਾ ਏ । ਐਸਾ ਤੋਲਾ ਹੀ ਅਸਲ ਵਿਚ ਮੁਨੀ ਹੁੰਦਾ, ਅਤੇ ਲੋਕਾਂ ਤੋਂ ਮੁਨੀ ਕਹਾਉਂਦਾ ਏ ।",
  "270": "ਕੋਈ ਆਦਮੀ ਹੋਰਨਾਂ ਪਰਾਣੀਆਂ ਨੂੰ, ਦਿੰਦਾ ਦੁੱਖ ਜਾਂ ਕੁਟਦਾ ਮਾਰਦਾ ਜੋ । ਉਹ ਤਾਂ ਆਰੀਆ ਪੁਰਸ਼ ਨਾ ਜਾਏ ਗਿਣਿਆ, ਮਾਲਕ ਹੁੰਦਾ ਅਜਿਹੇ ਕਿਰਦਾਰ ਦਾ ਜੋ । ਜੋ ਵੀ ਆਦਮੀ ਹੋਰਨਾਂ ਪਰਾਣੀਆਂ ਨੂੰ, ਦਿੰਦਾ ਦੁੱਖ ਨਾ ਕੁਟਦਾ ਮਾਰਦਾ ਏ । ਉਤਮ ਆਰੀਆ ਪੁਰਸ਼ ਉਹ ਜਾਏ ਗਿਣਿਆ, ਹਰ ਇਕ ਆਰੀਆ ਆਖ ਸਤਕਾਰਦਾ ਏ ।",
  "271": "ਸ਼ੀਲ ਵਰਤ ਆਚਰਨ ਤੇ ਨੇਮ ਸੰਜਮ, ਕਰਕੇ ਲੱਖ ਸਮਾਧੀਆਂ ਲਾਏ ਕੇ ਜੀ । ਸੌਂ ਕੇ ਸਦਾ ਇਕੱਲਿਆਂ ਕੁੰਜ ਗੋਸ਼ੇ, ਹੱਥ ਜੋੜ ਖ਼ਲੂਸ ਜਤਾਏ ਕੇ ਜੀ ।",
  "272": "'ਹੋਈ ਮੈਨੂੰ ਨਿਰਵਾਣ ਪ੍ਰਾਪਤੀ ਏ', ਫਿਰ ਵੀ ਇਉਂ ਵਿਚਾਰ ਵਿਚਾਰੀਏ ਨਾ । ਜਿੰਨਾ ਚਿਰ ਨਾ ਪਾਪਾਂ ਦਾ ਨਾਸ਼ ਹੋਵੇ, ਕਦੇ ਭਿਖਸ਼ੂਆ ! ਹੌਸਲਾ ਹਾਰੀਏ ਨਾ ।",
  "chap20": "ਮੱਗ",
  "273": "'ਅਸ਼ਟ-ਮਾਰਗ' ਸਰੇਸ਼ਟ ਹੈ ਸਾਰਿਆਂ ਤੋਂ, 'ਚਾਰ-ਆਰੀਯਾ' ਸੱਚ ਸਰੇਸ਼ਟ ਕਹੀਏ । ਧਰਮਾਂ ਵਿਚੋਂ ਵੈਰਾਗ ਦਾ ਧਰਮ ਵਧੀਆ, ਗਿਆਨੀ ਪੁਰਖ ਮਨੁੱਖਾਂ 'ਚੋਂ ਸਮਝ ਲਈਏ ।",
  "274": "ਇਹੋ ਗਿਆਨ ਦੀ ਸ਼ੁਧੀ ਲਈ ਇਕ ਮਾਰਗ, ਨਹੀਂ ਦੂਸਰਾ ਏਸ ਦੇ ਨਾਲ ਦਾ ਏ । ਭਿਖਸ਼ੂ ਸੱਜਣੋ ! ਏਸ ਦੀ ਸ਼ਰਨ ਆਓ, ਇਹੀ ਮਾਇਆ ਤੇ ਮਾਰਾ ਨੂੰ ਟਾਲਦਾ ਏ ।",
  "275": "ਹੋਵੇ ਦੁਖਾਂ ਕਲੇਸ਼ਾਂ ਦਾ ਅੰਤ ਸਮਝੋ, ਐਸੇ ਮਾਰਗ ਵਿਚ ਤੁਸੀਂ ਪਰਵੇਸ਼ ਕੀਤਾ । ਮਾਰਗ ਨਹੀਂ ਇਹ ਸੂਲਾਂ ਤੇ ਕੰਡਿਆਂ ਦਾ, ਇਸੇ ਲਈ ਮੈਂ ਸੱਚ ਉਪਦੇਸ਼ ਕੀਤਾ ।",
  "276": "'ਤਥਾ ਗਤ' ਉਪਦੇਸ਼ ਨੇ ਕਰਨ ਵਾਲੇ, ਜ਼ੋਰ ਤੁਸਾਂ ਨੇ ਭਿਖਸ਼ੂਓ ਮਾਰਨਾ ਏਂ । ਏਸ ਮਾਰਗ ਤੇ ਤੁਸਾਂ ਜਦ ਪੈਰ ਧਰਿਆ, ਮਾਇਆ ਮਾਰਨੀ ਦੁਖ ਨਿਵਾਰਨਾ ਏਂ ।",
  "277": "'ਛਿਨ-ਭੰਗਰ ਦੇ ਮਾਇਆ ਸੰਕਲਪ ਸਾਰੇ', ਜਦੋਂ ਤੱਤ ਗਿਆਨੀ ਪਛਾਣਦਾ ਏ । ਉਹਦੇ ਦੁੱਖ ਤੇ ਪਾਪ ਸਭ ਹਰੇ ਜਾਂਦੇ, ਮਾਰਗ ਲੱਭਦਾ ਪਰਮ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "278": "ਨਿਰਾ ਦੁੱਖ ਕਲੇਸ਼ ਸੰਕਲਪ ਸਾਰੇ, ਜਦੋਂ ਤੱਤ ਗਿਆਨੀ ਪਛਾਣਦਾ ਏ । ਓਸ ਪੁਰਖ ਸੁਜਾਨ ਨੂੰ ਮਿਲੇ ਮੁਕਤੀ, ਮਾਰਗ ਲੱਭਦਾ ਪਰਮ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "279": "ਜਦੋਂ ਰਾਹੀਂ ਗਿਆਨ ਦੇ ਪਏ ਸੋਝੀ, 'ਛਾਇਆ ਰੂਪ ਇਹ ਵਸਤੂਆਂ ਸਾਰੀਆਂ ਨੇ' । ਸਾਰੇ ਗੁਣ ਵੀ ਇਹਨਾਂ ਦੇ ਹਨ ਮਿਥਿਆ, ਤੰਦਾਂ ਮਾਇਆ ਨੇ ਜਿਵੇਂ ਪਸਾਰੀਆਂ ਨੇ । ਡੇਰਾ ਦੁੱਖ ਕਲੇਸ਼ ਦਾ ਉੱਠ ਜਾਏ, ਰਾਗ-ਮੁਕਤ ਹੈ ਉਹ ਇਨਸਾਨ ਹੁੰਦਾ । ਇਹੀ ਸੁੱਖ ਦਾ ਹੋਏ ਸਰੇਸ਼ਟ ਮਾਰਗ, ਇਹੀ ਅਸਲ ਵਿਚ ਪਰਮ ਨਿਰਵਾਣ ਹੁੰਦਾ ।",
  "280": "ਉੱਠ ਜਾਗਣੇ ਦਾ ਜਦੋਂ ਹੋਏ ਵੇਲਾ, ਜਿਹੜਾ ਆਦਮੀ ਉਠਦਾ ਜਾਗਦਾ ਨਹੀਂ । ਰਿਸ਼ਟ ਪੁਸ਼ਟ ਤੇ ਬਲੀ ਜਵਾਨ ਹੋ ਕੇ, ਆਲਸ ਨੇਸਤੀ ਜਿਹੜਾ ਤਿਆਗਦਾ ਨਹੀਂ । ਲਿੱਸਾ ਮਨ, ਕਮਜ਼ੋਰ ਵਿਚਾਰ ਜਿਸ ਦੇ, ਉਦਮ-ਹੀਣ, ਜੋ ਛਾਲ ਨਹੀਂ ਮਾਰ ਸਕਦਾ । ਮਾਰਗ ਉਹ ਨਿਰਵਾਣ ਦੇ ਕਦੇ ਤੁਰ ਕੇ, ਨਹੀਂ ਆਪਣੇ ਦੁੱਖ ਨਿਵਾਰ ਸਕਦਾ ।",
  "281": "ਮੂੰਹੋਂ ਸੋਚ ਵਿਚਾਰ ਕੇ ਗੱਲ ਕਰੀਏ, ਸੰਜਮ ਨਾਲ ਸੰਭਾਲੀਏ ਮਨ ਆਪਣਾ । ਪਾਪ ਕਰਮਾਂ ਤੋਂ ਸਦਾ ਸੰਕੋਚ ਕਰ ਕੇ, ਸਾਫ਼ ਮੈਲ ਤੋਂ ਰੱਖੀਏ ਤਨ ਆਪਣਾ । ਮਨ, ਬਚਨ ਤੇ ਕਰਮ ਨੇ ਤਿੰਨ ਮਾਰਗ, ਇਹਨਾਂ ਤਿੰਨਾਂ ਨੂੰ ਸਦਾ ਬੁਹਾਰਨਾ ਜੇ । ਇਉਂ ਦੱਸਿਆ ਬੁੱਧ ਨੇ ਜੋ ਮਾਰਗ, ਉਸ ਨੂੰ ਮੰਨਣਾ ਅਤੇ ਸਤਕਾਰਨਾ ਜੇ ।",
  "282": "ਸਿਰੜ ਨਾਲ ਜੇ ਯੋਗ ਅਭਿਆਸ ਕਰੀਏ, ਹਿਰਦੇ ਵਿਚ ਹੈ ਗਿਆਨ ਪਰਗਾਸ ਹੁੰਦਾ । ਜੇਕਰ ਯੋਗ ਅਭਿਆਸ ਨੂੰ ਛੱਡ ਦੇਈਏ, ਫੇਰ ਗਿਆਨ ਦਾ ਸੱਤਿਆਨਾਸ ਹੁੰਦਾ । ਨਾਸ ਅਤੇ ਵਿਕਾਸ ਦੇ ਇਹ ਮਾਰਗ, ਕਰ ਦੋਹਾਂ ਦੀ ਖੂਬ ਸਿਆਣ ਲਈਏ । ਫੇਰ ਇਹਨਾਂ ਤੇ ਇਸ ਤਰ੍ਹਾਂ ਪੈਰ ਧਰੀਏ, ਵਿਕਸਤ ਆਪਣਾ ਕਰ ਗਿਆਨ ਲਈਏ ।",
  "283": "ਜੰਗਲ ਕੱਟੀਏ ਸਾਰਾ ਹੀ ਖਾਹਿਸ਼ਾਂ ਦਾ, ਇੱਕ-ਇੱਕ ਦਰਖਤ ਦਾ ਵੱਢਣਾ ਕੀ । ਏਸ ਜੰਗਲ ਤੋਂ ਹੁੰਦਾ ਹੈ ਡਰ ਪੈਦਾ, ਏਸ ਜੰਗਲ ਨੂੰ ਵੱਢਣੋਂ ਛੱਡਣਾ ਕੀ । ਕੱਟ ਵੱਢ, ਉਖਾੜ ਕੇ ਵਣ ਸਾਰਾ, ਮੁਕਤ ਖਾਹਿਸ਼ਾਂ ਤੋਂ ਤੁਸੀਂ ਹੋ ਜਾਓ । ਜਿਹੜ ਡਰ ਸੀ ਆਉਂਦਾ ਖਾਹਿਸ਼ਾਂ ਤੋਂ, ਓਸ ਡਰ ਤੋਂ ਸੁਰਖਰੂ ਹੋ ਜਾਓ ।",
  "284": "ਜਿੰਨਾ ਚਿਰ ਵੀ ਪੁਰਸ਼ ਦੇ ਦਿਲ ਅੰਦਰ, ਰਾਈ ਭਰ ਰਹਿੰਦੀ ਤ੍ਰਿਸ਼ਨਾ ਨਾਰ ਦੀ ਏ । ਵਣ ਕੱਟਿਆਂ, ਜਿਵੇਂ ਇੱਕ ਰੁਖ ਬਾਕੀ, ਹੋਂਦ-ਕਾਮਨਾ ਓਸ ਦੀ ਮਾਰਦੀ ਏ । ਜਿੰਨਾ ਚਿਰ ਵੀ ਕਿਸੇ ਦਾ ਮਨ ਰੁਕਿਆ, ਰਹਿੰਦਾ ਮਾਰਿਆ ਲਾਲਸਾ-ਭੁੰਗਦਾ ਏ । ਓਨਾ ਚਿਰ ਓਹ ਇਉਂ ਨਿਰਬਲ ਹੁੰਦਾ, ਬਾਲ ਮਾਤਾ ਦਾ ਦੁੱਧ ਜੋ ਚੁੰਘਦਾ ਏ ।",
  "285": "ਸਰਦ ਰੁੱਤੇ ਜੀਕਰ 'ਫੁੱਲ ਕਮਲਲਿਨੀ' ਦਾ, ਪਕੜ ਹੱਥ ਦੇ ਨਾਲ ਭਰੂੱ ਲਈਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਆਤਮ-ਸਨੇਹ ਤਾਈਂ, ਆਪੇ ਅੰਦਰੋਂ ਬਾਹਰ ਧਰੂਹ ਲਈਏ । ਕੇਵਲ ਓਸੇ ਹੀ ਮਾਰਗ ਦੀ ਗੱਲ ਕਰੀਏ, ਜਿਹੜਾ ਬੁੱਧ ਸੰਸਾਰ ਨੂੰ ਦੱਸਿਆ ਏ । ਐਸਾ ਬੁੱਧ ਜੋ ਗਿਆ ਨਿਰਵਾਣ ਮਾਰਗ, ਅਤੇ ਜਾਏ ਅਨੰਤ ਵਿਚ ਵੱਸਿਆ ਏ ।",
  "286": "'ਏਸ ਸਾਲ ਬਰਸਾਤ ਦੀ ਰੁੱਤ ਅੰਦਰ, ਮੇਰਾ ਦਿਲ ਕਰਦਾ ਏਥੇ ਰਹਾਂਗਾ ਮੈਂ । ਆਉਣ ਵਾਲੀਆਂ ਸਰਦੀਆਂ ਗਰਮੀਆਂ ਵਿਚ, ਜਾ ਕੇ ਅਮਕੇ ਸਥਾਨ ਤੇ ਬਹਾਂਗਾ ਮੈਂ' । ਜਿਹੜਾ ਕੋਈ ਵੀ ਸੋਚਦਾ ਰਹੇ ਏਦਾਂ, ਕੱਚਾ ਅਕਲ ਦਾ ਮੂੜ੍ਹ ਇਨਸਾਨ ਹੁੰਦਾ । ਆਉਣ ਵਾਲਿਆਂ ਵਿਘਨਾਂ ਤੇ ਖਤਰਿਆਂ ਦਾ, ਭੋਰਾ ਭਰ ਨਹੀਂ ਜਿਸ ਨੂੰ ਗਿਆਨ ਹੁੰਦਾ ।",
  "287": "ਵਿਸ਼ਿਆਂ ਵਿਚ ਜੋ ਪੁਰਸ਼ ਗ਼ਲਤਾਨ ਹੋਵੇ, ਦੁੱਧ, ਪੁੱਤ ਦਾ ਮੋਹ ਜਦ ਪੈ ਜਾਏ, ਹੜ੍ਹ ਰੋਹੜਦਾ ਜਿਵੇਂ ਹੈ ਪਿੰਡ ਸੁੱਤਾ, ਮੌਤ ਉਹਨੂੰ ਘਸੀਟ ਕੇ ਲੈ ਜਾਏ ।",
  "288": "ਹੋਏ ਘਟੀ ਤਾਂ ਕੋਈ ਨਾ ਬਾਂਹ ਫੜਦਾ, ਟਲਦੀ ਮੌਤ ਨਾ ਜਦੋਂ ਵੀ ਆਈ ਹੋਵੇ । ਪੁੱਤ, ਪਿਓ, ਮਾਤਾ, ਸਾਕ-ਸੈਣ ਕੋਈ, ਨਾਹੀਂ ਆਖਰੀ ਸਮੇਂ ਸਹਾਈ ਹੋਵੇ ।",
  "289": "ਹੋਏ ਘਟੀ ਤਾਂ ਕੋਈ ਨਾ ਬਾਂਹ ਫੜਦਾ, ਟਲਦੀ ਮੌਤ ਨਾ ਜਦੋਂ ਵੀ ਆਈ ਹੋਵੇ । ਪੁੱਤ, ਪਿਓ, ਮਾਤਾ, ਰਿਸ਼ਤੇਦਾਰ ਕੋਈ, ਨਹੀਂ ਆਖਰੀ ਵਕਤ ਸਹਾਈ ਹੋਵੇ । ਏਸ ਅਮਰ ਹਕੀਕਤ ਨੂੰ ਕੋਈ ਪੰਡਤ, ਜਿਸ ਵੇਲੇ ਵੀ ਵੇਖ ਪਛਾਣਦਾ ਏ । ਬਿਨਾਂ ਦੇਰ ਲਾਇਆਂ ਸ਼ੀਲਵਾਨ ਹੋ ਕੇ, ਕਰਦਾ ਰਾਹ ਉਹ ਸਾਫ਼ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "chap21": "ਪਕਿੱਣਕ",
  "290": "ਥੋੜ੍ਹਾ ਸੁੱਖ ਤਿਆਗਿਆਂ ਕਦੇ ਜੇਕਰ, ਬਾਹਲੇ ਸੁੱਖ ਦੇ ਮਿਲਣ ਦੀ ਆਸ ਹੋਵੇ । ਥੋੜ੍ਹੇ ਸੁੱਖ ਨੂੰ ਛੱਡ ਕੇ ਪਾਉਣ ਬਾਹਲਾ, ਇਓਂ ਪੰਡਤਾਂ ਦਾ ਕਾਰਜ ਰਾਸ ਹੋਵੇ ।",
  "291": "ਦੁੱਖ ਦੇ ਕੇ ਕੋਈ ਜੋ ਹੋਰਨਾਂ ਨੂੰ, ਰਹਿੰਦਾ ਆਪ ਨੂੰ ਸੁੱਖ ਦੀ ਆਸ ਕਰਦਾ । ਵੈਰ ਭਾਵਨਾ ਦੀ ਫਾਹੀ ਫੱਸ ਜਾਏ, ਉਹਦਾ ਵੈਰ ਹੀ ਓਸਦਾ ਨਾਸ ਕਰਦਾ ।",
  "292": "ਜਿਹੜੇ ਚੰਗੇ ਕਰਤੱਬ ਨੂੰ ਛੱਡ ਬਹਿੰਦੇ, ਅਤੇ ਮੰਦੇ ਕਰਤੱਬ ਨੂੰ ਪਾਲਦੇ ਨੇ । ਮਾਰੇ ਹੋਏ ਜੋ ਇਸ ਤਰ੍ਹਾਂ ਗ਼ਾਫ਼ਲੀ ਦੇ, ਹੁੰਦੇ ਉਹ ਗੁਨਾਹਾਂ ਦੇ ਨਾਲ ਦੇ ਨੇ ।",
  "293": "ਰੱਖਣ ਮਨ ਦੀ ਮੈਲ ਨੂੰ ਜੋ ਚੇਤੇ, ਮੰਦਾ ਕੋਈ ਕਰਤੱਬ ਜੋ ਨਹੀਂ ਕਰਦੇ । ਕਰਕੇ ਗ਼ਾਫ਼ਲੀ ਦੂਰ ਸੁਚੇਤ ਰਹਿੰਦੇ, ਉਹਨਾਂ ਪੰਡਤਾਂ ਦੇ ਪਾਪ ਸਦਾ ਹਰਦੇ ।",
  "294": "ਮਾਈ ਬਾਪ ਜੋ ਤ੍ਰਿਸ਼ਨਾ-ਹੰਕਾਰ ਰੂਪੀ, ਕੋਈ ਮੌਤ ਦੇ ਘਾਟ ਉਤਾਰ ਦੇਵੇ । ਜੜ੍ਹ-ਚੇਤਨ ਸਿਧਾਂਤ, ਜੋ ਦੋ ਰਾਜੇ, ਸਣੇ ਮੋਹ ਤੇ ਰੂਪ ਦੇ ਮਾਰ ਦੇਵੇ ।",
  "295": "ਬਾਘ ਵਾਸ਼ਨਾ ਦਾ ਇਹਨਾਂ ਨਾਲ ਪੰਜਵਾਂ, ਪੰਡਤ ਜੋ ਵੀ ਓਸ ਨੂੰ ਕੋਹ ਜਾਏ । ਤੁਰ ਕੇ ਪਰਮ-ਨਿਰਵਾਣ ਦੇ ਰਾਹ ਉੱਤੇ, ਮੁਕਤ ਸਾਰਿਆਂ ਦੁੱਖਾਂ ਤੋਂ ਹੋ ਜਾਏ ।",
  "296": "ਦਿਨੇ ਰਾਤ ਜੋ ਬੁੱਧਾਂ ਦਾ ਧਿਆਨ ਧਰਦੇ, ਏਸੇ ਧੁਨ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਰਹਿਣ ਜਾਗਦੇ, ਦੂਰ ਉਹ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਭਗਤ ਅਖਵਾਉਂਦੇ ਨੇ ।",
  "297": "ਦਿਨੇ ਰਾਤ ਜੋ ਧਰਮ ਦਾ ਧਿਆਨ ਧਰ ਕੇ, ਇਸੇ ਧੁਨ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਰਹਿਣ ਜਾਗਦੇ, ਦੂਰ ਉਹ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਸ਼ਿਸ਼ ਕਹਾਉਂਦੇ ਨੇ ।",
  "298": "ਦਿਨੇ ਰਾਤ ਜੋ 'ਸੰਘ' ਦਾ ਧਿਆਨ ਧਰਦੇ, ਏਸੇ ਧੁਨ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਰਹਿਣ ਜਾਗਦੇ, ਦੂਰ ਉਹ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਭਗਤ ਅਖਵਾਉਂਦੇ ਨੇ ।",
  "299": "ਕਾਂਇਆਂਗਤੀ ਦਾ ਨਿਸਦਿਨ ਜੋ ਧਿਆਨ ਧਰਦੇ, ਏਸ ਧੁਨ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਰਹਿਣ ਜਾਗਦੇ, ਦੂਰ ਉਹ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਸ਼ਿਸ਼ ਕਹਾਉਂਦੇ ਨੇ ।",
  "300": "ਦਿਨੇ ਰਾਤ 'ਅਹਿੰਸਾ' ਦਾ ਧਿਆਨ ਕਰ ਕੇ, ਏਸ ਧੁਨ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਰਹਿਣ ਜਾਗਦੇ, ਦੂਰ ਉਹ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਭਗਤ ਸਦਾਉਂਦੇ ਨੇ ।",
  "301": "ਨਿਸ ਦਿਨ ਆਪੇ ਨੂੰ ਵੱਸ ਜੋ ਰਹਿਣ ਕਰਦੇ, ਏਸੇ ਕਾਰ ਵਿਚ ਵਕਤ ਲੰਘਾਉਂਦੇ ਨੇ । ਜਾਗਰੂਕ ਓਹ ਦੂਰ ਨੇ ਗ਼ਾਫ਼ਿਲੀ ਤੋਂ, ਸੱਚੇ ਗੌਤਮ ਦੇ ਸ਼ਿਸ਼ ਕਹਾਉਂਦੇ ਨੇ ।",
  "302": "ਜਿਹੜੇ ਘਰ ਨਾ ਰਹਿਣ ਦੇ ਹੋਣ ਕਾਬਲ, ਔਖਾ ਉਹਨਾਂ ਵਿਚ ਕਰਨ ਹੈ ਵਾਸ ਹੁੰਦਾ । ਛੱਡ ਜਾਣਾ ਵੀ ਘਰਾਂ ਨੂੰ ਬੜਾ ਮੁਸ਼ਕਿਲ, ਔਖਾ ਵਿਚਰਨਾ ਵਿਚ ਸਨਿਆਸ ਹੁੰਦਾ । ਔਖਾ ਵੱਸਣਾ ਬੜਾ ਅਪਮਾਨ ਜਰ ਕੇ, ਦੁੱਖ ਬਹੁਤ ਸੰਸਾਰ ਦੇ ਰਾਹੀਆਂ ਨੂੰ । ਭਟਕਣ ਮਾਰਗ ਸੰਸਾਰ ਦੀ ਤਜੇ ਜਿਹੜਾ, ਕੱਟ ਜਾਏ ਉਹ ਦੁੱਖ ਦੀਆਂ ਫਾਹੀਆਂ ਨੂੰ ।",
  "303": "ਸ਼ੀਲਵਾਨ, ਸ਼ਰਧਾਲੂ ਤੇ ਸਾਊ, ਸੱਚਾ, ਜਿਹੜਾ ਨੇਕੀ ਦੀ ਕਾਰ ਕਮਾਉਂਦਾ ਏ । ਓਸ ਪੁਰਸ਼ ਦਾ ਜੱਗ ਤੇ ਜੱਸ ਹੋਵੇ, ਇੱਜ਼ਤ ਮਾਣ ਉਹ ਹਰ ਥਾਂ ਪਾਉਂਦਾ ਏ ।",
  "304": "ਬਰਫ਼ਾਂ ਢਕੇ ਪਹਾੜ ਹਿਮਾਲੀਆ ਜਿਉਂ, ਚਾਨਣ ਸੰਤਾਂ ਦਾ ਦਿਸੇ ਚੁਫੇਰੇ ਦੇ ਵਿਚ । ਨਹੀਂ ਨੇੜਿਓਂ ਨਜ਼ਰ ਅਸੰਤ ਆਏ, ਤੀਰ ਛਡਿਆ ਜਿਵੇਂ ਹਨੇਰੇ ਦੇ ਵਿਚ ।",
  "305": "ਰਹੇ ਮਸਤ ਇਕੱਲਿਆਂ ਬੈਠ ਕੇ ਜੋ, ਕਦੇ ਬੈਠਾ ਇਕੱਲਿਆਂ ਅੱਕਦਾ ਨਹੀਂ । ਇੱਕੋ ਸੇਜੇ ਇਕੱਲਿਆਂ ਰਹੇ ਸੌਂਦਾ, ਕਦੇ ਭੌਂਦਿਆਂ ਫਿਰਦਿਆਂ ਥੱਕਦਾ ਨਹੀਂ । ਜਿਹੜਾ ਇਉਂ ਇਕਾਂਤ ਦੇ ਵਿਚ ਰਹਿ ਕੇ, ਕਾਬੂ ਆਪਣੇ ਆਪ ਤੇ ਪਾਉਂਦਾ ਏ । ਰਹਿਕੇ ਉਹਨੂੰ ਇਕੱਲੇ ਨੂੰ ਵਿਚ ਜੰਗਲ, ਲੁੱਤਫ਼ ਜ਼ਿੰਦਗੀ ਦਾ ਡਾਢਾ ਆਉਂਦਾ ਏ ।",
  "chap22": "ਨਿਰਯ",
  "306": "ਸਿੱਧਾ ਨਰਕ ਨੂੰ ਜਾਏ ਜੋ ਝੂਠ ਬੋਲੇ, ਮੁਨਕਰ ਹੋਣ ਕਰਕੇ ਬੇਈਮਾਨ ਹੁੰਦੇ । ਜਾਏ ਵਿਚ ਪਰਲੋਕ ਦੇ ਨੀਚ-ਕਰਮੀ, ਪੈ ਕੇ ਦੋਜ਼ਖ਼ੀਂ ਇਕ-ਸਮਾਨ ਹੁੰਦੇ ।",
  "307": "ਪੀਲੇ ਕਪੜੇ ਗਲਾਂ ਵਿਚ ਪਾਈ ਫਿਰਦੇ, ਸੰਜਮ ਹੀਣ ਅਧਰਮ ਦੀ ਕਾਰ ਕਰਦੇ । ਸਿੱਧੇ ਜਾਣ ਓਹ ਸੜਦਿਆਂ ਵਿਚ ਨਰਕਾਂ, ਕੀਤੇ ਪਾਪ ਹੀ ਉਹਨਾਂ ਨੂੰ ਲੈ ਮਰਦੇ ।",
  "308": "ਸੰਜਮ ਹੀਣ ਹੋ ਕੇ ਦੁਰਾਚਾਰ ਕਰਕੇ, ਕਰਦਾ ਕਮਾਈ ਜੋ ਸ਼ਹਿਰ ਅੰਦਰ । ਏਸ ਪਾਪ ਦੀ ਖੱਟੀ ਦੇ ਚੌਲ ਹੁੰਦੇ, ਬੁੱਝੇ ਹੋਏ ਸਮਝੋ ਮਾਰੂ ਜ਼ਹਿਰ ਅੰਦਰ । ਇਹਨਾਂ ਚੌਲਾਂ 'ਚੋਂ ਪਿੰਨੀਆਂ ਬਣਦੀਆਂ ਜੋ, ਕਦੇ ਭੁੱਲ ਨਾ ਉਹਨਾਂ ਨੂੰ ਚੱਖੀਏ ਜੀ । ਓਹਦੇ ਨਾਲੋਂ ਤਾਂ ਚੰਗਾ ਹੈ ਲਾਟ ਵਰਗਾ, ਭਖਦਾ ਲਹ-ਗੋਲਾ ਭਾਵੇਂ ਭੱਖੀਏ ਜੀ ।",
  "309": "ਹੋਵੇ ਗ਼ਾਫ਼ਿਲੀ-ਮਾਰਿਆ ਪੁਰਸ਼ ਕੋਈ, ਸੰਗ ਨਾਰ ਬਿਗਾਨੀ ਦਾ ਭਾਲਦਾ ਏ । ਚਾਰ ਮੰਦੀਆਂ ਗਤੀਆਂ ਦਾ ਬਣੇ ਭਾਗੀ, ਪਾਪੀ ਕੋਈ ਨਾ ਓਸ ਦੇ ਨਾਲ ਦਾ ਏ । ਪੱਲੇ ਇੱਕ ਤਾਂ ਉਹਦੇ ਗੁਨਾਹ ਪੈਂਦਾ, ਕਾਮ ਓਸ ਦੀ ਨੀਂਦ ਨਸਾਂਵਦਾ ਏ । ਮਿੱਟੀ ਓਸ ਦੀ ਪੁੱਜ ਪਲੀਤ ਤੀਜੀ, ਚੌਥੇ, ਨਰਕ ਨੂੰ ਓਹ ਸਿਧਾਂਵਦਾ ਏ ।",
  "310": "ਮੰਦਾ ਫਲ ਮਿਲਦਾ, ਮਿੱਟੀ ਵੱਖ ਬਲਦੀ, ਮਾੜੀ ਗਤੀ ਤਕਦੀਰ ਮਨਹੂਸ ਹੁੰਦੀ । ਪਰ-ਇਸਤਰੀ ਸਹਿਮੀ ਤੇ ਡਰੀ ਹੋਈ ਤੋਂ, ਖ਼ੁਸ਼ੀ ਡਰੇ ਨੂੰ ਘੱਟ ਮਹਿਸੂਸ ਹੁੰਦੀ । ਉਤੋਂ ਰਾਜ ਦਰਬਾਰ ਤੋਂ ਜੁਰਮ ਕਾਰਨ, ਨਾਲ ਡੰਡਿਆਂ ਸਖ਼ਤ ਪਿਟਾਈ ਹੁੰਦੀ । ਇਸੇ ਕਰ ਕੇ ਹੈ ਕਥਨ ਸਿਆਣਿਆਂ ਦਾ, ਪਾਪ ਰੂਪ ਹੈ ਨਾਰ ਪਰਾਈ ਹੁੰਦੀ ।",
  "311": "ਢੱਬ ਨਾਲ ਸੰਭਾਲ ਕੇ ਨਾ ਲਾਈਏ, ਸੁੱਕਾ ਘਾਹ ਵੀ ਹੱਥ ਨੂੰ ਪੱਛਦਾ ਏ । ਠੀਕ ਤਰ੍ਹਾਂ ਨਾ 'ਸੰਗਮ' ਵਿਚ ਰਲੇ ਜਿਹੜਾ, ਓਹ ਨਰਕ ਦਾ ਰਾਹ ਹੀ ਕੱਛਦਾ ਏ ।",
  "312": "ਹੋਵੇ ਕਰਮ ਸਿਥੱਲ, ਵਰਤ ਮੈਲ ਭਰਿਆ, ਹੋਵੇ ਬਿਨਾਂ ਉਤਸ਼ਾਹ ਦੇ ਬ੍ਰਹਮਚਾਰੀ । ਗੱਲਾਂ ਤਿੰਨੇ ਹੀ ਜਾਣੀਏਂ ਕੱਚੀਆਂ ਨੇ, ਨਹੀਂ ਹੁੰਦੀਆਂ ਕਦੇ ਵੀ ਲਾਭਕਾਰੀ ।",
  "313": "ਧਾਰਨ ਦਿਓ ਉਹਨੂੰ ਸਿਰੜ ਹੌਸਲੇ ਥੀਂ, ਜੇਕਰ ਕੋਈ ਸਨਿਆਸ ਨੂੰ ਚਾਂਹਵਦਾ ਏ । ਹੋਵੇ ਢਿਲਮਠ-ਯਕੀਨ ਜੋ ਸੰਨਿਆਸੀ, ਫਿਰਦਾ ਐਵੇਂ ਓਹ ਖੇਹ ਉਡਾਂਵਦਾ ਏ ।",
  "314": "ਉੱਤਮ ਗੱਲ ਹੈ ਪਾਪ ਦਾ ਨਾ ਕਰਨਾ, ਪਾਪੀ ਪਾਪ ਕਰ ਕੇ ਪੱਛੋਤਾਉਂਦਾ ਏ, ਕਾਰਜ ਸਦਾ ਸਰੇਸ਼ਟ ਹੈ ਪੁੰਨ ਕਰਨਾ, ਕਿਉਂਕਿ ਕਰਨ-ਹਾਰਾ ਸੁੱਖ ਪਾਉਂਦਾ ਏ ।",
  "315": "ਜਿਵੇਂ ਰੱਖਿਆ ਦੇ ਪੱਖ ਤੋਂ ਬੜਾ ਤਕੜਾ, ਬਾਹਰੋਂ ਅੰਦਰੋਂ ਸੀਮਾਂ ਦਾ ਸ਼ਹਿਰ ਹੁੰਦਾ । ਤਿਵੇਂ ਰੱਖਿਆ ਆਪੇ ਦੀ ਆਪ ਕਰੀਏ, ਇਸ 'ਚ ਹੋਏ ਅਣਗਹਿਲੀ ਤਾਂ ਕਹਿਰ ਹੁੰਦਾ । ਇਕ ਛਿਨ ਵੀ ਕੋਈ ਜੇ ਖੁੰਝ ਜਾਏ, ਲਾਂਭੇ ਰਾਹ ਤੋਂ ਕੋਹਾਂ ਤੇ ਜਾ ਪਇੰਦਾ । ਕੁੰਭੀ ਨਰਕ ਦੇ ਵਿਚ ਉਹ ਜਾ ਡਿੱਗੇ, ਨਾਲ ਸ਼ੋਕ ਦੇ ਰਿੱਝਦਾ ਸਦਾ ਰਹਿੰਦਾ ।",
  "316": "ਜਿਹੜੀ ਸ਼ਰਮ ਨਾ ਕਰਨ ਦੀ ਗੱਲ ਹੋਵੇ, ਜਿਹੜੇ ਓਸ ਤੋਂ ਐਵੇਂ ਸ਼ਰਮਾਈ ਜਾਂਦੇ । ਜਿਹੜੀ ਸ਼ਰਮ ਕਰਨ ਵਾਲੀ ਜਿਹੜੀ ਥਾਂ ਹੋਵੇ, ਓਥੇ ਵੇਚ ਕੇ ਸ਼ਰਮ ਜੋ ਖਾਈ ਜਾਂਦੇ । ਐਸੇ ਆਦਮੀ ਵਹਿਮ ਤੇ ਭਰਮ ਖਾਧੇ, ਮਿਥਿਆ ਉਹਨਾਂ ਦਾ ਨੁਕਤਾ-ਨਿਗਾਹ ਹੁੰਦਾ । ਸਦਾ ਓਹਨਾਂ ਦੀ ਬੜੀ ਦੁਰਗਤੀ ਹੁੰਦੀ, ਨਹੀਂ ਓਹਨਾਂ ਲਈ ਸੁੱਖ ਦਾ ਸਾਹ ਹੁੰਦਾ ।",
  "317": "ਜਿਹੜੀ ਡਰਨ ਦੀ ਜ਼ਰਾ ਨਾ ਗੱਲ ਹੋਵੇ, ਓਥੇ ਸਮਝ ਕੇ ਡਰ ਜੋ ਡਰ ਜਾਏ । ਜਿਹੜੀ ਥਾਂ ਉਤੋਂ ਆਉਣਾ ਡਰ ਚਾਹੀਏ, ਓਸ ਥਾਂ ਤੇ ਹੋ ਨਿਡਰ ਜਾਂਦੇ । ਐਸੇ ਆਦਮੀ ਵਹਿਮ ਤੇ ਭਰਮ ਖਾਧੇ, ਮਿਥਿਆ ਉਹਨਾਂ ਦਾ ਨੁਕਤਾ-ਨਿਗਾਹ ਹੁੰਦਾ । ਸਦਾ ਓਹਨਾਂ ਦੀ ਪੁੱਜ ਦੁਰਗਤੀ ਹੁੰਦੀ, ਨਹੀਂ ਓਹਨਾਂ ਲਈ ਸੁੱਖ ਦਾ ਸਾਹ ਹੁੰਦਾ ।",
  "318": "ਕੋਈ ਗੱਲ ਜੋ ਚਾਹੀਦੀ ਨਹੀਂ ਕਰਨੀ, ਜਿਹੜੇ ਸਮਝਦੇ ਓਸ ਨੂੰ ਕਰਨ ਵਾਲੀ । ਜਿਹੜੀ ਗੱਲ ਪਰ ਕਰਨ ਦੇ ਯੋਗ ਹੋਵੇ, ਜੋ ਨਾ ਸਮਝਦੇ ਓਸ ਨੂੰ ਕਰਨ ਵਾਲੀ । ਐਸੇ ਆਦਮੀ ਵਹਿਮ ਤੇ ਭਰਮ ਫਾਥੇ, ਮਿਥਿਆ ਉਹਨਾਂ ਦਾ ਨੁਕਤਾ-ਨਿਗਾਹ ਹੁੰਦਾ । ਸਦਾ ਓਹਨਾਂ ਦੀ ਪੁੱਜ ਦੁਰਗਤੀ ਹੋਵੇ, ਨਹੀਂ ਓਹਨਾਂ ਲਈ ਸੁੱਖ ਦਾ ਸਾਹ ਹੁੰਦਾ ।",
  "319": "ਜਿਹੜੀ ਗੱਲ ਹੋਵੇ ਨਹੀਂ ਕਰਨ ਵਾਲੀ, ਜੋ ਜਾਣ ਜਾਏ ਨਹੀਂ ਕਰਨ ਵਾਲੀ । ਜਿਹੜੀ ਗੱਲ ਹੋਵੇ ਕੀਤੀ ਜਾਣ ਵਾਲੀ, ਜੋ ਜਾਣ ਜਾਏ ਹੈਗੀ ਕਰਨ ਵਾਲੀ । ਐਸੇ ਆਦਮੀ ਦਾ ਭਰਮ ਦੂਰ ਹੋਇਆ, ਠੀਕ ਓਸ ਦਾ ਨੁਕਤਾ-ਨਿਗਾਹ ਹੁੰਦਾ । ਉੱਤਮ ਗਤੀ ਦਾ ਬਣੇ ਉਹ ਬਸ਼ਰ ਭਾਗੀ, ਓਹਨੂੰ ਸੁੱਖ ਆਨੰਦ ਉਮਾਹ ਹੁੰਦਾ ।",
  "chap23": "ਨਾਗ",
  "320": "ਹਾਥੀ ਜੰਗ ਦੇ ਗਰਮ ਮੈਦਾਨ ਅੰਦਰ, ਫਿਰਕੇ ਵੈਰੀ ਦੇ ਦਲਾਂ ਨੂੰ ਗਾਹ ਕਰਦਾ । ਸ਼ੂਕਣ ਤੀਰ ਕਮਾਨਾਂ ਚੋਂ ਲੱਖ ਭਾਵੇਂ, ਰੱਤੀ ਭਰ ਨਹੀਂ ਉਹ ਪਰਵਾਹ ਕਰਦਾ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਗਾਲੀਆਂ ਬੋਲ ਮੰਦੇ । ਸੁਣ ਕੇ ਟਾਲਦਾ ਅਤੇ ਸਹਾਰਦਾ ਹੈ । 'ਗਿਣਤੀ ਬਾਹਲੀ ਜ਼ਬਾਨ ਦੇ ਭੈੜਿਆਂ ਦੀ', ਇਸੇ ਗੱਲ ਨੂੰ ਸਦਾ ਵਿਚਾਰਦਾ ਹੈ ।",
  "321": "ਜਿਹੜਾ ਕਿਸੇ ਨੇ ਹੋਏ ਸਿਧਾਇਆ ਹਾਥੀ, ਓਹੀ ਜਾਂਦਾ ਹੈ ਫੌਜੀ ਕਮਾਨ ਦੇ ਨਾਲ । ਉਹਦੇ ਉੱਪਰ ਹੀ ਰਾਜਾ ਅਸਵਾਰ ਹੋ ਕੇ, ਚੜ੍ਹਦਾ ਜੰਗ ਨੂੰ ਹੈ ਸ਼ਾਹੀ ਸ਼ਾਨ ਦੇ ਨਾਲ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੈ ਸ਼ਾਨ ਉਸ ਆਦਮੀ ਦੀ, ਕਰ ਆਪਣਾ ਆਪ ਜੋ ਵੱਸ ਛੱਡਦਾ । ਸੁਣ ਕੇ ਮੰਦਿਆਂ ਬੋਲਾਂ ਤੇ ਗਾਲੀਆਂ ਨੂੰ, ਗੁੱਸਾ ਨਹੀਂ ਕਰਦਾ, ਸਗੋਂ ਹੱਸ ਛੱਡਦਾ ।",
  "322": "ਓਸੇ ਖੱਚਰ ਨੂੰ ਸਮਝਦੇ ਲੋਕ ਵਧੀਆ, ਜਿਸ ਨੂੰ ਕਿਸੇ ਨੇ ਠੀਕ ਸਿਧਾਇਆ ਹੋਵੇ । ਓਸੇ ਘੋੜੇ ਦਾ ਪਾਰਖੂ ਮੁੱਲ ਪਾਉਂਦੇ, ਚੰਗੀ ਨਸਲ ਦਾ ਜੰਮਿਆਂ ਜਾਇਆ ਹੋਵੇ । ਵਿਚ ਹਾਥੀਆਂ ਦੇ 'ਮਹਾਂ-ਨਾਗ' ਸੋਹੇ, ਕੋਈ ਹੋਰ ਹਾਥੀ ਓਹਦੀ ਚਾਲ ਦਾ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਆਪੇ ਨੂੰ ਸਾਧਿਆ ਜਿਸ, ਉੱਤਮ ਆਦਮੀ ਓਸ ਦੇ ਨਾਲ ਦਾ ਨਹੀਂ ।",
  "323": "ਪਦਵੀ ਪਾਉਣੀ ਨਿਰਵਾਣ ਦੀ ਬੜੀ ਔਖੀ, ਕੋਈ ਵਿਰਲਾ ਹੀ ਓਸ ਨੂੰ ਪਾ ਸਕਦਾ । ਚੜ੍ਹ ਕੇ ਔੜਿਆਂ, ਖੱਚਰਾਂ ਹਾਥੀਆਂ ਤੇ, ਏਸ ਮੰਜ਼ਿਲ ਦੇ ਵੱਲ ਨਹੀਂ ਜਾ ਸਕਦਾ । ਕੇਵਲ ਸੰਜਮੀ ਹੋਏ ਤੇ ਕਰੇ ਸੰਜਮ, ਵਸ ਆਪਣੇ ਆਪ ਨੂੰ ਕਰ ਜਾਏ । ਤੁਰੇ ਓਹ ਨਿਰਵਾਣ ਦੇ ਰਾਹ ਉੱਪਰ, ਮੰਜ਼ਿਲ ਆਪਣੀ ਕਰ ਉਹ ਸਰ ਜਾਏ ।",
  "324": "ਕੁੰਚਰ 'ਧਨ ਪਾਲਕ' ਬੜੇ ਬਲ ਵਾਲਾ, ਜਿਹੜਾ ਫੌਜਾਂ ਨੂੰ ਮਾਰ ਭਜਾਉਂਦਾ ਏ । ਉਸ ਨੂੰ ਰੋਕਣਾ ਬੜਾ ਹੀ ਹੋਏ ਮੁਸ਼ਕਿਲ, ਜਦੋਂ ਕਾਮ ਦੇ ਵੇਗ ਵਿਚ ਆਉਂਦਾ ਏ । ਜੇਕਰ ਨੂੜ ਕੇ ਓਸ ਨੂੰ ਸੁੱਟ ਲਈਏ, ਚੌਲ-ਚਾਰੇ ਨੂੰ ਮੂੰਹ ਉਹ ਲਾਉਂਦਾ ਨਹੀਂ । ਲੱਥੇ ਹੇਰਵਾ ਹਾਥੀਆਂ ਸਾਥੀਆਂ ਦਾ, ਹਾਥੀ ਵਣ ਦੀ ਸ਼ਾਨ ਭੁਲਾਉਂਦਾ ਨਹੀਂ ।",
  "325": "ਕਣਕ ਖਾ ਕੇ ਫਿਟੇ ਹੋਏ ਸੂਰ ਵਾਂਗਰ, ਪੇਟੂ ਭੈੜੇ ਡਕਾਰ ਜੋ ਮਾਰਦਾ ਏ, ਮੀਟ ਅੱਖੀਆਂ ਊਂਘਦਾ ਰਹੇ ਜਿਹੜਾ, ਪਾਸੇ ਬਿਸਤਰੇ ਤੇ ਰਹਿੰਦਾ ਮਾਰਦਾ ਏ । ਹੋਵੇ ਆਦਮੀ ਆਲਸੀ ਇਉਂ ਜੋ ਵੀ, ਮਨ ਓਸ ਦਾ ਸੋਚਣ ਤੋਂ ਰਹਿ ਜਾਏ । ਖਹਿੜਾ ਛੱਡਦਾ ਨਹੀਂ ਹੈ ਦੁੱਖ ਉਹਦਾ, ਜੰਮਣ ਮਰਨ ਦੇ ਗੇੜ ਵਿਚ ਪੈ ਜਾਏ ।",
  "326": "ਪਹਿਲਾਂ ਅੱਜ ਤੋਂ ਇਹ ਚੰਚਲ ਚਿੱਤ ਮੇਰਾ, ਰਹਿੰਦਾ ਆਪਣੀ ਮਰਜ਼ੀ ਨਾਲ ਭਟਕਦਾ ਸੀ । ਜਿਧਰ ਦਿਲ ਕਰਦਾ, ਓਧਰ ਉੱਡ ਜਾਂਦਾ, ਕੋਈ ਮੋੜਦਾ ਇਹਨੂੰ ਨਾ ਹਟਕਦਾ ਸੀ । ਚੰਗੀ ਤਰ੍ਹਾਂ ਮੈਂ ਕਰਾਂ ਪਰ ਵੱਸ ਇਹਨੂੰ, ਕਰਨ ਦਿਆਂ ਨਾ ਏਸ ਨੂੰ ਮਨ ਆਈ । ਮਸਤ ਹਾਥੀ ਨੂੰ ਸਿਰ ਤੇ ਜਿਵੇਂ ਕੁੰਡਾ, ਦੇਵੇ ਵੱਸ ਤੋਂ ਬਾਹਰ ਨਾ ਜਾਣ ਰਾਈ ।",
  "327": "ਆਲਸ ਝਾੜ ਕੇ ਸਦਾ ਪਰਸੰਨ ਰਹੀਏ, ਏਸ ਗੱਲ ਨੂੰ ਕਦੇ ਵਿਸਾਰੀਏ ਨਾ । ਕਰੀਏ ਆਪਣੇ ਮਨ ਦੀ ਨਿੱਤ ਰਾਖੀ, ਇਹਨੂੰ ਛੱਡ ਖੁੱਲ੍ਹਾ ਬਾਜ਼ੀ ਹਾਰੀਏ ਨਾ । ਕੋਈ ਹਾਥੀ ਜਿਉਂ ਦਲਦਲ ਦੇ ਵਿਚ ਫਸਿਆ, ਜਿਸਮ ਆਪਣਾ ਜ਼ੋਰ ਨਾਲ ਪੁੱਟ ਜਾਏ, ਓਸ ਤਰ੍ਹਾਂ ਹੀ ਚਾਹੀਦਾ ਆਦਮੀ ਨੂੰ, ਜ਼ੋਰ ਮਾਰ ਕੇ ਪਾਪਾਂ ਤੋਂ ਛੁੱਟ ਜਾਏ ।",
  "328": "ਐਸਾ ਕੋਈ ਸਾਥੀ ਜੇਕਰ ਮਿਲੇ ਤੈਨੂੰ, ਕੋਟ ਅਕਲ ਦਾ ਅਤੇ ਹੁਸ਼ਿਆਰ ਹੋਵੇ । ਚੰਗੀ ਜ਼ਿੰਦਗੀ ਭੋਗਦਾ ਖ਼ੁਸ਼ੀ ਰਹਿੰਦਾ, ਨਾਲ ਤੁਰਨ ਲਈ ਤੇਰੇ ਤਿਆਰ ਹੋਵੇ । ਸਾਰੇ ਵਿਘਨ ਅੰਦੇਸੜੇ ਦੂਰ ਕਰ ਕੇ, ਉਹਦੇ ਨਾਲ ਤੂੰ ਕਦਮ ਮਿਲਾਈ ਚੱਲੀਂ । ਪੂਰੀ ਸਮਝ ਤੇ ਹੌਸਲੇ ਨਾਲ ਭਿਖਸ਼ੂ, ਉਹਦੇ ਨਾਲ ਤੂੰ ਸਾਥ ਨਿਭਾਈ ਚੱਲੀਂ ।",
  "329": "ਗਜਰਾਜ ਜਿਉਂ ਵਣਾਂ ਦੇ ਵਿਚ ਫਿਰਦਾ, ਖੁੱਲ੍ਹਾਂ ਪੂਰੀਆਂ ਪੂਰੀਆਂ ਮਾਣਦਾ ਏ । ਰਾਜ ਹਾਰਿਆ ਜਿਸ ਤਰ੍ਹਾਂ ਕੋਈ ਰਾਜਾ, ਫਿਰਦਾ ਜੰਗਲਾਂ ਦੀ ਖੇਹ ਛਾਣਦਾ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਤੂੰ ਨਿਸ਼ੰਗ ਹੋ ਕੇ, ਤੈਨੂੰ ਜੇਕਰਾਂ ਨਾ ਪਾਰਾਵਾਰ ਮਿਲਦਾ, ਤੁਰ ਪਈਂ ਇਕੱਲਾ ਸੁਚੇਤ ਹੋ ਕੇ, ਸਿਆਣਾ ਜੇ ਨਾ ਰਾਹ ਦਾ ਯਾਰ ਮਿਲਦਾ ।",
  "330": "ਹੁੰਦਾ ਨਹੀਂ ਅੰਞਾਣੇ ਦਾ ਸਾਥ ਚੰਗਾ, ਉਹ ਤਾਂ ਕਦੇ ਨਾ ਪੂਰੀਆਂ ਪਾਉਂਦਾ ਏ । ਚੰਗਾ ਓਸ ਤੋਂ ਤੁਰਨ ਇਕੱਲਿਆਂ ਹੀ, ਸਾਥ ਮੂੜ੍ਹ ਦਾ ਰਾਸ ਨਾ ਆਉਂਦਾ ਏ । ਖੁੱਲ੍ਹਾ , ਘੁੰਮਦਾ ਜੰਗਲੀ ਜਿਵੇਂ ਹਾਥੀ, ਚਾਹੀਏ ਘੁੰਮਣਾਂ ਓਦਾਂ ਹੀ ਲਟਕ ਦੇ ਨਾਲ । ਕਰੀਏ ਪਾਪ ਨਾ, ਸਦਾ ਸੁਚੇਤ ਰਹੀਏ, ਤੁਰੀਏ ਫੇਰ ਭਾਵੇਂ ਕੱਲੇ ਮਟਕ ਦੇ ਨਾਲ ।",
  "331": "ਕੰਮ ਪੈਣ ਉੱਪਰ ਜਿਹੜੇ ਬਹੁੜਦੇ ਨੇ, ਮਿੱਤਰ ਲੱਗਦੇ ਬੜੇ ਹੀ ਸੁੱਖਦਾਈ । ਕਾਰਨ ਸੁੱਖ ਦਾ ਸਬਰ ਸੰਤੋਖ ਹੁੰਦਾ, ਕਰੀਏ ਏਸ ਦੇ ਵਿਚ ਨਾ ਸ਼ੱਕ ਰਾਈ । ਸੁਖੀ ਪੁੰਨ ਰੱਖਣ ਮੌਤ ਆਈ ਪਿੱਛੋਂ, ਜਦੋਂ ਵਿਚ ਪਰਲੋਕ ਦੇ ਵਾਸ ਹੁੰਦਾ । ਅਸਲ ਸੁੱਖ ਆਨੰਦ ਹੈ ਓਸ ਵੇਲੇ, ਜਦੋਂ ਸਗਲ ਸੰਤਾਪ ਦਾ ਨਾਸ ਹੁੰਦਾ ।",
  "332": "ਕਰੀਏ ਸੇਵਾ ਜੇ ਆਪਣੇ ਮਾਪਿਆਂ ਦੀ, ਘਰ ਆਪਣੇ ਸੁੱਖ ਤਦ ਵੱਸਦਾ ਏ । ਖ਼ੁਸ਼ੀ ਬੜੀ ਸੰਨਿਆਸ ਦੇ ਵਿਚ ਹੋਵੇ, ਸੁੱਖ ਸਦਾ ਨਿਸ਼-ਪਾਪ ਤੇ ਹੱਸਦਾ ਏ ।",
  "333": "ਬਿਰਧ ਹੋ ਕੇ ਵੀ ਸ਼ੀਲਵਾਨ ਰਹਿਣਾ, ਸ਼ਰਧਾ ਹੋਏ ਅਡੋਲ ਤਾਂ ਸੁਖਦਾਈ । ਸੁੱਖ ਦਵੇ ਗਿਆਨ-ਗ੍ਰਹਿਣ ਕਰਨਾ, ਮੁੱਖ ਪਾਪ ਤੋਂ ਮੋੜਨਾ ਸੁਖਦਾਈ ।",
  "chap24": "ਤਞਹਾ",
  "334": "ਜਿਹੜਾ ਗ਼ਾਫ਼ਲੀ ਕਰੇ ਇਖ਼ਲਾਕ ਵੱਲੋਂ, ਤ੍ਰਿਸ਼ਨਾ ਓਸ ਨੂੰ ਇਓਂ ਦਬੱਲਦੀ ਏ । ਅਮਰ ਵੇਲ ਜਿਓਂ ਬੇਰੀ ਦੇ ਰੁੱਖ ਉੱਤੇ, ਪਾਉਂਦੀ ਜੜ੍ਹ ਤੇ ਫੈਲਦੀ ਮੱਲਦੀ ਏ । ਓਹ ਆਦਮੀ ਇਕ ਤੋਂ ਥਾਂ ਦੂਜੀ, ਰਹਿੰਦਾ, ਦੌੜਦਾ, ਭਟਕਦਾ ਡੋਲਦਾ ਏ । ਜਿਵੇਂ ਸੰਘਣੇ ਜੰਗਲ ਦੇ ਵਿਚ ਬਾਂਦਰ, ਭੁੜਕ ਨੱਸ ਕੇ ਫਲਾਂ ਨੂੰ ਫੋਲਦਾ ਏ ।",
  "335": "ਕਾਲੇ ਮੂੰਹ ਵਾਲੀ ਭੈੜੀ ਨੀਚ ਤ੍ਰਿਸ਼ਨਾ, ਜਦੋਂ ਆਪਣੀ ਆਈ ਤੇ ਆਉਂਦੀ ਏ । ਚੰਬੜ ਫੈਲ ਕੇ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਜਿਸ ਆਦਮੀ ਤੇ ਗਲਬਾ ਪਾਉਂਦੀ ਏ । ਕਰਨ ਓਸ ਤੇ ਸਾਰੇ ਸੰਤਾਪ ਧਾਵਾ, ਇਓਂ ਦੁਖੀ ਓਹਦਾ ਸਾਹ ਸਾਹ ਹੋਵੇ । ਜਿਵੇਂ ਰੁੱਤ ਬਰਸਾਤ ਦੀ ਤਿੜ੍ਹਾਂ ਵਾਲਾ, ਹਰ ਪਾਸੇ ਵੱਲ ਉੱਗਿਆ ਘਾਹ ਹੋਵੇ ।",
  "336": "ਕਾਲੇ ਮੂੰਹ ਵਾਲੀ ਭੈੜੀ ਨੀਚ ਤ੍ਰਿਸ਼ਨਾ, ਹੁੰਦਾ ਬੜਾ ਔਖਾ ਜਿਸ ਨੂੰ ਮਾਰਨਾ ਈਂ । ਜਿਹੜਾ ਏਸ ਬਲਾ ਤੇ ਪਾਏ ਕਾਬੂ, ਓਹਨੇ ਆਪਣਾ ਕਾਜ ਸਵਾਰਨਾ ਈਂ । ਓਹਨੂੰ ਫ਼ਿਕਰ ਨਾ ਕੋਈ ਸੰਸਾਰ ਅੰਦਰ, ਦੁੱਖ ਇਸ ਤਰ੍ਹਾਂ ਲਾਗਿਓਂ ਢਿਲਕ ਜਾਏ, ਕੌਲ ਫੁੱਲ ਦੀ ਪੱਤੀ ਤੇ ਪੈਣ ਵਾਲਾ, ਤੁਬਕਾ ਪਾਣੀ ਦਾ ਜਿਸ ਤਰ੍ਹਾਂ ਤਿਲਕ ਜਾਏ ।",
  "337": "ਜਿਹੜੇ ਚੱਲ ਕੇ ਆਏ ਹੋ ਤੁਸੀਂ ਏਥੇ, ਇਕ ਗੱਲ ਆਖਾਂ ਜਿਸ ਤੇ ਜੁੱਟ ਜਾਓ । ਜਿਵੇਂ ਘਾਹ ਨੂੰ ਜੜ੍ਹਾਂ ਤੋਂ ਪੁੱਟਦੇ ਨੇ, ਤੁਸੀਂ ਮਨਾਂ 'ਚੋਂ ਤ੍ਰਿਸ਼ਨਾ ਨੂੰ ਪੁੱਟ ਜਾਓ । ਇਹ ਗੱਲ ਕਲਿਆਣ ਨਿਰਵਾਣ ਦੀ ਏ, ਪੱਲੇ ਬੰ੍ਹਣੀ ਚਾਹੀਦੀ ਦਾਨਿਆਂ ਨੂੰ । ਤੋੜਨ ਦਿਓ ਨਾ ਮਾਇਆ ਨੂੰ ਇਓਂ ਆਪਾ, ਵਹਿਣ ਭੰਨਦਾ ਜਾਏ ਜਿਓਂ ਕਾਨਿਆਂ ਨੂੰ ।",
  "338": "ਕਿਸੇ ਰੁੱਖ ਨੂੰ ਛਾਂਗੀਏ ਸੌ ਵਾਰੀ, ਤਣਾ, ਡਾਹਣਿਆਂ ਦੇ ਸਣੇ ਵੱਢ ਦਈਏ । ਮੁੜਕੇ ਝੱਟ ਹੀ ਉਹ ਹੈ ਪੁੰਗਰ ਆਉਂਦਾ, ਜੇਕਰ ਜੜ੍ਹ ਜ਼ਮੀਨ ਵਿਚ ਛੱਡ ਦਈਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਮਝੀਏ ਆਦਮੀ ਜੋ, ਤ੍ਰਿਸ਼ਨਾ ਜੜ੍ਹਾਂ ਤੋਂ ਖਿੱਚ ਕੇ ਪੁੱਟਦਾ ਨਹੀਂ । ਮੁੜ ਮੁੜ ਲੱਗਦੇ ਰੋਗ-ਸੰਤਾਪ ਉਸ ਨੂੰ, ਖਹਿੜਾ ਦੁੱਖਾਂ ਤੋਂ ਓਸਦਾ ਛੁੱਟਦਾ ਨਹੀਂ ।",
  "339": "ਜੀਹਦੇ ਛੱਤੀ ਸਰੋਤ ਨੇ ਪਏ ਵਹਿੰਦੇ, ਵੱਲ ਸੋਹਣੀਆਂ ਚੀਜ਼ਾਂ ਪਿਆਰੀਆਂ ਦੇ । ਤ੍ਰਿਸ਼ਨਾ ਮੋਹ ਨੇ ਓਸ ਨੂੰ ਰੋਹੜ ਖੜਦੇ, ਵਿਚ ਖੋਲਿਆਂ, ਖੱਡਾਂ, ਖਵਾਰੀਆਂ ਦੇ ।",
  "340": "ਇਹ ਸਾਰੇ ਸਰੋਤ ਨੇ ਵਹੀ ਜਾਂਦੇ, ਅਮਰ ਵੇਲ ਹਰ ਪਾਸਿਓਂ ਫੁੱਟਦੀ ਏ । ਜੜ੍ਹਾਂ ਪੁੱਟੀਏ ਉਹਦੀਆਂ ਗਿਆਨ ਦੇ ਨਾਲ, ਤਾਂਹੀਓਂ ਜਾਨ ਅਜ਼ਾਬ ਤੋਂ ਛੁੱਟਦੀ ਏ ।",
  "341": "ਖਾਰੇ ਤ੍ਰਿਸ਼ਨਾ ਦੇ ਪਿਆਰੇ ਨੇ ਪਰਾਣੀਆਂ ਨੂੰ, ਬੜੇ ਮਨ ਮੋਹਣੇ ਮਿੱਠੇ ਲੱਗਦੇ ਨੇ । ਜਿਹੜੇ ਐਸ਼ ਦੀ ਭਾਲ ਵਿਚ ਫਿਰਨ ਭਉਂਦੇ, ਇਹ ਉਹਨਾਂ ਨੂੰ ਫਾਹੁੰਦੇ ਠੱਗਦੇ ਨੇ । ਐਸੇ ਤ੍ਰਿਸ਼ਨਾ ਦੇ ਚੱਕਰ ਵਿਚ ਜੋ ਫਾਥੇ, ਜਾਂਦੇ ਰੁੜ੍ਹੀ ਉਹ ਜ਼ਰਾ ਨਾ ਥੰਮਦੇ ਨੇ । ਦੁੱਖ ਜੱਗ ਦਾ ਉਹਨਾਂ ਨੂੰ ਮਾਰਦਾ ਏ, ਵਾਰ ਵਾਰ ਉਹ ਵਿਣਸਦੇ ਜੰਮਦੇ ਨੇ ।",
  "342": "ਲੱਗੇ ਵੇਖ ਕੇ ਪਿੱਛੇ ਸ਼ਿਕਾਰੀਆਂ ਨੂੰ, ਸੈਹਾ ਦੌੜਦਾ ਹੈ ਜਿਵੇਂ ਜ਼ੋਰ ਦੇ ਨਾਲ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਤ੍ਰਿਸ਼ਨਾ ਦੇ ਮਗਰ ਪ੍ਰਾਣੀ, ਫਿਰਦਾ ਨੱਸਦਾ ਜ਼ੋਰ ਤੇ ਸ਼ੋਰ ਦੇ ਨਾਲ ।",
  "343": "ਉਹ ਜਕੜਿਆ ਮਨ ਦੇ ਬੰਧਨਾਂ ਵਿਚ, ਸਦਾ ਦੁੱਖ ਹੀ ਦੁੱਖ ਉਠਾਈ ਜਾਵੇ । ਇਸੇ ਲਈ ਹੀ ਭਿਖਸ਼ੂ ਨੂੰ ਚਾਹੀਦਾ ਹੈ, ਦੂਰ ਤ੍ਰਿਸ਼ਨਾ ਨੂੰ ਮਨੋਂ ਹਟਾਈ ਜਾਵੇ ।",
  "344": "ਜਿਹੜਾ ਆਦਮੀ ਤੋੜ ਕੇ ਬੰਧਨਾਂ ਨੂੰ, ਧਾਰਨ ਖ਼ੁਸ਼ੀ ਦੇ ਨਾਲ ਸੰਨਿਆਸ ਕਰਦਾ । ਉਹ ਮੋਹ ਸੰਸਾਰ ਦਾ ਤਿਆਗ ਦਿੰਦਾ, ਵਿਚ ਜੰਗਲਾਂ ਦੇ ਜਾ ਕੇ ਵਾਸ ਕਰਦਾ । ਜੇਕਰ ਫੇਰ ਵੀ ਛੱਡ ਕੇ ਜੰਗਲਾਂ ਨੂੰ, ਓਹ ਵੱਲ ਸੰਸਾਰ ਦੇ ਆਉਂਦਾ ਏ । ਸਮਝੋ ਓਹ ਤਾਂ ਫਾਹੀ ਤੋਂ ਮੁਕਤ ਹੋ ਕੇ, ਫੇਰ ਫਾਹੀ ਵਿਚ ਧੌਣ ਫਸਾਉਂਦਾ ਏ ।",
  "345": "ਬਣੇ ਹੋਣ ਸਨੁਕੜੇ ਦੇ ਰੱਸਿਆਂ ਦੇ, ਬੰਧਨ ਹੋਣ ਭਾਵੇਂ ਲੋਹੇ ਲੱਕੜੀ ਦੇ । ਪੰਡਤ ਓਹਨਾਂ ਨੂੰ ਕਦੇ ਨਾ ਕਹਿਣ ਪੱਕੇ, ਸਗੋਂ ਸਮਝਦੇ ਤਾਰ ਨੇ ਮੱਕੜੀ ਦੇ । ਜੜੇ ਮੋਤੀਆਂ ਨਾਲ ਜੋ ਕੁੰਡਲਾਂ ਨੂੰ, ਅਤੇ ਵਹੁਟੀਆਂ ਪੁੱਤਰਾਂ ਪਿਆਰਦੇ ਨੇ । ਓਸ ਮੋਹ ਪਿਆਰ ਨੂੰ ਕਹਿਣ ਪੰਡਤ, ਬੰਧਨ ਇਹੀ ਤਾਂ ਅਸਲ ਵਿਚ ਸਾਰ ਦੇ ਨੇ ।",
  "346": "ਮਾਇਆ ਮੋਹ ਤੇ ਧਨ ਦੇ ਬੰਧਨਾਂ ਨੂੰ, ਪੱਕਾ ਬਹੁਤ ਹੀ ਪੰਡਤ ਬਖਾਣਦੇ ਨੇ । ਪੀਡੇ, ਛਲੀਏ ਤੇ ਹੇਠ ਨੂੰ ਧੂਹਣ ਵਾਲੇ, ਲੱਛਣ ਇਹਨਾਂ ਦੇ ਖੂਬ ਪਛਾਣਦੇ ਨੇ । ਤੋੜ ਭੰਨ ਕੇ ਇਹੋ ਜਿਹੇ ਬੰਧਨਾਂ ਨੂੰ, ਪੰਡਤ ਲੋਕ ਆਜ਼ਾਦੀਆਂ ਮਾਣਦੇ ਨੇ । ਝੰਜਟ-ਕਾਮ ਦੇ ਸਭ ਤਿਆਗ ਦਿੰਦੇ, ਪੈਂਦੇ ਤੁਰ ਉਹ ਰਾਹ ਨਿਰਵਾਣ ਦੇ ਨੇ ।",
  "347": "ਤ੍ਰਿਸ਼ਨਾ ਮਾਇਆ ਦੇ ਵਿਚ ਗ਼ਲਤਾਨ ਜਿਹੜੇ, ਇਓਂ ਡਿਗਦੇ ਆਪਣੀ ਝਾਲ ਅੰਦਰ । ਜਿਵੇਂ ਮੱਕੜੀ ਘਾਤ ਵਿਚ ਹੋਈ ਬੈਠੀ, ਜਾਂਦੀ ਫਸ ਹੈ ਆਪਣੇ ਜਾਲ ਅੰਦਰ । ਸੋਝੀ ਆਏ ਤਾਂ ਤੋੜ ਕੇ ਬੰਧਨਾਂ ਨੂੰ, ਪੰਡਤ ਜਾਲ ਤਾਈਂ ਤਾਰ ਤਾਰ ਕਰਦੇ । ਤ੍ਰਿਸ਼ਨਾ, ਦੁੱਖ ਤੇ ਭੁੱਖ ਤੋਂ ਪਾਉਣ ਮੁਕਤੀ, ਬੇੜੇ ਆਪਣੇ ਭਵਜਲੋਂ ਪਾਰ ਕਰਦੇ ।",
  "348": "ਕੋਈ ਚਾਹੇ ਜੋ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਦੁੱਖ ਰੋਗ ਦੇ ਸਾਗਰ ਨੂੰ ਪਾਰ ਕਰਨਾ । ਓਸ ਨੂੰ ਚਾਹੀਦਾ ਪੰਜਾਂ 'ਸਕੰਧਾਂ' ਦੇ ਨਾਲ, ਕਦੇ ਭੁੱਲ ਵੀ ਨਹੀਂ ਪਿਆਰ ਕਰਨਾ । ਭਰਮ ਭੂਤ, ਭਵਿਖ ਦੇ ਤਿਆਗ ਦੇਵੇ, ਹਾਲਾ ਸਾਲ ਦੇ ਵੀ ਸੰਸੇ ਹਰੇ ਸਾਰੇ । ਜੰਮਣ-ਮਰਨ ਦਾ ਓਸ ਦਾ ਗੇੜ ਮੁੱਕੇ, ਵਹਿਣ ਉਹ ਨਿਰਵਾਣ ਦੇ ਤਰੇ ਸਰੇ ।",
  "349": "ਤੀਬਰ ਮੋਹ ਤੜਫਾਉਂਦਾ ਰਹੇ ਹਰ ਦਮ, ਜੀਹਨੂੰ ਸੰਸਿਆਂ ਕੋਹ ਨਿਢਾਲ ਕੀਤਾ । ਕਾਮ-ਵਾਸ਼ਨਾ ਸੁੰਦਰਤਾ ਭਾਲਦਾ ਜੋ, ਜਿਸਨੇ ਤਿਆਗ ਦਾ ਰਤਾ ਨਹੀਂ ਖ਼ਿਆਲ ਕੀਤਾ । ਵਾਰ ਵਾਰ ਉਸ ਤੇ ਵਾਰ ਕਰੇ ਤ੍ਰਿਸ਼ਨਾ, ਮਗਰ ਪੈ ਕੇ ਬੜਾ ਘਰਕਾਉਂਦੀ ਏ । ਇਓਂ ਉਹਦਿਆਂ ਮੋਹ ਦੇ ਬੰਧਨਾਂ ਨੂੰ, ਰਹਿੰਦੀ ਹੋਰ ਮਜ਼ਬੂਤ ਬਣਾਉਂਦੀ ਏ ।",
  "350": "ਭਲਾ ਆਦਮੀ ਹੋ ਸੁਚੇਤ ਜਿਹੜਾ, ਵਿਚੋਂ ਭਰਮ ਸੰਦੇਹ ਨੂੰ ਮਾਰਦਾ ਏ । ਮੁੱਖ ਭੋਗ ਵਿਲਾਸ ਤੋਂ ਮੋੜ ਲੈਂਦਾ, ਪੱਲਾ ਪਕੜ ਲੈਂਦਾ ਸਦਾਚਾਰ ਦਾ ਏ । ਉਹ ਤੋੜ ਕੇ ਮਾਇਆ ਦੇ ਸੰਗਲਾਂ ਨੂੰ, ਪੈਜ ਆਪਣੀ ਆਪ ਸਵਾਰਦਾ ਏ । ਤ੍ਰਿਸ਼ਨਾ ਕਾਮ ਨੂੰ ਜੜ੍ਹਾਂ ਤੋਂ ਪੁੱਟ ਛੱਡੇ, ਸਾਰੇ ਆਪਣੇ ਦੁੱਖ ਨਿਵਾਰਦਾ ਏ ।",
  "351": "ਪੂਰਨ ਜਿਸ ਨੇ ਮਰਾਤਬਾ ਪਾ ਲਿਆ ਏ, ਜਿਸ ਨੂੰ ਮੋਹ ਦਾ ਭੈ ਵਿਆਪਦਾ ਨਹੀਂ । ਜਿਸ ਨੇ ਤ੍ਰਿਸ਼ਨਾ ਨੂੰ ਜੜ੍ਹਾਂ ਤੋਂ ਪੁੱਟਿਆ ਹੈ, ਧੱਬਾ ਲੱਗਿਆ ਦਾਮਨ ਤੇ ਪਾਪ ਦਾ ਨਹੀਂ । ਓਸ ਪੁਰਖ ਨੇ ਏਸ ਸੰਸਾਰ ਅੰਦਰ, ਦੁੱਖ ਰੋਗ ਦੇ ਤੀਰਾਂ ਨੂੰ ਕੱਟਿਆ ਏ । ਬੰਧਨ ਓਸ ਦੇ ਸਭ ਖਲਾਸ ਹੋ ਗਏ, ਮਰਨਾ ਜੰਮਣਾ ਓਸ ਦਾ ਮੁੱਕਿਆ ਏ ।",
  "352": "ਜੀਹਨੇ ਤ੍ਰਿਸ਼ਨਾ ਤੋਂ ਗੈਲ ਛਡਾ ਲਈ ਏ, ਐਸ਼-ਸੰਪਤੀ ਨੂੰ ਜੱਫਾ ਮਾਰਦਾ ਨਹੀਂ । ਭਾਸ਼ਾ, ਕਾਵਿ ਦੇ ਵਿਚ ਨਿਪੁੰਨ ਜਿਹੜਾ, ਐਵੇਂ ਫੋਕੀਆਂ ਯੱਕੜਾਂ ਮਾਰਦਾ ਨਹੀਂ । ਬੁੱਧ-ਵਾਣੀ ਦਾ ਬੋਧ ਵੀ ਰੱਖਦਾ ਹੈ, ਅੱਖਰ ਜੋੜਨਾ ਤੋੜਨਾ ਜਾਣਦਾ ਏ । ਮਰਨਾ ਜੰਮਣਾ ਓਸ ਦਾ ਖਤਮ ਹੋਇਆ, ਗਿਆਨੀ ਪੁਰਖ ਉਹ ਤਾਰੂ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "353": "ਮੈਂ ਮੋਹ ਤੇ ਮਾਇਆ ਨੂੰ ਜਿੱਤਿਆ ਹੈ, ਮੈਂ ਸਭ ਹਕੀਕਤਾਂ ਜਾਣਦਾ ਹਾਂ । ਮੈਂ ਝਾੜਿਆ ਸਾਰਿਆਂ ਲੱਛਣਾਂ ਨੂੰ, ਪੂਰਨ ਤਿਆਗ ਅਵਸਥਾ ਨੂੰ ਮਾਣਦਾ ਹਾਂ । ਤ੍ਰਿਸ਼ਨਾ ਨਾਸ ਕਰਕੇ ਮੁਕਤ ਹੋ ਗਿਆ ਹਾਂ, ਕੋਈ ਖਿੱਚ ਨਾ ਪਾਉਂਦੀ ਚਾਹ ਮੈਨੂੰ । ਕਿਹੜੇ ਗੁਰੂ ਦੀ ਕਿਸੇ ਨੂੰ ਦੱਸ ਪਾਵਾਂ, ਮਿਲਿਆ ਆਪਣੇ ਆਪ ਹੈ ਰਾਹ ਮੈਨੂੰ ।",
  "354": "ਜੇ ਕਰ ਧਰਮ ਦਾ ਕੋਈ ਉਪਦੇਸ਼ ਕਰਦਾ, ਉਹ ਦਾਨ ਤਾਂ ਦਾਨਾ-ਸਿਰ-ਦਾਨ ਹੁੰਦਾ । ਕਰੇ ਧਰਮ ਦੇ ਰਸ ਦੀ ਰੀਸ ਜਿਹੜਾ, ਸਭਨਾਂ ਰਸਾਂ 'ਚੋਂ ਓਹ ਪ੍ਰਧਾਨ ਹੁੰਦਾ । ਜਿਹੜੇ ਲੋਕ ਨੇ ਧਰਮ ਦੇ ਨਾਲ ਰੱਤੇ, ਕਿਧਰੇ ਹੋਰ ਰੱਤੇ ਉਹਨਾਂ ਨਾਲ ਦੇ ਨਹੀਂ । ਤ੍ਰਿਸ਼ਨਾ ਪੁੱਟ ਕੇ ਜੜ੍ਹਾਂ ਤੋਂ ਨਾਸ ਕਰੀਏ, ਦੁੱਖ ਕਦੇ ਫਿਰ ਸਿਰ ਉਠਾਲਦੇ ਨਹੀਂ ।",
  "355": "ਪਰਲੇ ਪਾਰ ਨੂੰ ਜਾਣ ਦੀ ਸੋਚਦਾ ਨਹੀਂ, ਨਾ ਹੀ ਓਸ ਦੇ ਲਈ ਪਰਯਾਸ ਕਰਦਾ । ਮੰਦੀ ਮੱਤ ਵਾਲੇ ਐਸੇ ਆਦਮੀ ਦਾ, ਕਾਮ, ਭੋਗ, ਵਿਲਾਸ ਹੈ ਨਾਸ ਕਰਦਾ । ਤ੍ਰਿਸ਼ਨਾ ਭੋਗ ਦੇ ਵਿਚ ਗ਼ਲਤਾਨ ਹੋ ਕੇ, ਨਹੀਂ ਨੇਕੀ ਦੀ ਕਾਰ ਵਿਚਾਰਦਾ ਏ । ਖੈ ਆਪਣਾ ਕਰੇ ਦੁਰਬੁੱਧ ਏਦਾਂ, ਜਿਵੇਂ ਉਹ ਪਰਾਇਆਂ ਨੂੰ ਮਾਰਦਾ ਏ ।",
  "356": "ਜਿਵੇਂ ਖੇਤਾਂ ਵਿਚ ਘਾਹ ਬਘਾਟ ਹੋਵੇ, ਪਾਈਏ ਬੀਜ ਤਾਂ ਜ਼ਰਾ ਵੀ ਉੱਗਦਾ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਦਾ ਤਬਾਹ ਕਰਦਾ, ਮੋਹ ਕਦੇ ਮਨੁੱਖ ਨੂੰ ਪੁੱਗਦਾ ਨਹੀਂ । ਏਸੇ ਵਾਸਤੇ ਸੱਚ ਦੀ ਗੱਲ ਸਮਝੋ, ਮੋਹ ਮਾਇਆ ਨੂੰ ਤਜੇ ਇਨਸਾਨ ਜਿਹੜਾ । ਮਹਾਂਫਲ ਅਵੱਸ਼ ਹੀ ਮਿਲੇ ਉਸ ਤੋਂ, ਐਸੇ ਆਦਮੀ ਨੂੰ ਕਰੀਏ ਦਾਨ ਜਿਹੜਾ ।",
  "357": "ਜਿਵੇਂ ਖੇਤਾਂ ਵਿਚ ਘਾਹ ਬਘਾਟ ਹੋਵੇ, ਜਿਨਸ ਕੋਈ ਵੀ ਓਸ ਵਿਚ ਉੱਗਦੀ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਦਾ ਤਬਾਹ ਕਰਦੀ, ਨਫ਼ਰਤ ਕਦੇ ਮਨੁੱਖ ਨੂੰ ਪੁੱਗਦੀ ਨਹੀਂ । ਏਸੇ ਵਾਸਤੇ ਸੱਚ ਦੀ ਗੱਲ ਸਮਝੋ, ਦਿਲੋਂ ਈਰਖਾ ਤਜੇ ਇਨਸਾਨ ਜਿਹੜਾ । ਮਹਾਂਫਲ ਅਵੱਸ਼ ਹੀ ਮਿਲੇ ਉਸ ਤੋਂ, ਐਸੇ ਆਦਮੀ ਨੂੰ ਕਰੀਏ ਦਾਨ ਜਿਹੜਾ ।",
  "358": "ਜਿਵੇਂ ਖੇਤਾਂ ਵਿਚ ਘਾਹ ਬਘਾਟ ਹੋਵੇ, ਬੀਜ ਪਾਈਏ ਤਾਂ ਜ਼ਰਾ ਵੀ ਉੱਗਦਾ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਦਾ ਤਬਾਹ ਕਰਦਾ, ਭਰਮ ਕਦੇ ਮਨੁੱਖ ਨੂੰ ਪੁੱਗਦਾ ਨਹੀਂ । ਏਸੇ ਵਾਸਤੇ ਸੱਚ ਦੀ ਗੱਲ ਸਮਝੋ, ਦੇਵੇ ਭਰਮ ਨੂੰ ਤਜ ਇਨਸਾਨ ਜਿਹੜਾ । ਮਹਾਂਫਲ ਅਵੱਸ਼ ਹੀ ਮਿਲੇ ਉਸ ਤੋਂ, ਐਸੇ ਆਦਮੀ ਨੂੰ ਕਰੀਏ ਦਾਨ ਜਿਹੜਾ ।",
  "359": "ਜਿਵੇਂ ਖੇਤਾਂ ਵਿਚ ਘਾਹ ਬਘਾਟ ਹੋਵੇ, ਜਿਨਸ ਕੋਈ ਵੀ ਓਸ ਵਿਚ ਉੱਗਦੀ ਨਹੀਂ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਸਦਾ ਤਬਾਹ ਕਰਦੀ, ਤ੍ਰਿਸ਼ਨਾ ਕਦੇ ਮਨੁੱਖ ਨੂੰ ਪੁੱਗਦੀ ਨਹੀਂ । ਏਸੇ ਵਾਸਤੇ ਸੱਚ ਦੀ ਗੱਲ ਸਮਝੋ, ਤ੍ਰਿਸ਼ਨਾ ਚਾਹ ਨੂੰ ਤਜੇ ਇਨਸਾਨ ਜਿਹੜਾ । ਮਹਾਂਫਲ ਅਵੱਸ਼ ਹੀ ਮਿਲੇ ਉਸ ਤੋਂ, ਐਸੇ ਆਦਮੀ ਨੂੰ ਕਰੀਏ ਦਾਨ ਜਿਹੜਾ ।",
  "chap25": "ਭਿੱਖੂ",
  "360": "ਸੁੰਘਣ, ਸੁਨਣ ਦੇ ਵਿਚ ਜੋ ਕਰੇ ਸੰਜਮ, ਰਹੇ ਉਹ ਨਾ ਕਦੇ ਨੁਕਸਾਨ ਦੇ ਵਿਚ । ਸੰਜਮ ਠੀਕ ਹੁੰਦਾ ਕਰਨਾ ਅੱਖੀਆਂ ਦਾ, ਸੰਜਮ ਠੀਕ ਹੈ ਕਰਨ ਜ਼ਬਾਨ ਦੇ ਵਿਚ ।",
  "361": "ਮਨ, ਬਚਨ ਤੇ ਕਰਮ ਵਿਚ ਰੱਖ ਸੰਜਮ, ਸਭਨਾਂ ਇੰਦਰੀਆਂ ਨੂੰ ਵੱਸ ਕਰ ਜਾਏ । ਭਿਖਸ਼ੂ ਉਹ ਤਾਂ ਸਮਝੀਏ ਮੁਕਤ ਹੋਇਆ, ਸਾਗਰ ਦੁੱਖ ਕਲੇਸ਼ ਦਾ ਤਰ ਜਾਏ ।",
  "362": "ਕਰੇ ਹੱਥ ਦੀ ਕਾਰ ਦੇ ਵਿਚ ਸੰਜਮ, ਪੈਰ-ਚਾਲ ਵੀ ਸੰਜਮ ਦੇ ਨਾਲ ਚੱਲੇ । ਸੰਜਮ ਵਾਲਿਆਂ ਵਿਚ ਸਿਰ-ਕੱਢ ਹੋਵੇ, ਸੰਜਮ ਹੋਵੇ ਜ਼ਬਾਨ ਦਾ ਜਿਸ ਪੱਲੇ । ਜਿਸ ਦੀ ਸੋਚ ਅਧਿਆਤਮ ਤੇ ਟਿਕੀ ਰਹਿੰਦੀ, ਧਿਆਨ-ਮਗਨ ਸਮਾਧੀਆਂ ਲਾਉਂਦਾ ਏ । ਰੱਖ ਸਬਰ ਸੰਤੋਖ ਏਕਾਂਤ ਵਾਸੀ, ਭਿਖਸ਼ੂ ਜੱਗ ਵਿਚ ਓਹੀ ਕਹਾਉਂਦਾ ਏ ।",
  "363": "ਰਹਿੰਦਾ ਮੰਤਰਾਂ ਦਾ ਜਿਹੜਾ ਜਾਪ ਕਰਦਾ, ਸੰਜਮ ਜੋ ਜ਼ਬਾਨ ਦਾ ਰੱਖਦਾ ਏ । ਆਕੜ ਖਾਨ ਤੇ ਬੋਲ ਦਾ ਨਹੀਂ ਭੈੜਾ, ਭਿਖਸ਼ੂ ਓਸ ਨੂੰ ਮੰਨੀਏਂ ਲੱਖ ਦਾ ਏ । ਧਰਮ, ਅਰਥ, ਪਰਮਾਰਥ ਦੇ ਰਸਤਿਆਂ ਨੂੰ, ਐਸਾ ਭਿਖਸ਼ੂ ਹੀ ਸਦਾ ਰੁਸ਼ਨਾਉਂਦਾ ਏ । ਘੁਲੀਆਂ ਮਿਸਰੀਆਂ ਉਹਦੇ ਵਖਿਆਨਾਂ ਦੇ ਵਿਚ, ਮੰਦਾ ਬੋਲ ਨਾ ਜੀਭ ਤੇ ਆਉਂਦਾ ਏ ।",
  "364": "ਰਹੇ ਧਰਮ ਦੇ ਰਾਹ ਤੇ ਜੋ ਤੁਰਿਆ, ਨਿਸਚਾ ਧਰਮ ਦੇ ਰਾਹ ਵਿਚ ਜੋ ਰੱਖਦਾ ਏ । ਦਿਨੇ ਰਾਤ ਜੋ ਧਰਮ ਦਾ ਕਰੇ ਚਿੰਤਨ, ਜਿਹੜਾ ਧਰਮ ਉਪਦੇਸ਼ ਦੇ ਪੱਖ ਦਾ ਏ । ਐਸਾ ਭਿਖਸ਼ੂ ਧਰਮਾਤਮਾ ਜੋ ਹੋਵੇ, ਮਹਿਮਾ ਓਸ ਦੀ ਅਪਰ ਅਪਾਰ ਹੁੰਦੀ । ਦੁੱਖ, ਜ਼ਰਾ, ਨਾ ਓਸ ਨੂੰ ਮੌਤ ਆਏ, ਓਹਦੀ ਜ਼ਿੰਦਗੀ ਧਰਮ ਸਾਕਾਰ ਹੁੰਦੀ ।",
  "365": "ਝੋਲੀ ਆਪਣੀ ਵਿਚ ਜੋ ਲਾਭ ਆਏ, ਮੰਦਾ ਓਸ ਨੂੰ ਕਦੇ ਵੀ ਜਾਣੀਏ ਨਾ । ਲਾਭ ਪੁੱਜਦਾ ਵੇਖ ਕੇ ਹੋਰਨਾਂ ਨੂੰ, ਸੜੀਏ ਭੰਡੀਏ ਕਿਸੇ ਨੂੰ ਰਾਣੀਏ ਨਾ । ਭਿਖਸ਼ੂ ਜੋ ਵੀ ਈਰਖਾ ਲੱਬ ਕਾਰਣ, ਹੜੱਪਣ ਮਾਲ ਪਰਾਏ ਨੂੰ ਚਾਂਹਵਦਾ ਏ । ਉਹਦਾ ਚਿੱਤ ਇਕਾਗਰ ਨਹੀਂ ਹੋ ਸਕਦਾ, ਵਾਰ ਵਾਰ ਉਹ ਭਟਕਦਾ ਜਾਂਵਦਾ ਏ ।",
  "366": "ਭਾਵੇਂ ਰਤਾ ਮਾਸਾ ਹੋਏ ਲਾਭ ਪੁੱਜਾ, ਜਿਹੜਾ ਓਸ ਨੂੰ ਆਪਣਾ ਜਾਣਦਾ ਏ । ਨਫ਼ਰਤ ਨਾਲ ਨਾ ਓਸ ਨੂੰ ਕਹੇ ਮੰਦਾ, ਨਾ ਹੀ ਝੂਰਦਾ, ਭੰਡਦਾ, ਰਾਣਦਾ ਏ । ਐਸੇ ਭਿਖਸ਼ੂ ਦੀ ਦੇਵਤੇ ਕਰਨ ਉਪਮਾ, ਓਹਨੂੰ ਆਖਦੇ ਸ਼ੁੱਧ ਆਚਾਰ ਵਾਲਾ । ਸਦਾ ਆਲਸ ਹੈ ਨੱਸਦਾ ਦੂਰ ਉਸ ਤੋਂ, ਹੁੰਦਾ ਜੋ ਹੈ ਸੱਚੇ ਵਿਹਾਰ ਵਾਲਾ ।",
  "367": "ਜਿਸ ਨੂੰ ਜੱਗ ਦੇ ਨਾਲ ਨਾ ਮੋਹ ਮਮਤਾ, ਕਿਸੇ ਚੀਜ਼ ਦੀ ਨਹੀਂ ਪਰਵਾਹ ਕਰਦਾ । ਅਸਲ ਭਿਖਸ਼ੂ ਹੈ ਜੋ 'ਅਣ ਹੁੰਦਿਆਂ' ਤੇ, ਨਾਲ ਗ਼ਮ ਦੇ ਨਹੀਂ ਠੰਢੇ ਸਾਹ ਭਰਦਾ ।",
  "368": "ਭਿਖਸ਼ੂ ਬੁੱਧ-ਉਪਦੇਸ਼ ਨੂੰ ਮੰਨਦਾ ਜੋ, ਸੁੱਚਾ ਮਿੱਤਰਾਂ ਵਾਂਗ ਵਿਹਾਰ ਦਾ ਏ । ਓਹੋ ਸ਼ਾਂਤੀ ਮਹਾਂ ਆਨੰਦ ਮਾਣੇ, ਜੋ ਮਾੜੇ ਸੰਸਕਾਰਾਂ ਨੂੰ ਮਾਰਦਾ ਏ ।",
  "369": "ਭਿਖਸ਼ੂ ਪਿਆਰਿਆ ਬੇੜੀ ਨੂੰ ਕਰਾਂ ਖਾਲੀ, ਇਸ ਨੂੰ ਠੇਲ੍ਹਣਾ ਹੋਏ ਆਸਾਨ ਤੈਨੂੰ । ਮੋਹ, ਮਾਇਆ ਤੇ ਈਰਖਾ ਛੱਡ ਪਹਿਲਾਂ, ਫੇਰ ਮਿਲੇਗਾ ਪਦ ਨਿਰਵਾਣ ਤੈਨੂੰ । ਆਕੜ, ਰੂਪ, ਅਗਿਆਨ, ਅਭਿਮਾਨ ਤਾਈਂ, ਸਣੇ ਮੋਹ ਦੇ ਪੰਜਾਂ ਨੂੰ ਛੇਕੀਏ ਜੀ । ਤਮ੍ਹਾਂ, ਹਿਰਸ ਹਵਾ ਦੇ ਬੰਦਿਆਂ ਨੂੰ, ਸਦਾ ਦੂਰ ਤੋਂ ਹੀ ਮੱਥਾ ਟੇਕੀਏ ਜੀ ।",
  "370": "ਵਰਤ, ਨੇਮ ਤੇ ਭੋਗਾਂ ਦਾ ਮੋਹ ਜਿਹੜਾ, ਨੇੜੇ ਓਸ ਦੇ ਕਦੇ ਵੀ ਢੁੱਕੀਏ ਨਾ । ਦਈਏ ਤਜ ਸੰਦੇਹ ਤੇ ਭਰਮ ਤਾਈਂ, ਮਨ ਵਿਚ ਬਦਲੇ ਦੀ ਭਾਵਨਾ ਚੁੱਕੀਏ ਨਾ । ਸ਼ਰਧਾ, ਸ਼ਕਤੀ, ਧਿਆਨ, ਗਿਆਨ, ਸਿਮਰਨ, ਇਹਨਾਂ ਪੰਜਾਂ ਦੀ ਇੱਛਿਆ ਜੋ ਕਰਦਾ । ਪੰਜੇ ਮੋਹ ਜੋ ਕਰ ਲਏ ਵੱਸ ਭਿਖਸ਼ੂ, ਭਵ-ਸਾਗਰੀਂ ਲਹਿਰਾਂ ਨੂੰ ਓਹ ਤਰਦਾ ।",
  "371": "ਛੱਡ ਗ਼ਾਫ਼ਲੀ, ਧਿਆਨ ਲਗਾ ਭਿਖਸ਼ੂ, ਚਿੱਤ ਵਿਸ਼ੇ ਵਿਕਾਰਾਂ ਤੋਂ ਮੋੜਨਾ ਈਂ । ਵੱਸ ਭੋਗ ਵਿਲਾਸ ਦੇ ਨਹੀਂ ਪੈਣਾ, ਮਾਇਆ ਮੋਹ, ਜੰਜਾਲ ਨੂੰ ਤੋੜਨਾ ਈਂ । ਕਰਕੇ ਗ਼ਾਫ਼ਲੀ, ਲੋਹੇ ਦਾ ਗਰਮ ਗੋਲਾ, ਜੇਕਰ ਸੰਘ ਦੇ ਵਿਚ ਲੰਘਾਏਂਗਾ ਤੂੰ । 'ਹਾਏ ਦੁੱਖ ਹੋਇਆ, ਲੋਕੋ ਸੜ ਗਿਆ ਮੈਂ', ਹਾਲ ਪਾਹਰਿਆ ਤੇ ਬਹੁੜੀ ਪਾਏਂਗਾ ਤੂੰ ।",
  "372": "ਓਸ ਪੁਰਸ਼ ਨੇ ਧਿਆਨ ਲਗਾਉਣਾ ਕੀ, ਜਿਹੜਾ ਸੱਖਣਾ ਹੋਏ ਗਿਆਨ ਬਾਝੋਂ । ਕਦੇ ਗਿਆਨ ਨਾ ਕਿਸੇ ਦੇ ਪਏ ਪੱਲੇ, ਲਾਏ ਗਏ ਅਡੋਲ ਧਿਆਨ ਬਾਝੋਂ । ਜਿਹੜੇ ਆਦਮੀ ਏਸ ਜਹਾਨ ਅੰਦਰ, ਧਿਆਨ ਲਾ ਗਿਆਨ ਨੂੰ ਬੁੱਝਿਆ ਏ । ਏਸ ਗੱਲ ਵਿਚ ਸ਼ੱਕ ਨਾ ਰਾਈ ਮਾਤਰ, ਨੇੜੇ ਓਹ ਨਿਰਵਾਣ ਦੇ ਪੁੱਜਿਆ ਏ ।",
  "373": "ਸ਼ਾਂਤ ਚਿੱਤ ਵਾਲਾ ਕੋਈ ਜਦੋਂ ਭਿਖਸ਼ੂ, ਜਾਏ ਵਿਚ ਏਕਾਂਤ ਦੇ ਵਾਸ ਕਰਦਾ । ਸੱਚੇ ਧਰਮ ਦਾ ਓਸ ਨੂੰ ਹੋਏ ਦਰਸ਼ਨ, ਜਿਹੜਾ ਮਨ ਆਨੰਦ ਪ੍ਰਗਾਸ ਕਰਦਾ ।",
  "374": "ਜਿਹੜਾ ਪੰਜਾਂ ਸਕੰਧਾਂ ਦੀ ਉਤਪਤੀ ਨੂੰ, ਸਣੇ ਹੁੰਦੇ ਵਿਨਾਸ਼ ਵਿਚਾਰਦਾ ਏ । ਉਹ ਗਿਆਨੀਆਂ ਵਾਂਗ ਪਰਸੰਨ ਹੋ ਕੇ, ਅਮਿਓਂ ਓਸ ਨਾਲ ਕਾਲਜਾ ਠਾਰਦਾ ਏ ।",
  "375": "ਹੁੰਦਾ ਭਿਖਸ਼ੂ ਗਿਆਨੀ ਦਾ ਫ਼ਰਜ਼ ਪਹਿਲਾ, ਕਾਬੂ ਪਾਉਣਾ ਆਪਣੇ ਨਫ਼ਸ ਉੱਤੇ । ਸੁੱਚਾ ਆਪਣਾ ਚੱਜ ਆਚਾਰ ਕਰਨਾ, ਕੁੰਡਾ ਰੱਖਣਾ ਸਦਾ ਹੀ ਹਵਸ ਉੱਤੇ । ਕਰਕੇ ਸਬਰ ਸੰਤੋਖ ਅਟੰਕ ਰਹਿਣਾ, ਮੁਕਤੀ ਮਾਰਗੋਂ ਕਦੇ ਨਾ ਉੱਕਣਾ ਈਂ । ਨਹੀਂ ਆਲਸੀ, ਨੇਕ ਕਮਾਈ ਵਾਲੇ, ਐਸੇ ਮਿੱਤਰਾਂ ਦੇ ਨੇੜੇ ਢੁੱਕਣਾ ਈਂ ।",
  "376": "ਕਰੋ ਗੱਲ ਸਤਕਾਰ ਦੇ ਨਾਲ ਮਿੱਠੀ, ਸੁੱਚਾ ਆਪਣਾ ਸਦਾ ਆਚਾਰ ਕਰੀਏ । ਏਸੇ ਤਰ੍ਹਾਂ ਹੀ ਪਰਮ ਆਨੰਦ ਪਾਈਏ, ਸਾਗਰ ਦੁੱਖ ਤੇ ਰੋਗ ਦਾ ਪਾਰ ਕਰੀਏ ।",
  "377": "ਜਿਵੇਂ ਵੇਖੀਏ ਫੁੱਲਾਂ ਮੁਰਝਾਇਆਂ ਨੂੰ, ਝੱਟ ਵੇਲ ਚੰਬੇਲੀ ਦੀ ਝਾੜਦੀ ਏ । ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਭਿਖਸ਼ੂ ਦੀ ਸੋਚ ਸੁੱਚੀ, ਮੋਹ ਅਤੇ ਦਵੇਸ਼ ਨੂੰ ਸਾੜਦੀ ਏ ।",
  "378": "ਝਰੇ ਬੋਲਾਂ 'ਚੋਂ ਸ਼ਾਂਤ-ਫੁਹਾਰ ਜਿਸ ਦੇ, ਅਤੇ ਸਾਧਿਆ ਸ਼ਾਂਤ ਸਰੀਰ ਹੋਵੇ । ਖੱਲਲ ਨਹੀਂ ਵਿਚਾਰਾਂ ਵਿਚ ਪੈਣ ਦੇਵੇ, ਭਰਿਆ ਸ਼ਾਂਤੀ ਵਿਚ ਅਮੀਰ ਹੋਵੇ । ਬੰਧਨ ਜੋ ਸੰਸਾਰ ਦੇ ਤੋੜ ਜਾਏ, ਲੋਭ ਜਿਸ ਦਾ ਮਨ ਭਰਮਾਉਂਦਾ ਨਹੀਂ । ਪੂਰਨ ਸ਼ਾਂਤ-ਭਿਖਸ਼ੂ ਓਸੇ ਨੂੰ ਆਖਦੇ ਨੇ, ਉਹਦੀ ਪਦਵੀ ਨੂੰ ਪੁੱਜਿਆ ਜਾਉਂਦਾ ਨਹੀਂ ।",
  "379": "ਲਏ ਆਪੇ ਤੋਂ ਆਪ ਪਰੇਰਨਾ ਜੋ, ਆਪਣੇ ਆਪੇ ਵਿਚ ਝਾਤੀਆਂ ਮਾਰਦਾ ਏ । ਰਾਖਾ ਆਪਣਾ ਆਪ ਜੋ ਹੋਏ ਭਿਖਸ਼ੂ, ਓਹੀ ਖ਼ੁਸ਼ੀ ਵਿਚ ਸਮਾਂ ਗੁਜ਼ਾਰਦਾ ਏ ।",
  "380": "ਆਪ ਆਪਣੇ ਆਪ ਦਾ ਹੋਏ ਸਵਾਮੀ, ਆਪਾ ਆਪੇ ਨੂੰ ਆਪ ਹੀ ਜਾਣਦਾ ਏ । ਇਓਂ ਆਪੇ ਨੂੰ ਸੋਧੀਏ ਜਿਵੇਂ ਤਾਜਰ, ਸੁੰਦਰ ਘੋੜੇ ਦੀ ਰਗ ਪਛਾਣਦਾ ਏ ।",
  "381": "ਜਿਹੜਾ ਬੁੱਧ ਭਗਵਾਨ ਦੀ ਸਿੱਖਿਆ ਨੂੰ, ਹਿਰਦੇ ਖ਼ੁਸ਼ੀ ਦੇ ਨਾਲ ਸਮਾਉਂਦਾ ਏ । ਓਸ ਭਿਖਸ਼ੂ ਦੀ ਭਟਕਣਾ ਮੁੱਕ ਜਾਏ, ਉਹ ਸ਼ਾਂਤੀ ਦੀ ਪਦਵੀ ਪਾਉਂਦਾ ਏ ।",
  "382": "ਭਿਖਸ਼ੂ ਜੋ ਜਵਾਨੀ ਦੀ ਉਮਰ ਅੰਦਰ, ਹਿਰਦੇ ਬੁੱਧ-ਉਪਦੇਸ਼ ਨੂੰ ਧਾਰਦਾ ਏ । ਚੰਦ ਨਿਕਲ ਕੇ ਜਿਸ ਤਰ੍ਹਾਂ ਬੱਦਲਾਂ 'ਚੋਂ, ਚਾਨਣ ਧਰਤ ਦੇ ਉੱਤੇ ਖਿਲਾਰਦਾ ਏ ।",
  "chap26": "ਬ੍ਰਾਹਮਣ",
  "383": "ਤ੍ਰਿਸ਼ਨਾ ਰੂਪ ਸਰੋਤ ਨੂੰ ਲਾ ਮੁੰਦਾ, ਬ੍ਰਾਹਮਣ ! ਜਾਗਣਾ ਤੇ ਬਲ ਧਾਰਨਾ ਈਂ । ਮਨ ਭਾਉਂਦੀਆਂ ਜੋ ਵੀ ਕਾਮਨਾਵਾਂ, ਓਹਨਾਂ ਤਾਈਂ ਭਜਾਉਣਾ ਮਾਰਨਾ ਈਂ । ਮੰਦੀ ਭਾਵਨਾ ਦੇ ਸੰਸਕਾਰ ਜਿਹੜੇ, ਜੇਕਰ ਖੈ ਕਰਦਾ ਬ੍ਰਾਹਮਣ ! ਜਾਏਂਗਾ ਤੂੰ । ਇਹ ਗੱਲ ਹੈ ਪੱਥਰ ਤੇ ਲੀਕ ਵਰਗੀ, ਨਿਰਾਕਾਰ ਨਿਰਵਾਣ ਨੂੰ ਪਾਏਂਗਾ ਤੂੰ ।",
  "384": "ਤੁਰਦਾ ਧਰਮ ਦੇ ਮਾਰਗ ਤੇ ਜੋ ਪੰਡਤ, 'ਚਿੱਤ-ਭਾਵਨਾ' ਦਾ ਸੰਜਮ ਕਰੀ ਜਾਏ । ਲਹਿਰਾਂ ਮਾਰਦਾ ਸਾਗਰ ਨਾ ਰੋਕ ਸਕਦਾ, ਓਹ ਪਾਰਲੇ ਕੰਢੇ ਵਲ ਤਰੀ ਜਾਏ । ਜਿਸ ਪੰਡਤ ਪ੍ਰਾਕਰਮੀ ਨੇ ਇਸ ਤਰ੍ਹਾਂ ਦਾ, ਭੇਦ ਤੱਤ ਤੇ ਸੱਤ ਦਾ ਪਾ ਲਿਆ ਏ । ਸਾਰੇ ਬੰਧਨ ਹੀ ਓਸ ਦੇ ਦੂਰ ਹੋ ਗਏ, ਗਲੋਂ ਓਸ ਨੇ ਫਾਹੀ ਨੂੰ ਲਾਹ ਲਿਆ ਏ ।",
  "385": "ਅੱਖ, ਕੰਨ ਤੇ ਨੱਕ ਨਾ ਜੀਭ ਜਿਸ ਦੀ, ਕਾਇਆ ਮਨ ਆਈ ਨਹੀਂ ਪਾਰ ਜਿਸ ਦਾ । ਰੂਪ, ਸ਼ਬਦ, ਸਪਰਸ਼ ਨਾ ਧਰਮ ਜੀਹਦੇ, ਰਸ ਗੰਧ ਨੇ ਨਹੀਂ ਅਪਾਰ ਜਿਸ ਦਾ । ਮੈਂ, ਮੇਰੀ ਨੂੰ ਮਾਰਿਆ ਜਿਸ ਹੋਵੇ, ਕਾਬੂ ਆਪਣੇ ਆਪ ਤੇ ਪਾਏਗਾ ਜੋ । ਉਹਨੂੰ ਬ੍ਰਾਹਮਣ ਕਹਾਉਣ ਦਾ ਹੱਕ ਪੂਰਾ, ਜਗਤ ਜਾਲ ਤੋਂ ਮੁਕਤ ਹੋ ਜਾਏਗਾ ਜੋ ।",
  "386": "ਜੀਹਦਾ ਪਾਕ ਗੁਨਾਹ ਤੋਂ ਹੋਏ ਦਾਮਨ, ਸੋਹਣਾ ਆਪਣਾ ਫ਼ਰਜ਼ ਨਿਭਾਉਂਦਾ ਏ । ਮਨ ਕੁੰਗੂ ਦੇ ਵਾਂਗਰਾਂ ਸਾਫ਼ ਰੱਖੇ, ਸਦਾ ਜੋ ਧਿਆਨ ਲਗਾਉਂਦਾ ਏ । ਜੀਹਦੀ ਵਾਸਨਾ ਭੜਕਣਾ ਮੁੱਕ ਗਈ, ਇਕ ਥਾਂ ਜਿਨ ਚਿੱਤ ਟਿਕਾ ਲਿਆ ਏ । ਉਸੇ ਆਦਮੀ ਨੂੰ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਓਹਨੇ ਪਦ ਨਿਰਵਾਣ ਨੂੰ ਪਾ ਲਿਆ ਏ ।",
  "387": "ਤੇਜ ਸੂਰਜ ਦਾ ਲਿਸ਼ਕਦਾ ਦਿਨ ਵੇਲੇ, ਰਾਤੀਂ ਚੰਦ ਪ੍ਰਕਾਸ਼ ਖਿਲਾਰਦਾ ਏ । ਚਮਕ ਸਸ਼ਤਰਾਂ ਨਾਲ ਹੈ ਸੂਰਮੇ ਦੀ, ਬ੍ਰਾਹਮਣ ਧਿਆਨ ਅੰਦਰ ਡਲ੍ਹਕਾਂ ਮਾਰਦਾ ਏ । ਆਲਸ ਦੂਰ ਕਰਕੇ ਬੁੱਧ ਜਾਗਿਆ ਜੋ, ਤੇਜ ਓਸ ਦਾ ਹੋਰ ਪਰਕਾਰ ਦਾ ਏ । ਉਹ ਤਾਂ ਨੂਰ ਦਾ ਹੋਏ ਅਖੁੱਟ ਸੋਮਾਂ, ਦਿਨੇ ਰਾਤ ਹੀ ਪਿਆ ਲਿਸ਼ਕਾਰਦਾ ਏ ।",
  "388": "ਬ੍ਰਾਹਮਣ ਆਖਦੇ ਨੇ ਓਸ ਆਦਮੀ ਨੂੰ, ਸਗਲੀ ਪਾਪਾਂ ਦੀ ਮੈਲ ਨੂੰ ਧੋ ਲਿਆ ਜਿਸ । ਹੋਇਆ ਅਸਲ ਸੰਨਿਆਸ ਦਾ ਧਾਰਨੀ ਓਹ, ਮਨ 'ਸੰਘ' ਦੇ ਵਿਚ ਪਰੋ ਲਿਆ ਜਿਸ । ਜਿਸ ਨੇ ਆਪਣੇ ਚਿੱਤ ਨੂੰ ਸਾਫ਼ ਕੀਤਾ, ਵਿਚੋਂ ਮਾਰ ਬੁਰਿਆਈਆਂ ਨੂੰ ਕੱਢਿਆ ਏ । ਓਹਨੂੰ ਏਸ ਕਾਰਨ ਭਿਖਸ਼ੂ ਆਖਦੇ ਨੇ, ਜੀਹਨੇ ਮੋਹ ਸੰਸਾਰ ਦਾ ਛੱਡਿਆ ਏ ।",
  "389": "ਮੰਦਾ ਬ੍ਰਾਹਮਣ ਦਾ ਅੱਗਿਓਂ ਕੋਪ ਕਰਨਾ, ਮਾੜੀ ਗੱਲ ਬ੍ਰਾਹਮਣ ਤੇ ਵਾਰ ਹੋਵੇ । ਕਰੇ ਬ੍ਰਾਹਮਣ ਤੇ ਵਾਰ ਧ੍ਰਿਗ ਓਹਨੂੰ, ਕੋਪੇ ਬ੍ਰਾਹਮਣ ਤਾਂ ਲੱਖ ਧਿੱਕਾਰ ਹੋਵੇ ।",
  "390": "ਇਹ ਬ੍ਰਾਹਮਣ ਦੀ ਥੋੜ੍ਹੀ ਪਰਾਪਤੀ ਨਹੀਂ, ਜਿਹੜਾ ਮੋਹ ਤੇ ਮਾਇਆ ਨੂੰ ਮਾਰ ਲੈਂਦਾ । ਹੋੜ, ਮੋੜ ਕੇ ਹਿੰਸਾ ਤੋਂ ਹੱਥ ਆਪਣਾ, ਭੁੱਖ ਮੇਟ ਲੈਂਦਾ ਹਿਰਦਾ ਠਾਰ ਲੈਂਦਾ ।",
  "391": "ਮਨ, ਬਚਨ ਤੇ ਆਪਣੇ ਕਰਮ ਰਾਹੀਂ, ਕਦੇ ਜੋ ਨਾਹੀਂ ਕੋਈ ਪਾਪ ਕਰਦਾ । ਓਸੇ ਤਾਈਂ ਬ੍ਰਾਹਮਣ ਮੈਂ ਮੰਨਦਾ ਹਾਂ, ਇਹਨਾਂ ਤਿੰਨਾਂ ਨੂੰ ਵੱਸ ਜੋ ਆਪ ਕਰਦਾ ।",
  "392": "ਜਿਸ ਕੋਲੋਂ ਵੀ ਬੁੱਧ-ਉਪਦੇਸ਼ ਲੈ ਕੇ, ਕੋਈ ਆਪਣਾ ਆਪ ਸੰਵਾਰਦਾ ਏ । ਉਹੂੰ ਚਾਹੀਦਾ ਉਹਦਾ ਸਨਮਾਨ ਕਰਨਾ, ਬ੍ਰਾਹਮਣ 'ਅਗਨੀ' ਨੂੰ ਜਿਵੇਂ ਸਤਕਾਰਦਾ ਏ ।",
  "393": "ਜਟਾ, ਜਨਮ ਤੇ ਗੋਤ ਦੇ ਨਾਲ ਸਮਝੋ, ਕੋਈ ਆਦਮੀ ਬ੍ਰਾਹਮਣ ਨਾ ਹੋ ਜਾਏ । ਬ੍ਰਾਹਮਣ ਉਹ ਹੈ ਸੱਚ ਦਾ ਧਾਰਨੀ ਹੋ, ਪਹਿਰੇ ਧਰਮ ਦੇ ਜਿਹੜਾ ਖਲੋ ਜਾਏ ।",
  "394": "ਓਏ ਮੂਰਖਾ ! ਜਟਾਂ ਵਿਚ ਕੀ ਧਰਿਆ ? ਮ੍ਰਿਗ-ਛਾਲਾ ਨੂੰ ਦੱਸ ਹੰਢਾਵਣਾ ਕੀ ? ਤੇਰੇ ਅੰਦਰ ਤਾਂ ਗੁੱਦੜ ਦਾ ਵਾਸ ਹੋਇਆ, ਕੁਲਾ, ਰੇਸ਼ਮੀ ਬਾਹਰ ਦਿਖਾਵਣਾ ਕੀ ?",
  "395": "ਸੁੱਕਾ ਪਿੰਜਰ ਤੇ ਨਾੜੀਆਂ ਦਿਸਦੀਆਂ ਨੇ, ਰੱਖੇ ਚੀਥੜੇ ਵੀ ਜੇ ਗਲ ਪਾਈ । ਬ੍ਰਾਹਮਣ ਆਖੀਏ ਓਸ 'ਨਵੇਕਲੇ' ਨੂੰ, ਬੈਠਾ ਜੰਗਲਾਂ ਵਿਚ ਜੋ ਧਿਆਨ ਲਾਈ ।",
  "396": "ਜਿਹੜਾ ਮਾਂ ਦੀ ਕੁੱਖ ਦਾ ਹੋਏ ਜਾਇਆ, ਬੜਾ ਉਹ ਧਨਵਾਨ ਮਗਰੂਰ ਹੋਵੇ । ਮੈਂ ਤਾਂ ਬ੍ਰਾਹਮਣ ਪਰ ਓਸ ਨੂੰ ਮੰਨਦਾ ਹਾਂ, ਜਿਹੜਾ ਤਿਆਗੀ ਤੇ ਮੋਹ ਤੋਂ ਦੂਰ ਹੋਵੇ ।",
  "397": "ਜਿਸ ਨੇ ਕੱਟਿਆ ਸਾਰੀਆਂ ਬੇੜੀਆਂ ਨੂੰ, ਜਿਸ ਨੂੰ ਤ੍ਰਿਸ਼ਨਾ ਦਾ ਡਰ ਡਰਾਉਂਦਾ ਨਹੀਂ । ਓਸ ਸੰਜਮੀ ਨੂੰ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਜਿਹੜਾ ਮੋਹ ਵਿਚ ਚਿੱਤ ਫਸਾਉਂਦਾ ਨਹੀਂ ।",
  "398": "ਭੰਨ ਤੋੜਿਆ ਕ੍ਰੋਧ ਦੇ ਸੰਗਲਾਂ ਨੂੰ, ਝੱਬੂ ਵਾਸਨਾ ਦਾ ਹੋਵੇ ਲਾਹਿਆ ਜਿਸ । ਓਸ ਬੁੱਧ ਤਾਈਂ ਬ੍ਰਾਹਮਣ ਮੰਨਦਾ ਹਾਂ, ਜੂਲਾ ਗਲੋਂ ਅਗਿਆਨ ਦਾ ਲਾਹਿਆ ਜਿਸ ।",
  "399": "ਜਿਹੜਾ ਆਦਮੀ ਚਿੱਤ ਨਾ ਕਰੇ ਮੈਲਾ, ਕੈਦ, ਗਾਲੀਆਂ, ਫਾਂਸੀਆਂ ਸਹੀ ਜਾਏ । ਖਿਮਾ-ਬਲ ਉਹਦਾ ਤਕੜੀ ਫੌਜ ਜੇਡਾ, ਮੇਰਾ ਮਨ ਉਸ ਨੂੰ ਬ੍ਰਾਹਮਣ ਕਹੀ ਜਾਏ ।",
  "400": "ਸੀਲ ਸੰਜਮੀ ਹੋਏ ਤੇ ਨਿੱਤ-ਨੇਮੀ, ਸੁਣੇ ਬੁੱਧ-ਵਾਣੀ ਕਰੋਧ ਨਹੀਂ ਕਰਦਾ । ਓਸ ਆਦਮੀ ਨੂੰ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਅੰਤਮ-ਦੇਹ ਧਾਰੀ ਜਿਹੜਾ ਨਹੀਂ ਮਰਦਾ ।",
  "401": "ਦਾਣਾ ਸਰ੍ਹੋਂ ਦਾ ਸੂਈ ਦੀ ਨੋਕ ਉਤੇ, ਜਿਵੇਂ ਧਰਦਿਆਂ ਸਾਰ ਹੀ ਢਹਿ ਜਾਏ । ਕਤਰਾ ਪਾਣੀ ਦਾ ਕੰਵਲ ਦੇ ਪੱਤਿਆਂ ਤੇ, ਝੱਟ ਤਿਲਕ ਜਾਏ, ਥੱਲੇ ਵਹਿ ਜਾਏ ।",
  "402": "ਓਸੇ ਤਰ੍ਹਾਂ ਹੀ ਕਾਮ ਦੇ ਭੋਗ ਕੋਲੋਂ, ਰਹਿ ਕੇ ਦੂਰ ਜੋ ਬੋਝ ਉਤਾਰ ਲੈਂਦਾ । ਐਸੇ ਸੰਜਮੀ ਨੂੰ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਪਾ ਜਿਹੜਾ ਹੈ ਦੁੱਖ ਦੀ ਸਾਰ ਲੈਂਦਾ ।",
  "403": "ਐਸਾ ਆਦਮੀ ਗੂੜ੍ਹ ਗਿਆਨ ਵਾਲਾ, ਜਿਹੜਾ ਰਾਹ-ਕੁਰਾਹ ਨੂੰ ਜਾਣਦਾ ਏ । ਮੈਂ ਤਾਂ ਉਸੇ ਨੂੰ ਹੀ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਪਾਇਆ ਮਰਤਬਾ ਜਿਸ ਨਿਰਵਾਣ ਦਾ ਏ ।",
  "404": "ਜਿਹੜਾ ਵਿਚ ਸੰਸਾਰ ਦੇ ਨਹੀਂ ਫਾਥਾ, ਖੱਚਤ ਹੋ ਰਿਹਾ ਵਿਚ ਸੰਨਿਆਸ ਨਾਹੀਂ । ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਓਸ ਨਿਥਾਵੇਂ ਨੂੰ ਮੈਂ, ਜਿਸ ਨੂੰ ਇੱਛਿਆ, ਵਾਸਨਾ, ਆਸ ਨਾਹੀਂ ।",
  "405": "ਜਿਸ ਨੇ ਲਾਠੀ ਨੂੰ ਰੱਖ ਕੇ ਇਕ ਪਾਸੇ, ਮੁੱਖ ਆਪਣਾ ਹਿੰਸਾ ਤੋਂ ਫੇਰਿਆ ਏ । ਨਾ ਹੀ ਮਾਰਿਆ ਕਿਸੇ ਨੂੰ ਆਪ ਓਹਨੇ, ਨਾ ਹੀ ਮਾਰਨ ਦੇ ਲਈ ਪਰੇਰਿਆ ਏ ।",
  "406": "ਜਿਹੜਾ ਨਹੀਂ ਵਿਰੋਧੀ ਵਿਰੋਧੀਆਂ ਦਾ, ਅੱਗੇ ਲਾਠੀਆਂ, ਹੱਥ ਜੋ ਚੁੱਕਦਾ ਨਹੀਂ । ਮੈਂ ਤਾਂ ਬ੍ਰਾਹਮਣ ਹੀ ਓਸ ਨੂੰ ਆਖਦਾ ਹਾਂ, ਪਾਉਂਦਾ ਮੰਗਤੇ ਨੂੰ ਵਾਸਤਾ ਟੁੱਕ ਦਾ ਨਹੀਂ ।",
  "407": "ਦਾਣਾ ਸਰ੍ਹੋਂ ਦਾ ਸੂਈ ਦੀ ਨੋਕ ਉਤੇ, ਜਿਵੇਂ ਧਰਦਿਆਂ ਸਾਰ ਹੀ ਗਿਰ ਜਾਏ । ਬ੍ਰਾਹਮਣ ਓਹ ਹੈ ਜਿਸ ਦੇ ਚਿੱਤ ਵਿਚੋਂ, ਮੋਹ, ਵੈਰ, ਪਾਖੰਡ ਸਭ ਕਿਰ ਜਾਏ ।",
  "408": "ਓਹ ਵੀ ਬ੍ਰਾਹਮਣ ਅਖਵਾਉਣ ਦਾ ਹੱਕ ਰੱਖੇ, ਜਿਹੜਾ ਸੱਚ ਦੇ ਸੁਖਨ ਅਲਾਉਂਦਾ ਏ । ਸਦਾ ਸਾਰਥ ਤੇ ਕੰਮ ਦੀ ਗੱਲ ਕਰਦਾ, ਫਿੱਕਾ ਬੋਲ ਨਾ ਦਿਲ ਦੁਖਾਉਂਦਾ ਏ ।",
  "409": "ਛੋਟੀ ਲੰਮੀ ਜਾਂ ਸ਼ੁਭ ਅਸ਼ੁਭ ਹੋਵੇ, ਭਾਵੇਂ ਹੋਏ ਹੌਲੀ ਭਾਵੇਂ ਹੋਏ ਭਾਰੀ । ਬਿਨਾ ਦਿੱਤਿਆਂ ਚੀਜ਼ ਜੋ ਨਹੀਂ ਲੈਂਦਾ, ਓਹੀ ਬ੍ਰਾਹਮਣ ਕਹਾਉਣ ਦਾ ਅਧਿਕਾਰੀ ।",
  "410": "ਨਹੀਂ ਲੋਕ-ਪਰਲੋਕ ਦੀ ਚਾਹ ਜਿਸ ਨੂੰ, ਜਿਹੜਾ ਕਿਸੇ ਦਾ ਆਸਰਾ ਤੱਕਦਾ ਨਹੀਂ । ਐਸੇ ਸੰਜਮੀ ਪੁਰਸ਼ ਨੂੰ ਸੱਚ ਜਾਣੋਂ, ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਕਦੇ ਮੈਂ ਥੱਕਦਾ ਨਹੀਂ ।",
  "411": "ਮੁਕਤ ਹੋਇਆ ਜੋ ਤ੍ਰਿਸ਼ਨਾ ਤੇ ਇੱਛਿਆ ਤੋਂ, ਸੰਸੇ ਵਿਚ ਨਾ ਚਿੱਤ ਫਸਾਉਂਦਾ ਏ । ਐਸੇ ਮੈਂ ਗਿਆਨੀ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਡੀਕ ਅੰਮ੍ਰਿਤ-ਨਿਰਵਾਣ ਦੀ ਲਾਉਂਦਾ ਏ ।",
  "412": "ਪੁੰਨ-ਪਾਪ ਦੀ ਫਾਹੀ ਤੋਂ ਪਾਰ ਹੋਇਆ, ਬਿਨਾਂ ਮੈਲ ਤੇ ਪਾਪ ਸੰਤਾਪ ਜਿਹੜਾ । ਓਸ ਪੁਰਸ਼ ਤਾਈਂ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਹੋਏ ਪਾਕ-ਪਵਿੱਤ ਨਿਸ਼ਪਾਪ ਜਿਹੜਾ ।",
  "413": "ਐਸੇ ਆਦਮੀ ਨੂੰ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਜਨਮ ਜਨਮ ਦੀ ਜੋ ਤ੍ਰਿਸ਼ਨਾ ਮਾਰਦਾ ਏ । ਨਿਰਮਲ, ਸਾਫ਼, ਸਵੱਛ ਜੋ ਚੰਦ ਵਾਂਗੂੰ, ਬਿਨਾਂ ਦਾਗ਼ ਜੋ ਚਾਨਣ ਖਿਲਾਰਦਾ ਏ ।",
  "414": "ਧਿਆਨ ਮਗਨ ਸੰਤੋਖੀ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਪਰਲੇ ਪਾਰ ਜੋ ਸ਼ਾਂਤ ਹੋ ਤਰ ਗਿਆ ਏ । ਜੰਮਣ ਮਰਨ ਦੇ ਗੇੜ ਵਿਚ ਪਾਉਣ ਵਾਲੇ, ਸੰਸੇ, ਮੋਹ ਤਾਈਂ ਸਰ ਕਰ ਗਿਆ ਏ ।",
  "415": "ਬ੍ਰਾਹਮਣ ਮੈਂ ਤਾਂ ਓਸ ਨੂੰ ਆਖਦਾ ਹਾਂ, ਜੀਹਨੇ ਤ੍ਰਿਸ਼ਨਾ ਦੇ ਸੋਮੇ ਦਾ ਨਾਸ ਕੀਤਾ । ਸਾਰੇ ਭੋਗ ਵਿਲਾਸ ਤਿਆਗ ਦਿੱਤੇ, ਧਾਰਨ ਖ਼ੁਸ਼ੀ ਦੇ ਨਾਲ ਸੰਨਿਆਸ ਕੀਤਾ ।",
  "416": "ਬ੍ਰਾਹਮਣ ਓਸੇ ਹੀ ਪੁਰਸ਼ ਨੂੰ ਆਖਦਾ ਹਾਂ, ਤ੍ਰਿਸ਼ਨਾ ਜਿਸ ਦੀ ਦਾ ਸੋਮਾ ਸੁੱਕਿਆ ਏ । ਘਰ ਛੱਡ ਜੋ ਜੰਗਲਾਂ ਵਿਚ ਭਉਂਦਾ, ਲੇਖਾ ਜਨਮ ਤੇ ਮਰਨ ਦਾ ਮੁੱਕਿਆ ਏ ।",
  "417": "ਮਾਨਸ ਜਨਮ ਜੰਜਾਲ ਨੂੰ ਕੱਟ ਜਿਹੜਾ, ਦੈਵੀ ਬੰਧਨਾਂ ਨੂੰ ਪਿੱਛੇ ਛੋੜ ਜਾਏ । ਓਸ ਆਦਮੀ ਨੂੰ ਮੈਂ ਤਾਂ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਸਗਲੇ ਜਾਲ ਜੰਜਾਲ ਜੋ ਤੋੜ ਜਾਏ ।",
  "418": "ਤਜ 'ਮੋਹ-ਨਿਰਮੋਹ' ਨੂੰ ਸ਼ਾਂਤ ਹੋਵੇ, ਸਰਬ ਲੋਕ ਵਿਜੱਈ ਬਲਵਾਨ ਜਿਹੜਾ । ਬਿਲਾ ਸ਼ੱਕ ਮੈਂ ਓਸ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਹੋਵੇ ਬਿਨਾਂ-ਕਲੇਸ਼ ਇਨਸਾਨ ਜਿਹੜਾ ।",
  "419": "ਜੰਮਣ-ਮਰਨ ਜੋ ਜਾਣਦਾ ਪਰਾਣੀਆਂ ਦਾ, ਸੁੰਦਰ-ਗਤੀ ਨੂੰ ਜਿਸ ਨੇ ਪਾ ਲਿਆ ਏ । ਜੀਹਨੇ ਮੋਹ ਨੂੰ ਇਸ ਤਰ੍ਹਾਂ ਕੋਹ ਲਿਆ, ਓਸ ਬੁੱਧ ਨੇ ਬ੍ਰਾਹਮਣ ਅਖਵਾ ਲਿਆ ਏ ।",
  "420": "ਮਾਣਸ, ਦੇਵ, ਗੰਧਰਬ ਨਾ ਜਾਣ ਸਕਦੇ, ਗਤੀ ਓਸ ਦੀ ਅਪਰ-ਅਪਾਰ ਹੋਵੇ । ਓਸ ਨਿਹ-ਕਲੰਕ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਜਿਸ ਦਾ ਸਦਾ ਹੀ ਮਾਣ ਸਤਕਾਰ ਹੋਵੇ ।",
  "421": "ਨਹੀਂ ਭੂਤ, ਭਵਿੱਖ ਦਾ ਫ਼ਿਕਰ ਕਰਦਾ, ਹਰ ਹਾਲ ਅੰਦਰ ਖਿੜੇ ਰੰਗ ਜਿਹੜਾ । ਮੈਂ ਤਾਂ ਓਸ ਨੂੰ ਹੀ ਬ੍ਰਾਹਮਣ ਆਖਦਾ ਹਾਂ, ਦਾਨ ਲਏ ਨਾ ਨੰਗ ਮਲੰਗ ਜਿਹੜਾ ।",
  "422": "ਮਹਾਂਰਿਸ਼ੀ ਤੇ ਸੂਰਮਾ, ਸਰਬ-ਜੇਤੂ, ਹੋਵੇ ਬੁੱਧ, ਅਡੋਲ, ਬਲਵਾਨ ਜਿਹੜਾ, ਬਿਲਾ ਸ਼ੱਕ ਮੈਂ ਓਸ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਗੁਣਵੰਤ, ਵਿਦਵਾਨ ਇਨਸਾਨ ਜਿਹੜਾ ।",
  "423": "ਪਿਛਲਾ ਜਨਮ ਜੋ ਆਪਣਾ ਜਾਣਦਾ ਏ, ਨਰਕ-ਸੁਰਗ ਤੇ ਝਾਤੀਆਂ ਮਾਰ ਆਇਆ । ਪੁਨਰ-ਜਨਮ ਜੰਜਾਲ ਜਿਸ ਕੱਟਿਆ ਏ, ਜੋ ਵੀ ਤੱਤ ਦੀ ਸਮਝਕੇ ਸਾਰ ਆਇਆ । ਜੋ ਸਦਾ ਸੁਚੇਤ ਤੇ ਜਾਗਦਾ ਹੈ, ਕਾਰਜ ਕਰ ਚੁੱਕਿਆ ਜੋ ਵੀ ਕਰਨ ਵਾਲਾ । ਐਸੇ ਗਹਿਰ ਗੰਭੀਰ ਨੂੰ ਕਹਾਂ ਬ੍ਰਾਹਮਣ, ਸਾਗਰ ਜੋ ਨਿਰਵਾਣ ਦਾ ਤਰਨ ਵਾਲਾ ।"
};
